// tools database: name, url, icon, cat, tags, desc

const toolsDB = [
  { name:'Sherlock', url:'https://github.com/sherlock-project/sherlock', icon:'🔎', cat:'social', tags:['username','accounts'],
    desc:'Sherlock — один из самых известных OSINT-инструментов для поиска аккаунтов по никнейму. Он одновременно проверяет более 400 социальных платформ — от крупных (Twitter, Instagram, GitHub, Reddit, TikTok) до нишевых форумов и региональных сетей. Написан на Python, работает из командной строки. Результаты выводятся в виде списка найденных URL с указанием статуса каждой проверки. Поддерживает вывод в CSV и JSON. Активно поддерживается сообществом, база платформ регулярно обновляется. Незаменим на первом этапе разведки по человеку когда известен только его ник.', descEn:'Sherlock is one of the most well-known OSINT tools for finding accounts by username. It simultaneously checks 400+ social platforms — from major ones (Twitter, Instagram, GitHub, Reddit, TikTok) to niche forums and regional networks. Written in Python, runs from command line. Results list found URLs with status. Supports CSV and JSON output. Actively maintained by the community. Essential at the first stage of person-level reconnaissance when only a nickname is known.' },

  { name:'Maigret', url:'https://github.com/soxoj/maigret', icon:'🕵️', cat:'social', tags:['username','profiling'],
    desc:'Maigret — эволюция идеи Sherlock с акцентом на глубокое профилирование. Помимо поиска аккаунтов на 3000+ платформах, он автоматически собирает открытые данные с найденных профилей: имена, биографии, аватары, ссылки на другие сети. Строит граф связей между аккаунтами. Умеет рекурсивно искать новые никнеймы найденные на профилях. Поддерживает вывод в HTML-отчёт с визуализацией. Особенно эффективен для установления связи между несколькими аккаунтами одного человека на разных платформах.', descEn:'Maigret is an evolution of Sherlock\'s idea with a focus on deep profiling. Beyond account search on 3000+ platforms, it automatically collects open data from found profiles: names, bios, avatars, links to other networks. Builds a relationship graph between accounts. Can recursively search for new usernames found on profiles. Supports HTML report output with visualization. Especially effective for linking multiple accounts of one person across different platforms.' },

  { name:'Holehe', url:'https://github.com/megadose/holehe', icon:'🦉', cat:'email', tags:['email','accounts'],
    desc:'Holehe специализируется на проверке email-адреса на сервисах через функцию восстановления пароля. В отличие от прямого поиска, он не создаёт аккаунты — он использует форму "Забыл пароль" которая раскрывает зарегистрирован ли адрес без уведомления пользователя. Поддерживает 120+ сервисов включая Amazon, Twitter, Instagram, Spotify, Adobe и многие другие. Это позволяет по одному email узнать какими сервисами пользуется человек, что даёт зацепки для дальнейшей разведки.', descEn:'Holehe specializes in checking whether an email address is registered on services via the password-recovery function. Unlike direct search, it doesn\'t create accounts — it uses the \'Forgot password\' form which reveals whether an address is registered without notifying the user. Supports 120+ services including Amazon, Twitter, Instagram, Spotify, Adobe and more. This lets you determine which services a person uses from a single email, providing leads for further investigation.' },

  { name:'theHarvester', url:'https://github.com/laramies/theHarvester', icon:'🌾', cat:'email', tags:['email','dns','recon'],
    desc:'theHarvester — классический инструмент для сбора информации о домене из открытых источников. Собирает email-адреса, имена сотрудников, поддомены, IP-адреса и URL через поисковики Google, Bing, Yahoo, DuckDuckGo, а также специализированные источники: Shodan, Censys, Hunter.io, SecurityTrails. Один из первых инструментов которые запускают при аудите внешнего периметра организации. Входит в состав Kali Linux. Поддерживает экспорт в XML и HTML.', descEn:'theHarvester is a classic tool for gathering domain information from open sources. Collects email addresses, employee names, subdomains, IPs and URLs via search engines Google, Bing, Yahoo, DuckDuckGo, plus specialized sources: Shodan, Censys, Hunter.io, SecurityTrails. One of the first tools launched during an organization\'s external perimeter audit. Included in Kali Linux. Supports XML and HTML export.' },

  { name:'SpiderFoot', url:'https://github.com/smicallef/spiderfoot', icon:'🕷️', cat:'network', tags:['automation','recon','framework'],
    desc:'SpiderFoot — мощный автоматизированный OSINT-фреймворк с веб-интерфейсом и CLI. Содержит более 200 модулей для сбора данных из разных источников: WHOIS, DNS, Shodan, VirusTotal, HaveIBeenPwned, социальные сети, даркнет и многое другое. Принимает на вход IP, домен, email, имя или другой идентификатор и строит карту всех связанных объектов. Результаты визуализируются в виде интерактивного графа. Поддерживает параллельный запуск модулей и сохранение результатов в SQLite.', descEn:'SpiderFoot is a powerful automated OSINT framework with a web interface and CLI. Contains 200+ modules for collecting data from various sources: WHOIS, DNS, Shodan, VirusTotal, HaveIBeenPwned, social networks, darknet and more. Accepts IP, domain, email, name or other identifier as input and builds a map of all related objects. Results visualized as an interactive graph. Supports parallel module execution and SQLite result storage.' },

  { name:'Recon-ng', url:'https://github.com/lanmaster53/recon-ng', icon:'🛰️', cat:'network', tags:['framework','modules','recon'],
    desc:'Recon-ng — модульный фреймворк для веб-разведки, построенный по образцу Metasploit. Имеет интерактивную командную строку с автодополнением, маркетплейс модулей (70+ штук), встроенную базу данных SQLite для хранения результатов. Модули охватывают: поиск по WHOIS, DNS-разведку, поиск в социальных сетях, сбор email, поиск в утечках. Поддерживает API-ключи для платных сервисов. Идеален для структурированных расследований где важно сохранять и связывать результаты между запросами.', descEn:'Recon-ng is a modular web reconnaissance framework built in the style of Metasploit. Features interactive CLI with autocomplete, module marketplace (70+ modules), built-in SQLite database for storing results. Modules cover: WHOIS lookup, DNS recon, social media search, email harvesting, breach data search. Supports API keys for paid services. Ideal for structured investigations where preserving and linking results between queries is important.' },

  { name:'OSINT Framework', url:'https://github.com/lockfale/osint-framework', icon:'📡', cat:'people', tags:['directory','reference'],
    desc:'OSINT Framework — не инструмент а интерактивная карта всех OSINT-ресурсов, организованная в виде дерева. Охватывает категории: поиск по людям, username, email, телефону, домену, IP, изображениям, социальным сетям, даркнету и многому другому. Каждый узел дерева ведёт на конкретный инструмент или сервис. Незаменим как отправная точка при изучении OSINT — помогает быстро найти подходящий инструмент под конкретную задачу.', descEn:'OSINT Framework is not a tool but an interactive map of all OSINT resources organized as a tree. Covers categories: people search, username, email, phone, domain, IP, images, social networks, darknet and much more. Each tree node links to a specific tool or service. Indispensable as a starting point when learning OSINT — helps quickly find the right tool for a specific task.' },

  { name:'Maltego CE', url:'https://github.com/MaltegoTech/maltego-trx', icon:'🕸️', cat:'network', tags:['graph','visualization'],
    desc:'Maltego — стандарт индустрии для визуального анализа связей между объектами. Строит интерактивные графы где узлы — это люди, домены, IP, email, организации, а рёбра — связи между ними. Имеет огромную библиотеку трансформаций (запросов к внешним источникам). Maltego CE — бесплатная версия с ограничениями. Используется в корпоративных расследованиях, кибербезопасности и журналистике. Позволяет буквально "видеть" инфраструктуру цели.', descEn:'Maltego is the industry standard for visual analysis of connections between objects. Builds interactive graphs where nodes are people, domains, IPs, emails, organizations, and edges are connections between them. Has a huge library of transforms (queries to external sources). Maltego CE is the free version with limitations. Used in corporate investigations, cybersecurity and journalism. Lets you literally \'see\' the target\'s infrastructure.' },

  { name:'ExifTool', url:'https://github.com/exiftool/exiftool', icon:'📷', cat:'image', tags:['metadata','exif','files'],
    desc:'ExifTool — универсальный инструмент для чтения, записи и редактирования метаданных файлов. Поддерживает более 30 000 тегов в сотнях форматов: JPEG, PNG, PDF, Word, Excel, видео и аудио файлы. Из фотографий можно извлечь GPS-координаты с точностью до метра, модель и серийный номер камеры, дату и время съёмки, настройки экспозиции. Метаданные документов часто содержат имя автора, путь к файлу на компьютере, версию ПО. Работает в командной строке, поддерживает пакетную обработку тысяч файлов.', descEn:'ExifTool is a universal tool for reading, writing and editing file metadata. Supports 30,000+ tags in hundreds of formats: JPEG, PNG, PDF, Word, Excel, video and audio files. From photos you can extract GPS coordinates to the meter, camera model and serial number, date and time of capture, exposure settings. Document metadata often contains author name, file path on the computer, software version. Runs from command line, supports batch processing of thousands of files.' },

  { name:'Metagoofil', url:'https://github.com/laramies/metagoofil', icon:'📄', cat:'network', tags:['metadata','documents'],
    desc:'Metagoofil автоматически ищет публичные документы (PDF, DOC, XLS, PPT) на сайте цели через Google, скачивает их и извлекает метаданные. Из найденных файлов извлекаются: имена пользователей Windows, пути к файлам (раскрывают структуру сети), версии ПО, email-адреса, названия отделов. Эти данные позволяют составить список реальных имён пользователей для атаки на аутентификацию или понять внутреннюю структуру организации.', descEn:'Metagoofil automatically searches for public documents (PDF, DOC, XLS, PPT) on a target site via Google, downloads them and extracts metadata. Extracted from found files: Windows usernames, file paths (revealing network structure), software versions, email addresses, department names. This data helps build a list of real usernames for authentication attacks or understand an organization\'s internal structure.' },

  { name:'Subfinder', url:'https://github.com/projectdiscovery/subfinder', icon:'🌐', cat:'network', tags:['subdomains','dns'],
    desc:'Subfinder — быстрый инструмент для пассивного обнаружения поддоменов. Использует более 50 пассивных источников: Censys, Certspotter, crt.sh, DNSdumpster, VirusTotal, Shodan, HackerTarget и другие. Полностью пассивный — не отправляет запросы напрямую к цели, что делает его незаметным. Написан на Go, работает очень быстро. Поддерживает множество форматов вывода. Входит в экосистему ProjectDiscovery и хорошо интегрируется с другими их инструментами.', descEn:'Subfinder is a fast tool for passive subdomain discovery. Uses 50+ passive sources: Censys, Certspotter, crt.sh, DNSdumpster, VirusTotal, Shodan, HackerTarget and others. Fully passive — doesn\'t send requests directly to the target, making it stealthy. Written in Go, very fast. Supports many output formats. Part of the ProjectDiscovery ecosystem and integrates well with their other tools.' },

  { name:'Amass', url:'https://github.com/owasp-amass/amass', icon:'🌊', cat:'network', tags:['subdomains','dns','mapping'],
    desc:'Amass — комплексный инструмент для картирования внешней поверхности атаки организации. Объединяет пассивные (DNS, сертификаты, веб-архивы, API) и активные (DNS-брутфорс, зонные трансферы) методы обнаружения поддоменов. Строит граф сетевой инфраструктуры. Поддерживает более 50 источников данных. Часть проекта OWASP. Один из наиболее полных инструментов для разведки DNS-инфраструктуры — находит то что другие пропускают.', descEn:'Amass is a comprehensive tool for mapping an organization\'s external attack surface. Combines passive (DNS, certificates, web archives, APIs) and active (DNS bruteforce, zone transfers) subdomain discovery methods. Builds a network infrastructure graph. Supports 50+ data sources. Part of the OWASP project. One of the most complete tools for DNS infrastructure recon — finds what others miss.' },

  { name:'DNSx', url:'https://github.com/projectdiscovery/dnsx', icon:'🔍', cat:'network', tags:['dns','resolve'],
    desc:'DNSx — быстрый и многофункциональный DNS-инструмент от ProjectDiscovery. Умеет резолвить массовые списки доменов, проверять наличие записей разных типов (A, AAAA, CNAME, MX, NS, TXT, PTR), брутфорсить поддомены по словарю. Поддерживает дикие карты DNS и умеет их фильтровать. Обрабатывает миллионы запросов в минуту благодаря конкурентной архитектуре на Go. Незаменим для массовой проверки и обогащения списков доменов.', descEn:'DNSx is a fast and versatile DNS tool from ProjectDiscovery. Can resolve mass domain lists, check for various record types (A, AAAA, CNAME, MX, NS, TXT, PTR), bruteforce subdomains from a wordlist. Supports DNS wildcards and can filter them. Processes millions of queries per minute thanks to concurrent Go architecture. Indispensable for mass verification and enrichment of domain lists.' },

  { name:'Httpx', url:'https://github.com/projectdiscovery/httpx', icon:'🌍', cat:'network', tags:['http','probe'],
    desc:'Httpx — быстрый HTTP-зондировщик от ProjectDiscovery. Принимает список хостов и проверяет какие из них доступны по HTTP/HTTPS, определяет коды ответов, заголовки, технологии (через Wappalyzer), снимает скриншоты. Помогает быстро отфильтровать живые хосты из тысяч найденных поддоменов. Поддерживает CDN-detection, следование редиректам, извлечение заголовков безопасности. Идеален в пайплайне после Subfinder или Amass.', descEn:'Httpx is a fast HTTP prober from ProjectDiscovery. Takes a list of hosts and checks which are accessible via HTTP/HTTPS, determines response codes, headers, technologies (via Wappalyzer), takes screenshots. Helps quickly filter live hosts from thousands of discovered subdomains. Supports CDN detection, redirect following, security header extraction. Ideal in a pipeline after Subfinder or Amass.' },

  { name:'Nuclei', url:'https://github.com/projectdiscovery/nuclei', icon:'⚡', cat:'network', tags:['scanner','templates'],
    desc:'Nuclei — быстрый сканер уязвимостей на основе YAML-шаблонов. База шаблонов от сообщества содержит тысячи проверок: CVE, неправильные конфигурации, раскрытие информации, устаревшие версии ПО. С точки зрения OSINT полезен для обнаружения открытых панелей администрирования, раскрытых конфигурационных файлов (.env, .git), открытых API без аутентификации. Работает очень быстро и поддерживает массовое сканирование.', descEn:'Nuclei is a fast vulnerability scanner based on YAML templates. The community template library contains thousands of checks: CVEs, misconfigurations, information disclosure, outdated software versions. From an OSINT perspective, useful for discovering open admin panels, exposed config files (.env, .git), open APIs without authentication. Works very fast and supports mass scanning.' },

  { name:'Photon', url:'https://github.com/s0md3v/Photon', icon:'💡', cat:'network', tags:['crawler','scraping'],
    desc:'Photon — быстрый веб-краулер оптимизированный для OSINT. Извлекает из сайтов: URL, email-адреса, номера телефонов, ссылки на социальные сети, ключи API, секреты в JavaScript-файлах, метаданные. Поддерживает рекурсивный обход с заданной глубиной, фильтрацию по типу данных, экспорт в JSON. Особенно полезен для нахождения случайно опубликованных секретов и внутренних ссылок на сайтах организаций.', descEn:'Photon is a fast web crawler designed specifically for OSINT. Extracts URLs, emails, social media links, files (images, documents), JavaScript files with endpoints, secrets (API keys, tokens in JS). Supports multithreading, works with different levels of depth. Can follow external links. Results saved in an organized directory structure. Written in Python.' },

  { name:'Social Mapper', url:'https://github.com/Greenwolf/social_mapper', icon:'🗂️', cat:'social', tags:['face','social-media'],
    desc:'Social Mapper автоматизирует поиск человека в социальных сетях по фото и имени. Использует распознавание лиц для подтверждения совпадений. Поддерживает LinkedIn, Facebook, Twitter, Instagram, Google+, VKontakte и другие. Принимает на вход список имён с фотографиями (например, из корпоративного сайта) и автоматически находит профили каждого сотрудника. Результаты сохраняются в HTML-отчёт. Мощный инструмент для массовой разведки по персоналу организации.', descEn:'Social Mapper automates the search for a person\'s profiles across social networks using facial recognition. You provide a name and photo — the tool searches Facebook, Twitter, LinkedIn, Instagram, VK and other platforms. Uses automated browser sessions. Helps quickly confirm whether profiles belong to the same person. Requires significant setup but saves hours of manual work on large-scale investigations.' },

  { name:'Twint', url:'https://github.com/twintproject/twint', icon:'🐦', cat:'social', tags:['twitter','scraping'],
    desc:'Twint позволяет собирать данные из Twitter/X без API-ключа — напрямую через веб-интерфейс. Умеет собирать твиты пользователя за любой период, искать по ключевым словам и геолокации, получать список подписчиков и подписок, собирать лайки. Данные сохраняются в CSV, JSON или SQLite. Позволяет строить временные линии активности пользователя, анализировать его интересы и связи. Полезен для исследования активности конкретных аккаунтов.', descEn:'Twint is a Twitter scraper that works without an API key. Collects tweets, followers, following lists, geolocations and mentions using specified filters. Can search by keyword, hashtag, date range, geographic location. Stores results in SQLite, CSV, JSON or Elasticsearch. Works around API limitations and can collect the full history of a user\'s tweets. Actively used in social media OSINT investigations.' },

  { name:'Osmedeus', url:'https://github.com/j3ssie/osmedeus', icon:'⚙️', cat:'network', tags:['automation','workflow'],
    desc:'Osmedeus — фреймворк для автоматизации OSINT и разведки. Оркестрирует запуск других инструментов (Subfinder, Amass, Httpx, Nuclei и других) в виде настраиваемых рабочих процессов. Поддерживает параллельное выполнение, уведомления через Slack/Telegram, веб-интерфейс для просмотра результатов. Идеален для Bug Bounty — запускаешь один процесс и получаешь полный отчёт о внешней инфраструктуре цели.', descEn:'Osmedeus is a workflow engine for automated penetration testing and reconnaissance. Defines execution pipelines: subdomain discovery → port scanning → service detection → vulnerability scanning. Supports parallel execution on multiple machines. Has a web dashboard to track progress. Integrates many popular tools: Subfinder, Amass, Nuclei, Httpx. Suitable for large-scale recon of organizations.' },

  { name:'Sn0int', url:'https://github.com/kpcyrd/sn0int', icon:'❄️', cat:'network', tags:['framework','osint'],
    desc:'Sn0int — полуавтоматический OSINT-фреймворк с собственным языком сценариев. Имеет встроенный маркетплейс модулей. Модули могут собирать данные из Shodan, Censys, crt.sh, социальных сетей, Tor-сети. Все данные хранятся в структурированной базе данных с возможностью связывания объектов. Умеет работать с Tor для анонимных запросов. Имеет интерактивный REPL-интерфейс. Хорошо подходит для структурированных расследований с накоплением данных.', descEn:'Sn0int is a semi-automatic OSINT framework written in Rust. Uses its own scripting language to describe data collection modules. Supports a marketplace of community modules. Built-in database for storing results with deduplication. Modules cover: subdomain discovery, social network search, email checks, IP analysis. Focused on structured data collection and relationship building.' },

  { name:'Karma_v2', url:'https://github.com/Dheerajmadhukar/karma_v2', icon:'🔱', cat:'network', tags:['passive','recon'],
    desc:'Karma_v2 — инструмент для пассивной разведки с использованием Shodan. Автоматически находит IP-адреса, связанные с доменом, проверяет открытые порты и сервисы, ищет уязвимые версии ПО, находит связанные поддомены через SSL-сертификаты. Умеет обходить WAF и CDN для получения реальных IP. Не отправляет пакеты напрямую к цели — работает исключительно через Shodan API, оставаясь полностью пассивным.', descEn:'Karma_v2 is a passive OSINT tool that finds exposed infrastructure assets. Works through passive data sources: Shodan, Censys, FOFA, BinaryEdge. Can discover IP addresses, domains, open ports, services, technologies without active scanning. Useful for mapping an organization\'s infrastructure without directly contacting it. Supports multiple API sources simultaneously.' },

  { name:'GrayhatWarfare', url:'https://github.com/0xsha/GoUtils', icon:'🪣', cat:'network', tags:['buckets','cloud'],
    desc:'Инструменты для поиска открытых облачных хранилищ (S3, Azure Blob, GCP). GrayhatWarfare индексирует миллионы публично доступных файлов в облачных бакетах. Позволяет искать по ключевым словам, доменам, компаниям. Открытые бакеты часто содержат: резервные копии баз данных, конфигурационные файлы с паролями, персональные данные клиентов, внутреннюю документацию. Один из ключевых источников при разведке облачной инфраструктуры организации.', descEn:'GrayhatWarfare is a search engine for open Amazon S3 buckets and Azure Blob Storage. Indexes millions of public cloud storage containers and their contents. Allows searching for files by keyword, extension, bucket name. Extremely useful for finding accidentally exposed sensitive data: configs, backups, databases, source code, personal data. Often reveals much more than expected.' },

  { name:'LeakIX', url:'https://github.com/LeakIX/l9explore', icon:'💧', cat:'network', tags:['leaks','exposed'],
    desc:'LeakIX — поисковик по открытым и скомпрометированным сервисам в интернете. Индексирует открытые базы данных (MongoDB, Elasticsearch, Redis), незащищённые панели управления, раскрытые конфигурационные файлы. В отличие от Shodan фокусируется именно на уязвимых и утёкших данных. l9explore — CLI-инструмент для работы с LeakIX API. Полезен для проверки собственной инфраструктуры на предмет случайных утечек.', descEn:'LeakIX is an internet scanning platform focused on detecting exposed and misconfigured services. Indexes open databases (MongoDB, Elasticsearch, Redis), open admin panels, insecure services. Has an API for programmatic access. Useful for monitoring your own infrastructure\'s exposure and investigating target organizations\' security posture. Updated regularly with new scan results.' },

  { name:'Crosslinked', url:'https://github.com/m8sec/crosslinked', icon:'🔗', cat:'social', tags:['linkedin','employees'],
    desc:'Crosslinked автоматизирует сбор имён сотрудников организации через LinkedIn без использования официального API. Использует поисковые запросы к Google и Bing. По найденным именам генерирует возможные корпоративные email-адреса в различных форматах (firstname.lastname@company.com и других). Результаты можно использовать для проверки через Hunter.io или в качестве списка для пентеста. Незаменим для разведки по персоналу.', descEn:'Crosslinked is a LinkedIn reconnaissance tool for gathering employee names. Uses search engine Google dorks to extract full names from LinkedIn profiles without needing an account or API. Generates potential username formats from found names (j.smith, jsmith, john.smith). Especially useful for creating username wordlists for password spraying against corporate services.' },

  { name:'Creepy', url:'https://github.com/ilektrojohn/creepy', icon:'🗺️', cat:'geo', tags:['geolocation','social'],
    desc:'Creepy собирает геолокационные данные из социальных сетей — Twitter, Flickr, Instagram. Анализирует геотеги фотографий и геолоцированные твиты, строит карту перемещений человека во времени. Позволяет отфильтровать точки по дате и времени. Результаты отображаются на интерактивной карте. Может экспортировать маршруты в KML для Google Earth. Отличный инструмент для понимания где бывает человек в разное время суток.', descEn:'Creepy is a geolocation OSINT tool that aggregates location data from social networks. Collects geotagged posts from Twitter, Instagram, Flickr and other platforms. Visualizes found locations on an interactive map. Can build movement patterns over time. Helps understand where a person has been and when, based on publicly available social media data.' },

  { name:'Datasploit', url:'https://github.com/DataSploit/datasploit', icon:'🧬', cat:'people', tags:['automated','osint'],
    desc:'Datasploit — автоматизированный OSINT-фреймворк для сбора информации о людях, компаниях, доменах и email. Объединяет данные из десятков источников и формирует сводный отчёт. Умеет искать по email, домену, имени, телефону и IP. Интегрируется с Shodan, Hunter.io, VirusTotal, HaveIBeenPwned. Результаты сохраняются в текстовые файлы и базу данных. Хорошо подходит для быстрого первичного сбора информации.', descEn:'Datasploit is an automated OSINT framework that correlates data about a target from multiple sources. Accepts email, domain, username or phone number as input. Searches across: social networks, WHOIS, DNS, Shodan, breach databases, dark web. Generates comprehensive HTML reports. Useful for quick initial reconnaissance when you need to collect maximum information in minimum time.' },

  { name:'PhoneInfoga', url:'https://github.com/sundowndev/phoneinfoga', icon:'📱', cat:'people', tags:['phone','lookup'],
    desc:'PhoneInfoga — специализированный инструмент для разведки по номерам телефонов. Определяет страну, оператора, тип линии (мобильная/стационарная/VoIP). Ищет номер в открытых источниках: Google, социальные сети, телефонные справочники. Имеет веб-интерфейс и REST API. Умеет работать с номерами из разных стран в различных форматах. Даёт быстрый обзор доступной публичной информации о номере.', descEn:'PhoneInfoga is one of the most advanced tools for phone number OSINT. Collects information using only free resources and open sources. Checks number validity and format, carrier, country. Searches Google, social networks, phone directories. Has a web interface for convenient use. Can reveal who the number belongs to, social accounts linked to it, and other public information.' },

  { name:'Infoga', url:'https://github.com/The404Hacking/Infoga', icon:'📧', cat:'email', tags:['email','gathering'],
    desc:'Infoga собирает информацию об email-адресах из разных источников: поисковики, PGP-серверы, Shodan. Определяет домен, проверяет MX-записи, ищет упоминания в интернете. Умеет проверять существование email через SMTP без фактической отправки письма. Поддерживает сбор сразу по домену — находит все публично известные адреса организации. Простой и быстрый инструмент для первичной разведки по email.', descEn:'Infoga is a tool for gathering email account information. Uses various sources: search engines, PGP servers, Shodan and other APIs. Finds linked social networks, checks whether the email is in breach databases, collects associated names and other metadata. Useful at the initial stage of email-based recon to understand how much information is publicly linked to an address.' },

  { name:'h8mail', url:'https://github.com/khast3x/h8mail', icon:'🔓', cat:'email', tags:['email','breach','leaks'],
    desc:'h8mail — инструмент для поиска email-адресов в базах утечек. Поддерживает несколько API для поиска в утечках: HaveIBeenPwned, Hunter.io, IntelX, Snusbase. Умеет работать с локальными базами утечек в разных форматах. Находит пароли, хэши и другие данные связанные с email из реальных утечек. Особенно ценен для оценки реального ущерба от компрометации корпоративного адреса.', descEn:'h8mail is an email OSINT tool specialized in finding credentials in data breaches. Supports multiple APIs: HaveIBeenPwned, Hunter, Snusbase, WeLeakInfo and others. Can process large lists of emails. Shows which breaches an address appeared in and what data was exposed. Password and hash data helps verify accounts and understand a person\'s password patterns.' },

  { name:'WhatBreach', url:'https://github.com/Ekultek/WhatBreach', icon:'🚨', cat:'email', tags:['breach','database'],
    desc:'WhatBreach автоматически находит в каких утечках баз данных фигурирует данный email-адрес. Использует HIBP API и другие источники. Умеет скачивать публично доступные утечки для локального анализа. Показывает сколько раз и в каких базах встречался адрес, какие данные утекли (пароли, телефоны, адреса). Помогает оценить цифровой след человека в контексте утечек данных.', descEn:'WhatBreach is a tool for checking email addresses against breach databases. Uses multiple APIs to determine in which data leaks an address appeared. Shows breach names, dates, and what type of data was exposed (passwords, phone numbers, addresses). Helps quickly assess what information about a target is available from leaks for further investigation.' },

  { name:'EmailHarvester', url:'https://github.com/maldevel/EmailHarvester', icon:'✉️', cat:'email', tags:['email','search'],
    desc:'EmailHarvester собирает email-адреса из открытых источников через поисковые системы. Поддерживает Google, Bing, Yahoo, ASK, DogPile. Имеет поддержку прокси и случайных User-Agent для обхода блокировок. Результаты сохраняются в текстовый файл. Прост в использовании и не требует API-ключей. Хорошо работает для быстрого сбора корпоративных email по домену.', descEn:'EmailHarvester is a tool for extracting email addresses from websites and search engines. Uses dorks and crawling to collect contact information. Supports multiple search engines. Can process large domains and collect email lists of an organization\'s employees. Results can be used for further verification and phishing simulations in authorized tests.' },

  { name:'GHunt', url:'https://github.com/mxrch/GHunt', icon:'🔮', cat:'people', tags:['google','account'],
    desc:'GHunt позволяет извлечь информацию из аккаунта Google по email или Google ID. Находит: имя владельца, фото профиля, подключённые сервисы Google (YouTube, Maps, Reviews), публичные отзывы на Google Maps, активность в Google Play. Также может анализировать Google Calendar на предмет публичных событий. Даёт неожиданно много информации о человеке через его Google-аккаунт.', descEn:'GHunt is an OSINT tool for Google accounts. Given an email address, it extracts: Google profile, account creation date, linked YouTube/Maps/Photos services, last activity, calendar information, reviews. Exploits various public Google APIs. One of the most powerful tools for email-based OSINT — reveals much more information than a simple search.' },

  { name:'Socialscan', url:'https://github.com/iojw/socialscan', icon:'📲', cat:'social', tags:['username','email','check'],
    desc:'Socialscan проверяет доступность username и email на популярных платформах. В отличие от Sherlock, он не просто проверяет наличие страницы, а использует точные API-запросы через форму регистрации, что даёт значительно меньше ложных срабатываний. Поддерживает Instagram, Twitter, GitHub, Reddit, Telegram, TikTok и другие. Написан на Python с асинхронными запросами — работает быстро.', descEn:'Socialscan is a tool for accurately checking username and email availability across social platforms. Unlike Sherlock, uses official APIs rather than heuristics, which eliminates false positives. Supports: GitHub, Reddit, Twitter, Instagram, DeviantArt and more. Very fast thanks to concurrent processing. Useful for confirming account existence before deeper analysis.' },

  { name:'Nexfil', url:'https://github.com/thewhiteh4t/nexfil', icon:'🌀', cat:'social', tags:['username','platforms'],
    desc:'Nexfil — инструмент для поиска профилей по никнейму на 350+ платформах. Имеет встроенную систему проверки валидности результатов для снижения ложных срабатываний. Поддерживает поиск сразу по нескольким никнеймам. Отображает результаты в цветном виде в терминале, сохраняет в текстовый файл. Регулярно обновляется новыми платформами. Хорошая альтернатива Sherlock с отличающейся базой платформ.', descEn:'Nexfil is a username search tool across social networks and websites. Checks 350+ platforms and shows which accounts exist. Features a clean color-coded interface, multithreading support. Similar to Sherlock but with a different platform set. Supports JSON export. Regularly updated with new platforms. Good for use in combination with other username search tools.' },

  { name:'BlackBird', url:'https://github.com/p1ngul1n0/blackbird', icon:'🐧', cat:'social', tags:['username','osint'],
    desc:'BlackBird — инструмент поиска аккаунтов по username и email на 500+ платформах. Особенность — формирует красивый HTML-отчёт с превью найденных профилей. Умеет извлекать дополнительную информацию с найденных страниц: биографию, количество подписчиков, аватар. Поддерживает использование прокси. Имеет Docker-образ для простого запуска. Отличается высоким качеством отчётности.', descEn:'BlackBird is an OSINT tool for finding accounts by username or email. Uses intelligent platform checks: does not just check for 404 response but analyzes page content. Supports 200+ platforms. Shows account creation dates and other available metadata. Has a web interface in addition to CLI. Written in Python with async support for high speed.' },

  { name:'UserFinder', url:'https://github.com/mishakorzik/UserFinder', icon:'👤', cat:'social', tags:['username','search'],
    desc:'UserFinder ищет аккаунты по имени пользователя на популярных платформах. Простой и легковесный инструмент без лишних зависимостей. Поддерживает более 200 сайтов. Выводит результаты прямо в терминал с цветовой индикацией. Подходит для быстрой проверки когда нужен простой инструмент без сложной настройки.', descEn:'UserFinder is a tool for finding a person\'s accounts across social networks by username. Checks 200+ platforms with multithreading. Outputs results in JSON format for subsequent processing. Supports proxy usage. Actively maintained and updated with new sites. Good addition to Sherlock and Maigret — the three tools together cover maximum platforms.' },

  { name:'WhatsMyName', url:'https://github.com/WebBreacher/WhatsMyName', icon:'🏷️', cat:'social', tags:['username','enumeration'],
    desc:'WhatsMyName — проект с базой данных для проверки существования аккаунтов на сайтах. База содержит правила для точной проверки — не просто наличие страницы, а конкретные признаки существующего аккаунта. Используется другими инструментами как источник данных. Сам по себе может запускаться как Python-скрипт. База регулярно обновляется сообществом и содержит более 600 платформ.', descEn:'WhatsMyName is a project that maintains an actively updated database of user presence indicators across hundreds of web services. The database is used as a backend in many other OSINT tools (Recon-ng, Spiderfoot). Has its own web interface. Supports contribution from the community to add new sites. One of the most reliable sources for username checks.' },

  { name:'Recon-ng', url:'https://github.com/lanmaster53/recon-ng', icon:'🛰️', cat:'network', tags:['framework','web'],
    desc:'Recon-ng предоставляет среду для проведения разведки в открытых источниках. Фреймворк содержит независимые модули, функции помощи и управление результатами для ускорения процессов OSINT. Полностью интерактивная командная строка с автодополнением по Tab. Поддерживает хранение всех результатов в базе данных с возможностью создания отчётов.', descEn:'Recon-ng Marketplace module for extended data collection. This module adds integration with additional API sources to extend the framework\'s capabilities. Suitable for professional recon workflows.' },

  { name:'Pagodo', url:'https://github.com/opsdisk/pagodo', icon:'🎣', cat:'network', tags:['google-dorks','passive'],
    desc:'Pagodo автоматизирует Google-дорки для пассивного сбора информации о потенциально уязвимых веб-приложениях. Использует базу дорков GHDB (Google Hacking Database). Обходит блокировки Google через случайные задержки и ротацию прокси. Находит: открытые панели входа, незащищённые файлы конфигурации, открытые директории, утечки информации через метаданные. Полностью пассивный — не обращается к цели напрямую.', descEn:'Pagodo (Passive Google Dork) automates Google Hacking Database (GHDB) dork queries. Downloads the GHDB database and runs hundreds of dork queries against a target domain. Finds: open directories, exposed configs, login panels, sensitive files, vulnerabilities. Implements smart delays to avoid Google blocks. Saves a lot of time on manual dorking.' },

  { name:'Dorkbot', url:'https://github.com/jgor/dorkbot', icon:'🤖', cat:'network', tags:['dorks','scanner'],
    desc:'Dorkbot сканирует результаты поисковых дорков на наличие уязвимостей. Использует Google или Bing для поиска потенциально уязвимых URL по заданным доркам, затем сканирует найденные URL с помощью инструментов типа Nikto или SQLMap. Хорошо подходит для Bug Bounty-программ где нужно быстро найти потенциально уязвимые эндпоинты в большом масштабе.', descEn:'Dorkbot is an automated tool for running Google dork queries and scanning found URLs for known vulnerabilities. Uses the GHDB database. Can process a list of dorks and check results for specific vulnerability patterns. Useful for quickly assessing how much sensitive information about a target is indexed by Google.' },

  { name:'GitHarvester', url:'https://github.com/metac0rtex/GitHarvester', icon:'🐙', cat:'network', tags:['github','secrets'],
    desc:'GitHarvester ищет конфиденциальную информацию в публичных GitHub-репозиториях через GitHub Search API. Находит случайно закоммиченные секреты: API-ключи, пароли, токены доступа, приватные ключи. Поддерживает поиск по организации или пользователю. Позволяет задать собственные паттерны поиска через регулярные выражения. Утечки секретов в GitHub — одна из самых распространённых проблем корпоративной безопасности.', descEn:'GitHarvester is a tool for collecting data from GitHub via search queries. Finds repositories, issues, code snippets containing keywords related to the target. Can discover: company infrastructure code, accidentally committed configurations, internal documentation. Useful for corporate recon — developers often accidentally push sensitive data to public repos.' },

  { name:'TruffleHog', url:'https://github.com/trufflesecurity/trufflehog', icon:'🐷', cat:'network', tags:['secrets','github'],
    desc:'TruffleHog сканирует Git-репозитории, файловые системы, S3-бакеты и другие источники в поисках случайно опубликованных секретов. Использует более 700 детекторов для поиска ключей AWS, Google, Stripe, GitHub, Slack и сотен других сервисов. Проверяет найденные ключи на актуальность через реальные API-запросы. Поддерживает сканирование всей истории коммитов включая удалённые файлы.', descEn:'TruffleHog is a specialized tool for finding secrets in Git repositories. Scans commit history and file content for: API keys, tokens, passwords, private keys. Uses entropy analysis and regular expressions. Supports GitHub, GitLab, Bitbucket and local repos. Can find secrets even in deleted files that remain in git history. An essential tool in security audits.' },

  { name:'GitLeaks', url:'https://github.com/gitleaks/gitleaks', icon:'🔑', cat:'network', tags:['secrets','git'],
    desc:'GitLeaks — быстрый инструмент для обнаружения секретов и чувствительных данных в Git-репозиториях. Сканирует историю коммитов, staging area и рабочую директорию. Имеет встроенный набор правил для обнаружения ключей популярных сервисов. Поддерживает интеграцию в CI/CD-пайплайн для предотвращения утечек. Может сканировать как локальные репозитории, так и удалённые через GitHub/GitLab API.', descEn:'GitLeaks is a tool for detecting sensitive data in Git repositories. Uses configurable rules to find API keys, tokens, credentials and other secrets. Supports pre-commit hooks to prevent accidental secret commits. Can scan both individual repos and entire GitHub organizations. Faster than TruffleHog on large repositories. Integrated in many CI/CD pipelines.' },

  { name:'Dumpster Diver', url:'https://github.com/securing/DumpsterDiver', icon:'🗑️', cat:'network', tags:['secrets','files'],
    desc:'DumpsterDiver анализирует большие объёмы данных в поиске жёстко закодированных секретов. Умеет анализировать ZIP-архивы, PDF-файлы, документы Office. Использует эвристику и энтропийный анализ для нахождения случайно выглядящих строк (ключей, токенов). Поддерживает настраиваемые правила. Полезен при анализе утечек — когда есть большой дамп файлов и нужно быстро найти в нём секреты.', descEn:'Dumpster Diver is a tool for searching through files in an S3 bucket or local filesystem for sensitive data. Looks for passwords, API keys, private keys, PII data. Uses content analysis of various file formats: text files, JSON, YAML, XML, source code. Useful when you\'ve already found an open bucket and need to quickly assess the sensitivity of its contents.' },

  { name:'SecretFinder', url:'https://github.com/m4ll0k/SecretFinder', icon:'🔐', cat:'network', tags:['javascript','secrets'],
    desc:'SecretFinder находит конфиденциальные данные в JavaScript-файлах. Анализирует JS-код сайтов в поисках API-ключей, токенов, URL внутренних эндпоинтов, учётных данных. Может сканировать конкретный JS-файл или весь сайт рекурсивно. Использует регулярные выражения для поиска паттернов различных сервисов. Очень часто в публичных JS-файлах случайно оставляют ключи к API и внутренние URL.', descEn:'SecretFinder is a tool for finding sensitive data in JavaScript files. Analyzes JS code and looks for: API keys, tokens, URLs of internal endpoints, passwords, credentials. Uses regular expressions for detection. Can process both local files and URLs. Essential when analyzing web applications — JS files often contain accidentally exposed secrets.' },

  { name:'LinkFinder', url:'https://github.com/GerbenJavado/LinkFinder', icon:'🔗', cat:'network', tags:['javascript','endpoints'],
    desc:'LinkFinder извлекает эндпоинты (URL и пути) из JavaScript-файлов. Анализирует JS-код и находит скрытые API-пути, внутренние URL, параметры. Поддерживает как анализ локальных файлов, так и онлайн-сканирование сайта. Результаты можно фильтровать по паттернам. Находит API-эндпоинты которые не документированы публично и могут быть уязвимы или раскрывать внутреннюю информацию.', descEn:'LinkFinder is a Python script for discovering endpoints and links in JavaScript files. Extracts all URLs, API paths and parameters from JS source code. Helps discover hidden endpoints in single-page applications where traditional crawlers fail. Can process both URLs and local files. Often reveals API endpoints not documented in public sources.' },

  { name:'FOCA', url:'https://github.com/ElevenPaths/FOCA', icon:'🦊', cat:'network', tags:['metadata','documents'],
    desc:'FOCA (Fingerprinting Organizations with Collected Archives) — Windows-инструмент для анализа метаданных публичных документов. Автоматически ищет документы через поисковики, скачивает и анализирует метаданные. Из найденных файлов извлекает: имена пользователей, пути к сетевым ресурсам, принтеры, email-адреса, версии ПО, операционные системы. Строит граф инфраструктуры организации на основе найденных данных.', descEn:'FOCA (Fingerprinting Organizations with Collected Archives) is a tool for metadata analysis and network information discovery. Automatically searches and downloads documents from a target domain, extracts metadata. Can discover internal server names, usernames, software. Also performs DNS, WHOIS, network analysis. Popular in penetration testing for pre-engagement recon.' },

  { name:'Wireshark-OSINT', url:'https://github.com/SecurityBreached/OSINT-tool-list', icon:'🦈', cat:'network', tags:['traffic','analysis'],
    desc:'Комплексный список OSINT-инструментов с описаниями и ссылками. Охватывает все категории: разведка по людям, сетям, социальным сетям, геолокации, email и телефонам. Включает как популярные так и малоизвестные инструменты. Регулярно обновляется. Полезен как справочник для выбора подходящего инструмента под конкретную задачу.', descEn:'Wireshark OSINT techniques involve using network traffic analysis for intelligence gathering. By analyzing captured packets you can identify: devices on the network, protocols used, connected external services, data transmission patterns. Useful for internal network analysis when physical access is available, or for analyzing traffic from known devices.' },

  { name:'AssetFinder', url:'https://github.com/tomnomnom/assetfinder', icon:'🎯', cat:'network', tags:['subdomains','assets'],
    desc:'AssetFinder от tomnomnom — простой и быстрый инструмент для поиска доменов и поддоменов связанных с заданным доменом. Использует пассивные источники: crt.sh, HackerTarget, Riddler.io, Certspotter и другие. Прост в использовании — принимает домен на вход и выводит список найденных активов. Хорошо работает в пайплайнах Unix с другими инструментами через pipe.', descEn:'AssetFinder is a fast tool for finding domains and subdomains associated with a target. Uses multiple sources: Certificate Transparency logs, crt.sh, Certspotter, Hackertarget, Wayback Machine, and others. Written in Go, works very fast. Simple to use: just pass a domain and get a list of related assets. Good for initial asset discovery before deeper analysis.' },

  { name:'Gau', url:'https://github.com/lc/gau', icon:'🌀', cat:'network', tags:['urls','wayback'],
    desc:'Gau (Get All URLs) собирает известные URL для домена из нескольких источников: Wayback Machine, Common Crawl, OTX AlienVault, URLScan. Позволяет найти исторические URL которые больше не существуют, но могут содержать интересные параметры или эндпоинты. Очень быстр. Часто используется для поиска забытых файлов, старых версий API, удалённых страниц.', descEn:'Gau (Get All URLs) fetches known URLs for a domain from multiple sources: Wayback Machine, AlienVault OTX, Common Crawl, URLScan. Helps discover endpoints, files, parameters that were once accessible but may no longer appear in navigation. Written in Go, very fast. Often reveals forgotten pages, old APIs, backup files. Used in combination with other URL analysis tools.' },

  { name:'Waybackurls', url:'https://github.com/tomnomnom/waybackurls', icon:'⏰', cat:'network', tags:['wayback','urls'],
    desc:'Waybackurls извлекает все URL которые когда-либо были проиндексированы Wayback Machine для заданного домена. Позволяет найти: старые эндпоинты API, удалённые файлы конфигурации, исторические версии страниц, забытые директории. Написан на Go, работает быстро. Незаменим для поиска "скрытых" частей сайта которые существовали раньше.', descEn:'Waybackurls extracts all URLs for a domain from the Wayback Machine archive. Helps find: old endpoints that may still work, forgotten files and directories, historical API paths. Fast alternative to manual Wayback Machine browsing. Used in combination with Gau for comprehensive URL discovery. Often reveals interesting endpoints missed by active crawling.' },

  { name:'Katana', url:'https://github.com/projectdiscovery/katana', icon:'⚔️', cat:'network', tags:['crawler','spider'],
    desc:'Katana — быстрый и настраиваемый веб-краулер от ProjectDiscovery. Поддерживает как стандартный HTTP-краулинг, так и JavaScript-рендеринг через headless-браузер. Автоматически заполняет формы, следует редиректам, обнаруживает эндпоинты в JS-файлах. Имеет гибкую систему фильтров. Отличный выбор для глубокого картирования веб-приложения перед тестированием.', descEn:'Katana is a next-generation web crawler from ProjectDiscovery. Supports both standard and headless (JavaScript) crawling. Automatically discovers forms, endpoints, JavaScript-based links. Smart filtering to avoid redundant crawling. Integrates with other PD tools. Much more effective than traditional crawlers for modern web applications built on React/Vue/Angular.' },

  { name:'Hakrawler', url:'https://github.com/hakluke/hakrawler', icon:'🕷️', cat:'network', tags:['crawler','fast'],
    desc:'Hakrawler — быстрый Go-краулер для поиска эндпоинтов и активов на сайте. Извлекает ссылки из HTML, JavaScript-файлов, sitemap.xml. Принимает список URL из stdin, поддерживает параллельную обработку. Прост в использовании и хорошо работает в Unix-пайплайнах. Подходит для быстрого картирования поверхности атаки.', descEn:'Hakrawler is a fast web crawler designed for quick discovery of endpoints and assets. Extracts URLs, forms, emails, and JavaScript file links. Written in Go, supports parallel crawling. Uses both standard crawling and Wayback Machine data. Suited for rapid initial recon before deeper analysis. Easily integrates in pipelines via stdin/stdout.' },

  { name:'GoWitness', url:'https://github.com/sensepost/gowitness', icon:'📸', cat:'network', tags:['screenshot','web'],
    desc:'GoWitness делает скриншоты веб-страниц в масштабе. Принимает список URL и создаёт скриншот каждого используя headless Chrome. Сохраняет результаты в SQLite с веб-интерфейсом для просмотра. Поддерживает импорт результатов из Nmap, Masscan и других сканеров. Незаменим для быстрого визуального аудита большого количества найденных хостов.', descEn:'GoWitness is a website screenshot tool written in Go using Chrome headless. Takes screenshots of web pages, saves response headers and status codes. Can process large lists of URLs in parallel. Used to quickly triage hundreds of discovered subdomains: instead of manually visiting each site, view a gallery of screenshots. Stores results in SQLite for convenient search and filtering.' },

  { name:'EyeWitness', url:'https://github.com/RedSiege/EyeWitness', icon:'👁️', cat:'network', tags:['screenshot','reporting'],
    desc:'EyeWitness делает скриншоты веб-сайтов, RDP и VNC-серверов. Создаёт подробный HTML-отчёт с скриншотами, HTTP-заголовками, информацией о сервере. Умеет категоризировать и приоритизировать находки. Поддерживает Nmap XML и Nessus CSV на вход. Отличный инструмент для первоначального осмотра найденных хостов в ходе разведки.', descEn:'EyeWitness is a tool for taking screenshots of websites, RDP and VNC services. Automatically categorizes discovered services. Generates HTML report with screenshots and metadata. Can detect default credentials on common devices. Used during large-scale network recon to quickly identify interesting services without visiting each one manually.' },

  { name:'Aquatone', url:'https://github.com/michenriksen/aquatone', icon:'🦆', cat:'network', tags:['screenshot','domains'],
    desc:'Aquatone — инструмент для визуальной инспекции доменов. Принимает список хостов, проверяет их доступность и делает скриншоты. Формирует подробный HTML-отчёт с классификацией находок. Хорошо интегрируется в пайплайн с Subfinder, Amass и другими инструментами разведки. Позволяет быстро визуально оценить большое количество поддоменов.', descEn:'Aquatone is a tool for visual inspection of websites at scale. Accepts a list of domains/IPs, takes screenshots, collects HTTP response headers. Generates HTML reports grouped by similarity — sites with the same technology or appearance appear together. Useful for quickly identifying interesting targets among hundreds of discovered assets.' },

  { name:'MassDNS', url:'https://github.com/blechschmidt/massdns', icon:'🚀', cat:'network', tags:['dns','bruteforce'],
    desc:'MassDNS — высокоскоростной DNS-резолвер способный обрабатывать миллионы запросов в минуту. Используется для брутфорса поддоменов по большим словарям. В связке с качественным словарём может найти поддомены которые пассивные методы не обнаруживают. Требует указания публичных DNS-серверов для распределения нагрузки. Один из самых быстрых инструментов в своём классе.', descEn:'MassDNS is an extremely fast DNS resolver capable of resolving millions of domains per second using public resolvers. Used for large-scale subdomain bruteforcing. Requires a wordlist and a list of DNS resolvers. Can handle lists of tens of millions of potential subdomains. Written in C for maximum performance. Often used as a backend in other DNS tools.' },

  { name:'PureDNS', url:'https://github.com/d3mondev/puredns', icon:'💨', cat:'network', tags:['dns','resolver'],
    desc:'PureDNS — точный и надёжный DNS-брутфорсер и резолвер. Решает проблему wildcard DNS-записей которая часто даёт ложные срабатывания при брутфорсе поддоменов. Автоматически определяет wildcard-домены и исключает их из результатов. Использует MassDNS под капотом для скорости. Один из самых надёжных инструментов для обнаружения реальных поддоменов.', descEn:'PureDNS is a fast DNS bruteforce and resolution tool. Automatically filters wildcard DNS records which is critical for accurate subdomain discovery. Uses MassDNS as a backend for high speed. Includes a built-in resolver validation system — automatically removes unreliable resolvers. Handles millions of DNS requests with high accuracy.' },

  { name:'Altdns', url:'https://github.com/infosec-au/altdns', icon:'🔀', cat:'network', tags:['dns','permutations'],
    desc:'Altdns генерирует перестановки и мутации поддоменов для обнаружения дополнительных активов. Принимает список найденных поддоменов и создаёт новые варианты добавляя слова (dev, staging, api, test, admin) в разных позициях. Получившийся список резолвируется для нахождения реально существующих хостов. Часто находит staging и development-серверы которые не индексируются публично.', descEn:'Altdns generates subdomain permutations based on found subdomains. Given a list of known subdomains, creates many variations: dev-api, api-dev, staging-api, api.staging, etc. Often finds subdomains missed by other tools. Can generate millions of potential names for subsequent resolution with MassDNS or PureDNS. Simple but very effective in combination with other subdomain tools.' },

  { name:'DNSRecon', url:'https://github.com/darkoperator/dnsrecon', icon:'🔭', cat:'network', tags:['dns','enumeration'],
    desc:'DNSRecon — комплексный инструмент для DNS-разведки. Выполняет: стандартное перечисление записей, поиск зонных трансферов, брутфорс поддоменов, reverse lookup, проверку DNSSEC, кэш-снупинг. Один из наиболее полных инструментов для DNS-анализа. Результаты сохраняются в SQLite или XML. Входит в Kali Linux. Хорошо подходит для глубокого изучения DNS-конфигурации домена.', descEn:'DNSRecon is a comprehensive DNS enumeration tool. Performs: zone transfer attempts, standard record enumeration, subdomain bruteforcing, reverse lookup, zone walking for DNSSEC. Checks for misconfigurations. Supports output in JSON and XML. Written in Python. Good for thorough and structured DNS analysis of a single domain rather than mass scanning.' },

  { name:'Fierce', url:'https://github.com/mschwager/fierce', icon:'🦁', cat:'network', tags:['dns','reconnaissance'],
    desc:'Fierce — DNS-сканер разработанный для нахождения нелинейного IP-пространства и имён хостов против нецелевых или целевых сетей. Выполняет зонные трансферы, перебирает поддомены, выполняет обратный поиск по найденным IP. Находит смежные сети и другие домены связанные с целью. Хорошо обнаруживает смежные серверы которые могут быть связаны с основной целью.', descEn:'Fierce is a DNS recon tool for finding non-contiguous IP space and hostnames. Performs zone transfer attempts, checks for wildcard DNS, enumerates nearby IP space. Written in Python. Not as fast as modern Go tools but useful for thorough analysis of a single organization\'s DNS infrastructure. Can discover IP ranges adjacent to a target that may belong to the same organization.' },

  { name:'Shodan CLI', url:'https://github.com/achillean/shodan-python', icon:'🔍', cat:'network', tags:['shodan','iot'],
    desc:'Официальная Python-библиотека и CLI для Shodan. Позволяет автоматизировать поиск в Shodan из командной строки и скриптов. Поддерживает все возможности Shodan API: поиск, получение информации о хостах, мониторинг сетей, уведомления об изменениях. Незаменим для интеграции данных Shodan в автоматизированные рабочие процессы разведки.', descEn:'Shodan CLI is the official command-line interface for the Shodan search engine. Enables querying Shodan data from the terminal: search by query, download results, get information about IPs, domains and organizations. Supports creating monitors for new discoveries. Can be integrated into automated scripts. Requires a paid API key for full functionality.' },

  { name:'Censys-Python', url:'https://github.com/censys/censys-python', icon:'🌐', cat:'network', tags:['censys','api'],
    desc:'Официальная Python-библиотека для Censys API. Позволяет программно выполнять поиск по базе Censys: хосты, сертификаты, домены. Поддерживает агрегирующие запросы для анализа большого количества данных. Censys особенно силён в области TLS-сертификатов и позволяет находить инфраструктуру по данным сертификатов.', descEn:'Censys Python is the official Python library for the Censys API. Allows programmatically searching for hosts, certificates and datasets. Supports complex queries to find specific services and configurations. Can bulk fetch IP metadata. Used to build automated recon pipelines. Censys data focuses on TLS certificates and protocol banners, complementing Shodan.' },

  { name:'IVRE', url:'https://github.com/ivre/ivre', icon:'🗺️', cat:'network', tags:['framework','passive'],
    desc:'IVRE — фреймворк для анализа сетей. Умеет хранить и анализировать данные из Nmap, Masscan, ZMap, Shodan, Censys. Предоставляет веб-интерфейс для визуализации и анализа данных. Поддерживает пассивный сбор данных через анализ трафика. Позволяет строить собственную базу данных просканированного интернет-пространства. Хорошо подходит для долгосрочного мониторинга инфраструктуры.', descEn:'IVRE (Instrument de Veille sur les Réseaux Extérieurs) is a network recon framework with a web interface. Stores and analyzes data from various sources: Nmap, Masscan, Zeek, Argus. Builds a database of network infrastructure. Useful for storing and analyzing the results of large-scale scans. Has its own web interface for searching and visualizing results.' },

  { name:'Netlas.io CLI', url:'https://github.com/netlas-io/netlas-python', icon:'🌊', cat:'network', tags:['netlas','search'],
    desc:'Python-клиент для Netlas — поисковика по интернет-инфраструктуре. Netlas индексирует все IPv4-адреса, открытые порты и сервисы. CLI позволяет автоматизировать поиск и интегрировать данные Netlas в скрипты. Альтернатива Shodan с рядом уникальных возможностей включая поиск по содержимому страниц и заголовкам.', descEn:'Netlas CLI is the command-line interface for the Netlas.io internet scanner. Netlas scans the internet and provides rich metadata about hosts: banners, certificates, DNS records, WHOIS. Similar to Shodan but with some unique data. CLI allows integrating data into automated pipelines. Particularly useful for finding services by specific technology signatures.' },

  { name:'Dirsearch', url:'https://github.com/maurosoria/dirsearch', icon:'📂', cat:'network', tags:['directory','bruteforce'],
    desc:'Dirsearch — инструмент для перебора директорий и файлов на веб-серверах. Имеет встроенный словарь из тысяч распространённых путей. Поддерживает рекурсивный обход, фильтрацию по коду ответа, расширения файлов, случайный User-Agent. Один из самых популярных инструментов для обнаружения скрытого контента на сайтах. Находит: панели администрирования, резервные копии, конфигурационные файлы, тестовые страницы.', descEn:'Dirsearch is a web path and file bruteforcing tool. Uses a wordlist to discover hidden directories, files and endpoints. Supports multithreading, various HTTP methods, custom headers and cookies. Has smart filtering of false positives. Includes a large built-in wordlist. Written in Python, easy to configure. The go-to tool for web application content discovery.' },

  { name:'Feroxbuster', url:'https://github.com/epi052/feroxbuster', icon:'🔨', cat:'network', tags:['directory','fuzzing'],
    desc:'Feroxbuster — быстрый рекурсивный инструмент для обнаружения контента. Написан на Rust для максимальной производительности. Поддерживает рекурсивный обход (автоматически сканирует найденные директории), фильтрацию результатов, ротацию User-Agent, поддержку прокси. Умеет автоматически обнаруживать и исключать wildcard-ответы. Один из лучших инструментов для брутфорса директорий.', descEn:'Feroxbuster is a fast content discovery tool written in Rust. Designed for recursive directory bruteforcing — automatically descends into discovered directories. Very fast thanks to async Rust. Supports smart filtering by status code, size and words. Auto-calibrates false positive detection. Often finds more content than Dirsearch on complex applications.' },

  { name:'Ffuf', url:'https://github.com/ffuf/ffuf', icon:'🎭', cat:'network', tags:['fuzzing','web'],
    desc:'Ffuf (Fuzz Faster U Fool) — универсальный веб-фаззер написанный на Go. Может фаззить: директории, параметры GET/POST, заголовки HTTP, субдомены через Host-заголовок. Поддерживает несколько словарей одновременно. Мощная система фильтрации результатов по коду, размеру, словам, строкам в ответе. Один из наиболее гибких и быстрых инструментов для веб-разведки.', descEn:'Ffuf (Fuzz Faster U Fool) is a versatile web fuzzer. Used for: directory/file discovery, virtual host discovery via Host header fuzzing, parameter bruteforcing, API endpoint discovery. Very fast, highly configurable filtering. Can fuzz any part of an HTTP request (URL, headers, body, parameters). The most flexible fuzzing tool — replaces Wfuzz in many workflows.' },

  { name:'Gobuster', url:'https://github.com/OJ/gobuster', icon:'👻', cat:'network', tags:['directory','dns'],
    desc:'Gobuster — быстрый инструмент для перебора URI, DNS-поддоменов и виртуальных хостов. Написан на Go, поддерживает параллельные запросы. Имеет несколько режимов: dir (перебор директорий), dns (поддомены), vhost (виртуальные хосты), s3 (S3-бакеты), gcs (Google Cloud Storage). Один из самых популярных инструментов в Bug Bounty сообществе.', descEn:'Gobuster is a tool for directory, DNS and virtual host bruteforcing written in Go. Three modes: dir (web paths), dns (subdomains), vhost (virtual hosts). Very fast thanks to parallel Go goroutines. Simple to use. Good default choice for quick content discovery. Less feature-rich than Ffuf but faster and simpler for straightforward tasks.' },

  { name:'Wfuzz', url:'https://github.com/xmendez/wfuzz', icon:'🌪️', cat:'network', tags:['fuzzing','web'],
    desc:'Wfuzz — швейцарский нож для фаззинга веб-приложений. Может подставлять payload в любую часть HTTP-запроса. Имеет богатую систему фильтров и плагинов. Поддерживает аутентификацию, прокси, куки. Особенно мощен для поиска скрытых параметров и эндпоинтов. Умеет работать с несколькими словарями и кодировками payload.', descEn:'Wfuzz is a web fuzzer designed for web application assessment. Supports fuzzing of any HTTP request parameter. Has powerful filtering by response code, size, words. Can detect hidden resources, parameters, authentication bypasses. Python-based, highly extensible. One of the oldest but still popular tools in the web security assessment arsenal.' },

  { name:'Arjun', url:'https://github.com/s0md3v/Arjun', icon:'🔎', cat:'network', tags:['parameters','discovery'],
    desc:'Arjun находит скрытые GET и POST параметры в веб-приложениях. Использует умные эвристики — сначала пробует небольшие группы параметров, затем бинарным поиском сужает до реально существующих. Имеет базу из 25 000+ параметров. Поддерживает JSON, XML, form-data форматы тела запроса. Незаменим для поиска скрытых функциональных возможностей API.', descEn:'Arjun is a tool for discovering hidden GET and POST parameters in web applications. Tries thousands of common parameter names to find ones that affect the application\'s response. Useful for finding hidden API parameters, debug flags, undocumented functionality. Uses smart heuristics to detect meaningful responses. Often reveals hidden application functionality.' },

  { name:'ParamSpider', url:'https://github.com/devanshbatham/ParamSpider', icon:'🕷️', cat:'network', tags:['parameters','urls'],
    desc:'ParamSpider собирает URL с параметрами для заданного домена из Wayback Machine и Common Crawl. Фильтрует дубликаты и нерелевантные результаты. Позволяет быстро получить список URL с параметрами которые стоит проверить на уязвимости. Поддерживает исключение определённых расширений файлов и фильтрацию по паттернам.', descEn:'ParamSpider is a tool for collecting URL parameters from web archives. Extracts parameter names and values from the Wayback Machine and other URL archives. Helps discover what parameters an application accepts without active scanning. Found parameters are useful for further fuzzing and vulnerability testing. Written in Python, easy to integrate in workflows.' },

  { name:'URO', url:'https://github.com/s0md3v/uro', icon:'🧹', cat:'network', tags:['urls','dedup'],
    desc:'URO (URL Reduction Tool) умно дедуплицирует и фильтрует большие списки URL. Убирает дубликаты учитывая семантическую эквивалентность (одинаковые параметры в разном порядке). Сохраняет только уникальные URL с разными параметрами. Незаменим в пайплайне после Gau или Waybackurls для очистки тысяч URL перед анализом.', descEn:'URO is a URL list deduplication tool. Removes redundant and duplicate URLs from large lists — keeps only unique parameter combinations. Essential when working with thousands of URLs from Gau, Waybackurls and other tools. Significantly reduces lists before further analysis without losing unique paths. Written in Python, works very fast.' },

  { name:'Haklistgen', url:'https://github.com/hakluke/haklistgen', icon:'📝', cat:'network', tags:['wordlist','generation'],
    desc:'Haklistgen генерирует кастомные словари для брутфорса на основе содержимого сайта. Скачивает все страницы и JS-файлы цели, извлекает слова и формирует словарь. Кастомный словарь специфичный для конкретного приложения значительно эффективнее универсальных словарей при поиске скрытых директорий и параметров.', descEn:'Haklistgen is a wordlist generation tool from discovered content. Extracts words from web pages and creates a targeted wordlist for bruteforcing. The generated wordlist is specific to the target domain — contains terms from the site\'s actual content. Often more effective than generic wordlists for discovering specific paths and parameters.' },

  { name:'CeWL', url:'https://github.com/digininja/CeWL', icon:'📚', cat:'network', tags:['wordlist','custom'],
    desc:'CeWL (Custom Word List generator) создаёт кастомные словари на основе содержимого сайта. Краулит сайт до заданной глубины, собирает уникальные слова заданной минимальной длины. Опционально собирает email-адреса и метаданные. Кастомные словари из контента самого сайта или организации значительно эффективнее при подборе паролей и директорий.', descEn:'CeWL (Custom Word List Generator) is a tool for creating wordlists from target website content. Crawls a site and extracts all unique words of specified minimum length. Used to create targeted wordlists for password spraying — employees often use company-specific terms in passwords. Can include email addresses found on the site. Written in Ruby.' },

  { name:'Wappalyzer CLI', url:'https://github.com/wappalyzer/wappalyzer', icon:'🔬', cat:'network', tags:['technology','fingerprint'],
    desc:'Wappalyzer определяет технологии используемые на сайте: CMS, фреймворки, серверы, аналитику, рекламные сети. CLI позволяет автоматизировать fingerprinting в скриптах. База данных содержит тысячи сигнатур технологий. Знание стека технологий помогает определить какие CVE могут быть применимы и какие векторы атаки наиболее перспективны.', descEn:'Wappalyzer CLI is the command-line version of the popular technology detection tool. Identifies CMS, frameworks, web servers, analytics and other technologies used on a website. Uses multiple detection methods: HTTP headers, HTML patterns, JavaScript variables, cookies. Knowing the target\'s technology stack helps choose appropriate attack vectors and tools.' },

  { name:'Whatweb', url:'https://github.com/urbanadventurer/WhatWeb', icon:'🌐', cat:'network', tags:['fingerprint','web'],
    desc:'WhatWeb идентифицирует технологии сайта — CMS, фреймворки, веб-серверы, плагины, версии ПО. Имеет более 1800 плагинов для fingerprinting. Поддерживает агрессивный режим для более точного определения версий. Может сканировать большой диапазон IP-адресов. Полезен для быстрого составления профиля технологического стека цели.', descEn:'WhatWeb identifies websites and their technologies. Detects over 1800 different technologies: CMS versions, blogging platforms, analytics, JavaScript libraries, web servers, operating systems. Each plugin has different levels of aggression — from passive header analysis to active probing. Outputs in various formats for automated processing.' },

  { name:'CMSeeK', url:'https://github.com/Tuhinshubhra/CMSeeK', icon:'🔍', cat:'network', tags:['cms','detection'],
    desc:'CMSeeK определяет тип и версию системы управления контентом сайта. Поддерживает обнаружение WordPress, Joomla, Drupal, Magento и более 170 других CMS. Для WordPress дополнительно перечисляет: версию, темы, плагины, пользователей. Знание конкретной версии CMS позволяет найти известные уязвимости и неправильные конфигурации.', descEn:'CMSeeK is a CMS detection and exploitation tool. Supports: WordPress, Joomla, Drupal and 180+ other CMSs. Performs in-depth scanning: version detection, theme and plugin enumeration, user enumeration, vulnerability search. Automatically tries known exploits for detected versions. Useful when the target is running one of the popular CMSs.' },

  { name:'WPScan', url:'https://github.com/wpscanteam/wpscan', icon:'🎯', cat:'network', tags:['wordpress','scanner'],
    desc:'WPScan — специализированный сканер безопасности для WordPress. Обнаруживает: версию WordPress, установленные темы и плагины с их версиями, пользователей, слабые пароли (через брутфорс), уязвимые компоненты. Использует собственную базу уязвимостей WPVulnDB. Стандартный инструмент при аудите WordPress-сайтов — которых в интернете более 40%.', descEn:'WPScan is the de facto standard for WordPress security auditing. Detects: WordPress version, installed themes and plugins with versions, users, security misconfigurations. Has its own vulnerability database updated regularly. Can enumerate users and attempt password bruteforcing. Supports both passive and aggressive scanning modes. Used both by pentesters and site owners.' },

  { name:'CMSmap', url:'https://github.com/dionach/CMSmap', icon:'🗺️', cat:'network', tags:['cms','vulnerability'],
    desc:'CMSmap автоматизирует обнаружение уязвимостей в популярных CMS: WordPress, Joomla, Drupal, Moodle. Перечисляет компоненты и проверяет их на наличие известных уязвимостей. Поддерживает брутфорс паролей. Генерирует отчёты. Хорош для быстрого аудита безопасности сайта когда нужно охватить несколько CMS одним инструментом.', descEn:'CMSmap is a CMS vulnerability scanner. Supports: WordPress, Joomla, Drupal, Moodle. Finds known vulnerabilities in detected CMS versions, enumerates users and plugins. Simpler than WPScan but covers a broader range of CMSs. Useful for quick assessment of common CMS installations. Written in Python, actively maintained.' },

  { name:'Joomscan', url:'https://github.com/OWASP/joomscan', icon:'🔭', cat:'network', tags:['joomla','scanner'],
    desc:'OWASP JoomScan — специализированный сканер для Joomla CMS. Определяет версию Joomla, перечисляет установленные компоненты и модули, проверяет известные уязвимости, ищет раскрытие информации. Часть проекта OWASP. Аналог WPScan но для Joomla — второй по популярности CMS в мире после WordPress.', descEn:'Joomscan is an OWASP project tool for scanning Joomla CMS installations. Detects Joomla version, finds known vulnerabilities in core and extensions, enumerates users and components. Automatically checks against a database of known Joomla vulnerabilities. Specifically designed for Joomla, making it more thorough than generic CMS scanners for this platform.' },

  { name:'Droopescan', url:'https://github.com/SamJoan/droopescan', icon:'💉', cat:'network', tags:['drupal','cms'],
    desc:'Droopescan — сканер на основе плагинов для Drupal и других CMS. Определяет версию Drupal, темы и модули. Проверяет известные уязвимости. Поддерживает также SilverStripe и другие CMS. Прост в расширении через систему плагинов. Необходим при тестировании сайтов на Drupal — часто используемой CMS для корпоративных и правительственных сайтов.', descEn:'Droopescan is a plugin-based scanner for several CMSs: Drupal, WordPress, SilverStripe, Moodle. Enumerates: installed plugins and themes, versions, users. Uses a passive detection approach that minimizes target-side noise. Particularly effective for Drupal sites — often finds more information than generic scanners. Written in Python.' },

  { name:'SQLMap', url:'https://github.com/sqlmapproject/sqlmap', icon:'💉', cat:'network', tags:['sql','injection'],
    desc:'SQLMap — легендарный инструмент для автоматического обнаружения и эксплуатации SQL-инъекций. Поддерживает все популярные СУБД: MySQL, PostgreSQL, Oracle, SQLite, MS SQL Server и другие. Умеет: обнаруживать инъекции, извлекать данные, получать доступ к файловой системе, выполнять команды. С точки зрения OSINT полезен для демонстрации уязвимостей найденных при разведке.', descEn:'SQLMap is the leading automated SQL injection detection and exploitation tool. Automatically discovers SQL injection vulnerabilities and extracts data from databases. Supports: MySQL, PostgreSQL, Oracle, MSSQL, SQLite and others. Can: extract database contents, bypass WAFs, escalate to OS command execution, download files. Indispensable in web application penetration testing.' },

  { name:'XSSer', url:'https://github.com/epsylon/xsser', icon:'⚡', cat:'network', tags:['xss','scanner'],
    desc:'XSSer — автоматический фреймворк для обнаружения XSS-уязвимостей. Имеет более 1300 специальных векторов атаки. Поддерживает разные типы XSS: reflected, stored, DOM-based. Умеет обходить WAF и фильтры. Генерирует отчёты в разных форматах. Может работать в сочетании с прокси-сервером для ручного тестирования.', descEn:'XSSer is an automatic framework for detecting, exploiting and reporting XSS vulnerabilities. Contains a large library of XSS payloads, supports various encoding methods to bypass filters. Can automatically generate PoC for found vulnerabilities. Supports injecting into GET, POST parameters, cookies and HTTP headers. Written in Python.' },

  { name:'Nikto', url:'https://github.com/sullo/nikto', icon:'🔦', cat:'network', tags:['web','scanner'],
    desc:'Nikto — классический сканер веб-серверов. Проверяет на наличие: устаревших компонентов с известными уязвимостями, опасных файлов, неправильных конфигураций, открытых директорий. База содержит более 6700 потенциально опасных файлов и программ. Один из самых известных инструментов для базового аудита веб-серверов. Входит в состав большинства дистрибутивов для пентеста.', descEn:'Nikto is one of the oldest and most well-known web server scanners. Checks for over 6700 potentially dangerous files, outdated software versions, server configuration issues. Very fast and simple to use. Results include links to CVEs for found issues. Works through proxies. Included in Kali Linux. Has many false positives but covers a very wide range of checks.' },

  { name:'Skipfish', url:'https://github.com/spinkham/skipfish', icon:'🐟', cat:'network', tags:['web','audit'],
    desc:'Skipfish — активный разведчик безопасности веб-приложений от Google. Краулит сайт и проверяет каждую найденную страницу на типичные уязвимости. Генерирует подробный HTML-отчёт с классифицированными находками. Написан на C, очень быстр. Поддерживает аутентификацию и куки. Хорошо справляется с крупными сайтами за счёт высокой производительности.', descEn:'Skipfish is an active web security assessment tool from Google. Performs high-performance crawling and testing. Detects: SQL injection, XSS, CSRF, path traversal, authentication issues. Generates an interactive HTML report. Very fast — can send thousands of requests per second. Less popular than other tools but generates very thorough reports.' },

  { name:'Nmap', url:'https://github.com/nmap/nmap', icon:'🗺️', cat:'network', tags:['port-scan','fingerprint'],
    desc:'Nmap — стандарт индустрии для сканирования сетей и портов. Определяет открытые порты, запущенные сервисы и их версии, операционную систему хоста. Имеет мощный движок скриптов (NSE) с тысячами готовых скриптов для обнаружения уязвимостей, сбора информации, брутфорса. Незаменим для картирования сетевой инфраструктуры цели.', descEn:'Nmap is the most famous and widely used network port scanner. Discovers open ports, determines service versions (nmap -sV), detects operating system (-O). Has a powerful scripting engine (NSE) with hundreds of scripts for vulnerability detection and service enumeration. The starting tool for network reconnaissance. Supports many scan types: TCP SYN, UDP, IDLE, ping scan.' },

  { name:'Masscan', url:'https://github.com/robertdavidgraham/masscan', icon:'🚀', cat:'network', tags:['port-scan','fast'],
    desc:'Masscan — самый быстрый сканер портов в мире. Способен просканировать весь интернет за 6 минут. Использует асинхронный подход и собственный TCP-стек. Синтаксис похож на Nmap. Идеален для быстрого первичного сканирования больших диапазонов IP. Часто используется в паре с Nmap: Masscan находит открытые порты, Nmap проводит детальный анализ.', descEn:'Masscan can scan the entire internet in under 6 minutes. Sends up to 10 million packets per second. Used for rapid discovery of open ports across large IP ranges. Less informative than Nmap (only ports, no service detection), but incomparably faster. Commonly used for initial wide-area scanning before deeper Nmap analysis of discovered hosts.' },

  { name:'Rustscan', url:'https://github.com/RustScan/RustScan', icon:'🦀', cat:'network', tags:['port-scan','rust'],
    desc:'RustScan — современный быстрый сканер портов написанный на Rust. Сканирует все 65535 портов за секунды, затем передаёт результаты в Nmap для детального анализа. Поддерживает скриптинг, Docker, настраиваемые батчи. Объединяет скорость Masscan с богатством возможностей Nmap. Активно развивается и имеет удобный интерфейс.', descEn:'Rustscan is a modern port scanner written in Rust. Scans all 65535 ports in under a second, then automatically passes results to Nmap for detailed analysis. Combines speed of Masscan with Nmap\'s flexibility. Supports custom Nmap scripts. Ideal for when you need both speed and full Nmap capabilities. The modern replacement for separate tools in many workflows.' },

  { name:'Zmap', url:'https://github.com/zmap/zmap', icon:'⚡', cat:'network', tags:['internet-scan','fast'],
    desc:'ZMap — быстрый сетевой сканер для исследований. Способен просканировать весь IPv4-интернет за 45 минут на гигабитном соединении. Разработан для исследований интернет-безопасности. Имеет модульную архитектуру и поддержку разных протоколов. Используется для измерения распространённости определённых сервисов и уязвимостей в масштабе всего интернета.', descEn:'ZMap is a network scanner designed for internet-wide surveys. Can scan the entire IPv4 internet in under an hour on a gigabit connection. Used for research and internet-wide security studies. Supports multiple probe types: TCP, UDP, ICMP. More reliable than Masscan for research-grade scanning. Used in academic studies of internet security posture.' },

  { name:'Zgrab2', url:'https://github.com/zmap/zgrab2', icon:'🦀', cat:'network', tags:['banner-grab','protocol'],
    desc:'ZGrab2 — инструмент для захвата баннеров и анализа протоколов в масштабе. В паре с ZMap позволяет не только найти открытые порты но и получить детальную информацию о запущенных сервисах. Поддерживает: HTTP, FTP, SSH, SMTP, TLS, Telnet и другие протоколы. Извлекает сертификаты, версии, конфигурации.', descEn:'Zgrab2 is a Go application scanner that complements ZMap. After ZMap discovers open ports, Zgrab2 performs application-layer banner grabbing. Supports many protocols: HTTP, HTTPS, SSH, FTP, SMTP, IMAP, TLS and others. Extracts banners, certificates, HTTP responses. Used in internet-wide surveys to collect service metadata at scale.' },

  { name:'Cloudbrute', url:'https://github.com/0xsha/CloudBrute', icon:'☁️', cat:'network', tags:['cloud','enumeration'],
    desc:'CloudBrute перебирает ресурсы в облачных инфраструктурах (AWS, Azure, GCP) для нахождения открытых хранилищ и других сервисов. Использует списки слов для генерации вариантов названий бакетов. Проверяет доступность и права на чтение. Открытые облачные хранилища — частый источник серьёзных утечек данных корпораций.', descEn:'Cloudbrute is a tool for discovering an organization\'s cloud infrastructure. Bruteforces storage service names (S3, GCS, Azure Blob) and other cloud services using company-specific wordlists. Can find: open storage buckets, cloud-hosted services, CDN distributions. Useful when you know the target company name but need to find its cloud assets.' },

  { name:'CloudEnum', url:'https://github.com/initstring/cloud_enum', icon:'☁️', cat:'network', tags:['cloud','aws','azure'],
    desc:'Cloud_enum перечисляет публичные ресурсы в AWS, Azure и Google Cloud по ключевым словам. Проверяет: S3-бакеты, Azure Blobs, Google Cloud Storage, Azure DevOps, GitHub. Принимает список ключевых слов (название компании, продукта) и автоматически генерирует и проверяет возможные варианты названий ресурсов.', descEn:'CloudEnum enumerates cloud resources for a keyword. Checks: AWS (S3, CloudFront, Elastic Beanstalk), Azure (Blob Storage, websites), GCP (storage, apps). Simple but effective for initial cloud asset discovery. Often finds forgotten development environments and staging servers with weaker security than production. Written in Python.' },

  { name:'S3Scanner', url:'https://github.com/sa7mon/S3Scanner', icon:'🪣', cat:'network', tags:['s3','aws'],
    desc:'S3Scanner проверяет Amazon S3 бакеты на наличие неправильной конфигурации доступа. Принимает список названий бакетов и определяет: существует ли бакет, доступен ли для чтения/записи анонимно, какие файлы в нём содержатся. Находит утечки данных в незащищённых S3-хранилищах.', descEn:'S3Scanner scans and enumerates Amazon S3 buckets. Takes a list of bucket names and checks their accessibility and permissions: open read, open write, authenticated access, no access. Can dump the contents of accessible buckets. Helps find accidentally exposed sensitive data in cloud storage. Supports AWS, DigitalOcean Spaces and other S3-compatible storage.' },

  { name:'Bucket Finder', url:'https://github.com/mattweidner/bucket_finder', icon:'🔍', cat:'network', tags:['s3','buckets'],
    desc:'Bucket Finder ищет публично доступные AWS S3 бакеты по словарю. Генерирует варианты имён на основе заданного ключевого слова, проверяет доступность. Скачивает содержимое найденных открытых бакетов. Простой но эффективный инструмент для нахождения незащищённых облачных хранилищ.', descEn:'Bucket Finder is a tool for discovering publicly accessible Amazon S3 buckets. Uses common company name variations to find associated buckets. Can check permissions and list contents of discovered buckets. Often finds accidentally exposed buckets with sensitive company data. Simple to use and effective for initial cloud reconnaissance.' },

  { name:'AWSBucketDump', url:'https://github.com/jordanpotti/AWSBucketDump', icon:'🗑️', cat:'network', tags:['aws','s3'],
    desc:'AWSBucketDump автоматически перечисляет и скачивает содержимое публичных S3-бакетов. Использует словарь для генерации имён бакетов, скачивает интересные файлы по расширению. Умеет работать с несколькими потоками для ускорения. Поиск ключевых слов в именах файлов позволяет быстро найти конфиденциальные данные.', descEn:'AWSBucketDump is a tool for dumping interesting files from S3 buckets. Unlike scanners, focuses on extracting valuable content: looks for files with extensions like .xls, .doc, .sql, .bak, etc. Useful when access to a bucket is confirmed and you need to quickly find the most valuable data without downloading everything. Written in Python.' },

  { name:'GitDumper', url:'https://github.com/arthaud/git-dumper', icon:'🐙', cat:'network', tags:['git','exposed'],
    desc:'GitDumper скачивает Git-репозиторий с сайта когда директория .git случайно открыта для доступа. Это позволяет получить полный исходный код сайта включая историю коммитов. В коде могут находиться: конфигурационные файлы с паролями, хэши паролей, ключи API, комментарии с внутренней информацией.', descEn:'GitDumper is a tool for downloading a .git directory from websites where directory listing is disabled but git files are accessible. Reconstructs the repository from individual git objects and refs. Often finds complete source code of web applications accidentally left accessible on production servers. A critical security misconfiguration that reveals entire codebases.' },

  { name:'GitTools', url:'https://github.com/internetwache/GitTools', icon:'🛠️', cat:'network', tags:['git','exposed'],
    desc:'GitTools — набор инструментов для работы с открытыми .git-директориями. Включает: Finder (находит сайты с открытым .git), Dumper (скачивает репозиторий), Extractor (восстанавливает файлы из частично скачанного репозитория). Открытый .git-каталог — одна из самых распространённых критических ошибок конфигурации веб-серверов.', descEn:'GitTools is a collection of tools for working with exposed .git directories: Finder (discovers git repos in URLs), Dumper (downloads the .git directory), Extractor (extracts source code even from incomplete git repos). The complete toolkit for git-based source code disclosure exploitation. Essential for web application security assessments.' },

  { name:'CORS Scanner', url:'https://github.com/chenjj/CORScanner', icon:'🌐', cat:'network', tags:['cors','misconfiguration'],
    desc:'CORScanner проверяет веб-сайты на неправильную конфигурацию CORS (Cross-Origin Resource Sharing). Обнаруживает ситуации когда сайт позволяет запросы с произвольных источников или зеркалирует Origin-заголовок без проверки. Некорректная настройка CORS может позволить злоумышленнику читать данные других пользователей.', descEn:'CORS Scanner is a tool for detecting misconfigured CORS (Cross-Origin Resource Sharing) policies. Checks if a web application allows requests from arbitrary origins, which can lead to data theft. Tests various CORS bypass techniques. Processes lists of URLs for mass scanning. CORS misconfigurations are a common vulnerability in modern web APIs.' },

  { name:'Commix', url:'https://github.com/commixproject/commix', icon:'💻', cat:'network', tags:['command-injection','automated'],
    desc:'Commix автоматизирует поиск и эксплуатацию уязвимостей внедрения команд ОС в веб-приложениях. Поддерживает различные техники обхода WAF, работу через прокси, несколько режимов инъекций. С точки зрения OSINT демонстрирует насколько опасными могут быть найденные уязвимости в веб-интерфейсах сетевых устройств.', descEn:'Commix (Command Injection Exploiter) is an automated tool for finding and exploiting OS command injection vulnerabilities. Supports multiple injection techniques, WAF bypass methods. Can execute operating system commands on vulnerable servers. Once command injection is confirmed, can attempt to establish a reverse shell. Written in Python, regularly updated.' },

  { name:'XSStrike', url:'https://github.com/s0md3v/XSStrike', icon:'⚡', cat:'network', tags:['xss','advanced'],
    desc:'XSStrike — продвинутый инструмент для обнаружения и эксплуатации XSS-уязвимостей. Использует собственный парсер HTML и JS, генерирует умные payload с обходом WAF. Умеет находить DOM XSS через анализ JavaScript. Может краулить сайт и проверять все найденные формы и параметры. Один из наиболее интеллектуальных XSS-сканеров.', descEn:'XSStrike is an advanced XSS detection and exploitation tool. Uses fuzzing with intelligent payloads that consider the context of injection (HTML, JavaScript, attributes). Analyzes responses to craft the most effective payloads. Can crawl applications and test all parameters. Has a WAF detection and evasion mode. More intelligent than simple XSS scanners.' },

  { name:'Retire.js', url:'https://github.com/RetireJS/retire.js', icon:'📦', cat:'network', tags:['javascript','vulnerabilities'],
    desc:'Retire.js находит устаревшие JavaScript-библиотеки с известными уязвимостями. Проверяет версии jQuery, Angular, React, Vue и тысяч других библиотек. Доступен как CLI, плагин для браузера, плагин для Burp Suite. База уязвимостей регулярно обновляется. Устаревшие JS-библиотеки — очень частая находка при аудите веб-приложений.', descEn:'Retire.js identifies JavaScript libraries with known vulnerabilities. Works as a browser extension, command-line tool or Burp Suite plugin. Compares used library versions against its vulnerability database. Essential for web application security assessments — outdated frontend libraries are a very common attack vector. Integrates in CI/CD pipelines for automated dependency checking.' },

  { name:'Osint-spy', url:'https://github.com/SharadKumar97/OSINT-SPY', icon:'🕵️', cat:'people', tags:['osint','all-in-one'],
    desc:'OSINT-SPY — комплексный инструмент для сбора информации об email, IP, домене или человеке. Интегрируется с несколькими API: Shodan, VirusTotal, EmailRep. Выводит результаты в структурированном виде. Прост в установке и использовании. Хорошо подходит для быстрого первичного сбора данных об объекте разведки.', descEn:'OSINT-spy is an OSINT tool that collects information about a domain, email, IP or phone number from multiple sources. Automatically queries: WHOIS, DNS, Shodan, Censys, email reputation services. Generates a structured report. Written in Python. Good as a first step for quick target profiling — collects the most important data from key sources in one command.' },

  { name:'Recon-pipeline', url:'https://github.com/epi052/recon-pipeline', icon:'🔄', cat:'network', tags:['automation','pipeline'],
    desc:'Recon-pipeline автоматизирует разведку с использованием очередей задач. Координирует запуск множества инструментов (Amass, Masscan, Nmap, Gobuster и других), управляет зависимостями между задачами. Хранит результаты в базе данных. Поддерживает паузу и возобновление. Идеален для длительных автоматизированных кампаний разведки.', descEn:'Recon-pipeline is an automated recon framework with dependency management between scanning stages. Defines tasks and their dependencies: subdomain discovery → resolution → port scanning → service detection. Uses Luigi for pipeline orchestration. Supports distributed execution. Saves state between runs — continues from where it stopped. Good for long-running recon of large organizations.' },

  { name:'Intrigue Core', url:'https://github.com/intrigueio/intrigue-core', icon:'🧠', cat:'network', tags:['discovery','framework'],
    desc:'Intrigue Core — платформа для обнаружения активов и поверхностей атаки. Использует задачи для сбора данных из DNS, Shodan, Censys, сертификатов. Строит граф связей между активами. Имеет веб-интерфейс. Используется для инвентаризации внешней инфраструктуры организации и поиска забытых активов.', descEn:'Intrigue Core is an attack surface management platform. Automatically discovers and maps an organization\'s digital assets: domains, IPs, services, cloud resources. Builds a graph of relationships between assets. Regularly checks for new assets. Has an API and web interface. Used by large organizations for continuous monitoring of their attack surface.' },

  { name:'AttackSurface Mapper', url:'https://github.com/superhedgy/AttackSurfaceMapper', icon:'🗺️', cat:'network', tags:['attack-surface','mapping'],
    desc:'AttackSurfaceMapper автоматически картирует поверхность атаки организации. Собирает: поддомены, IP-адреса, открытые порты, email-адреса, информацию о сотрудниках, данные из социальных сетей. Формирует отчёт со всеми найденными активами. Хорошо подходит для первичной разведки перед пентестом или Bug Bounty.', descEn:'AttackSurface Mapper (ASM) is an automated recon tool for comprehensive attack surface discovery. Combines data from multiple sources to build a complete picture of a target\'s internet-facing assets. Discovers subdomains, IPs, open ports, web technologies, cloud assets. Generates reports in multiple formats. Written in Python.' },

  { name:'Reconftw', url:'https://github.com/six2dez/reconftw', icon:'🔄', cat:'network', tags:['automation','allInOne'],
    desc:'ReconFTW — полностью автоматизированный фреймворк для разведки. Оркестрирует более 30 инструментов в едином рабочем процессе: обнаружение поддоменов, проверка живых хостов, скриншоты, поиск параметров, поиск секретов, сканирование на уязвимости. Результаты отправляются в Slack/Discord. Один из наиболее полных автоматизированных решений для Bug Bounty.', descEn:'ReconFTW is an automated recon tool that integrates 90+ tools and runs them in the correct order. Performs comprehensive reconnaissance: subdomain discovery → alive host checking → port scanning → screenshot taking → vulnerability scanning. Highly configurable — can run specific stages or all at once. One of the most complete automated recon solutions available.' },

  { name:'Final Recon', url:'https://github.com/thewhiteh4t/FinalRecon', icon:'🎯', cat:'network', tags:['recon','automated'],
    desc:'FinalRecon — быстрый инструмент для веб-разведки с простым интерфейсом. Выполняет: WHOIS, GeoIP, SSL-анализ, анализ заголовков, поиск поддоменов через crt.sh, DNS-записи, поиск в Shodan, сканирование директорий. Все результаты в одном месте. Хорошо подходит для быстрого первичного аудита домена.', descEn:'Final Recon is an automated web recon tool. Performs: WHOIS, SSL certificate analysis, header analysis, DNS, Shodan, WAF detection, directory bruteforcing, subdomain enumeration and more. All in one tool with a simple interface. Good for quick comprehensive recon of a target without setting up complex pipelines. Written in Python.' },

  { name:'Findomain', url:'https://github.com/Findomain/Findomain', icon:'🔭', cat:'network', tags:['subdomains','fast'],
    desc:'Findomain — один из самых быстрых инструментов для поиска поддоменов. Написан на Rust. Использует пассивные источники: Chaos, Shodan, Facebook Certificate Transparency, Google, Virustotal и другие. Поддерживает мониторинг — уведомляет о новых поддоменах через Slack/Discord/Telegram. Может интегрироваться с Nmap для немедленного сканирования найденных хостов.', descEn:'Findomain is a very fast subdomain finder written in Rust. Queries multiple passive sources: Certificate Transparency, Shodan, VirusTotal, SecurityTrails, Spyse, and others. Supports monitoring mode — notifies when new subdomains appear. Also has paid cloud version. Among the fastest passive subdomain finders — processes thousands of queries per second.' },

  { name:'Chaos Client', url:'https://github.com/projectdiscovery/chaos-client', icon:'🌀', cat:'network', tags:['subdomains','dataset'],
    desc:'Chaos от ProjectDiscovery — клиент для доступа к их постоянно обновляемой базе поддоменов. База содержит данные по миллионам доменов. Позволяет быстро получить актуальный список поддоменов без необходимости самостоятельного сбора. Особенно полезен для Bug Bounty — быстрый охват большой поверхности атаки.', descEn:'Chaos is ProjectDiscovery\'s public API containing subdomain data for millions of top domains. The client lets you query this database for instant subdomain lists without running your own passive recon. Data is collected and updated regularly. Extremely fast for initial subdomain discovery. Used in combination with other tools for comprehensive coverage.' },

  { name:'Shosubgo', url:'https://github.com/incogbyte/shosubgo', icon:'🔍', cat:'network', tags:['shodan','subdomains'],
    desc:'Shosubgo собирает поддомены через Shodan API. Ищет SSL-сертификаты в базе Shodan которые содержат имена хостов заданного домена. Быстрый и простой инструмент для дополнения результатов других методов поиска поддоменов. Иногда находит поддомены которые не индексируются в Certificate Transparency логах.', descEn:'Shosubgo is a tool for subdomain discovery using Shodan API. Queries Shodan\'s database for subdomains of a given domain. Shodan\'s dataset is unique — it comes from direct internet scanning, not passive sources. Can find subdomains that don\'t appear in DNS records or Certificate Transparency logs. Written in Go.' },

  { name:'Vita', url:'https://github.com/junnlikestea/vita', icon:'🌱', cat:'network', tags:['subdomains','aggregator'],
    desc:'Vita агрегирует поддомены из нескольких пассивных источников одновременно: Chaos, Shodan, crt.sh, HackerTarget, VirusTotal. Написан на Rust, работает быстро. Простой интерфейс — принимает домен, выдаёт список поддоменов. Хорошо работает в пайплайнах и легко интегрируется с другими инструментами.', descEn:'Vita is a subdomain aggregation tool that fetches results from multiple passive sources simultaneously. Sources include: Shodan, Censys, crt.sh, VirusTotal, Riddler, ThreatCrowd, SecurityTrails. Merges results and removes duplicates. Very simple to use — just provide a domain. Good for quick initial subdomain discovery as part of a larger recon pipeline.' },

  { name:'Anew', url:'https://github.com/tomnomnom/anew', icon:'🆕', cat:'network', tags:['diff','dedup'],
    desc:'Anew — простой инструмент для добавления только новых строк в файл. Незаменим в пайплайнах для отслеживания изменений: запускаешь поиск поддоменов повторно, Anew автоматически показывает только новые находки. Также удаляет дубликаты. Маленький но очень полезный инструмент от tomnomnom.', descEn:'Anew is a simple but very useful tool — appends only new lines to a file without duplicates. Essential in recon pipelines where multiple tools output overlapping results. Used to maintain a \'discovered subdomains\' file and only add newly found ones. Part of the hacker toolkit by tomnomnom. Simple, fast, written in Go.' },

  { name:'Uncover', url:'https://github.com/projectdiscovery/uncover', icon:'🔓', cat:'network', tags:['shodan','censys','search'],
    desc:'Uncover — единый интерфейс для поиска хостов через несколько поисковиков: Shodan, Censys, FOFA, Hunter, Quake, Zoomeye. Позволяет использовать нативный синтаксис каждого поисковика. Агрегирует и дедуплицирует результаты. Идеален когда нужно охватить максимум хостов используя разные поисковики одновременно.', descEn:'Uncover is a tool for quickly discovering open hosts using search engines: Shodan, Censys, Fofa, Hunter, Quake. Accepts Shodan-style queries and searches across all configured engines simultaneously. Aggregates results and removes duplicates. Written in Go by ProjectDiscovery. Useful when you need maximum coverage of passive scanner data for a specific query.' },

  { name:'FOFA CLI', url:'https://github.com/LubyRuffy/gofofa', icon:'🌐', cat:'network', tags:['fofa','search'],
    desc:'FOFA — китайский поисковик по интернет-устройствам (аналог Shodan). Особенно хорош для поиска устройств в азиатском сегменте интернета. gofofa — CLI-клиент для FOFA API. Поддерживает все фильтры FOFA. Иногда находит хосты которые не индексируются Shodan или Censys.', descEn:'FOFA is a Chinese internet asset search engine, similar to Shodan. The CLI tool allows querying FOFA\'s database from the terminal. FOFA has unique data especially for Asian internet infrastructure. Supports complex queries by protocol, OS, headers, certificates. Particularly useful for finding infrastructure in China and other Asian countries not well-covered by Western scanners.' },

  { name:'ZoomEye', url:'https://github.com/knownsec/ZoomEye-python', icon:'🔭', cat:'network', tags:['zoomeye','search'],
    desc:'ZoomEye — ещё один китайский поисковик по интернет-устройствам. Python-клиент позволяет автоматизировать поиск. Имеет собственную базу данных с уникальными данными по ряду регионов. Вместе с Shodan, Censys и FOFA даёт более полное покрытие интернет-инфраструктуры.', descEn:'ZoomEye is a Chinese cybersecurity search engine for internet-connected devices and services. Similar to Shodan but with unique data coverage, especially for Chinese infrastructure. Supports queries by: OS, service, location, port, web components. Has a free tier with limited queries. The CLI allows programmatic access to data. Complements Shodan for broader global coverage.' },

  { name:'PasteHunter', url:'https://github.com/kevthehermit/PasteHunter', icon:'📋', cat:'network', tags:['paste','monitoring'],
    desc:'PasteHunter мониторит Pastebin и другие сервисы для вставки текста в поиске конфиденциальных данных. Ищет: email-адреса, пароли, ключи API, исходный код, базы данных. Отправляет уведомления при нахождении. Сохраняет результаты в Elasticsearch. Утечки через Pastebin — распространённый способ слива данных.', descEn:'PasteHunter monitors pastebin sites (Pastebin, Hastebin, GitHub Gist, etc.) for sensitive data. Automatically scrapes new pastes and checks them for: API keys, credentials, emails, IP addresses, sensitive patterns. Stores found data in Elasticsearch. Useful for monitoring if company data appears in pastes — leaked credentials are often posted publicly.' },

  { name:'Pastehunter-ng', url:'https://github.com/gojhonny/PastebinScraper', icon:'📄', cat:'network', tags:['pastebin','scraping'],
    desc:'PastebinScraper автоматически собирает все новые публикации на Pastebin в реальном времени. Использует Pastebin Scraping API. Сохраняет содержимое для последующего анализа. Позволяет мониторить утечки по ключевым словам — email домена компании, названия проектов, имена пользователей.', descEn:'Pastehunter-ng is an updated version of PasteHunter with improved architecture and additional paste sites support. Monitors multiple paste services, applies configurable detection rules for sensitive content. Features better performance and more modern storage backends. Useful for continuous monitoring of paste sites for data leakage.' },

  { name:'Recon-robot', url:'https://github.com/iamthefrogy/frogy', icon:'🤖', cat:'network', tags:['automation','discovery'],
    desc:'Frogy — простой bash-скрипт для автоматизации разведки. Использует Subfinder, Httprobe, EyeWitness. Находит живые поддомены и делает их скриншоты. Прост в использовании и не требует сложной настройки. Хорошая отправная точка для Bug Bounty.', descEn:'Recon-robot is an automated recon script that chains multiple tools together. Designed for quick initial reconnaissance — runs a predefined set of tools in sequence on a target domain. Good for standardizing the initial recon process in a team. Can be customized with different tool chains.' },

  { name:'Haktrails', url:'https://github.com/hakluke/haktrails', icon:'🔍', cat:'network', tags:['securitytrails','api'],
    desc:'Haktrails — CLI-инструмент для SecurityTrails API. SecurityTrails хранит историческую DNS-информацию и данные о поддоменах. Через API можно получить: все когда-либо использовавшиеся DNS-записи, список поддоменов, WHOIS-историю, связанные домены. Исторические DNS-данные часто раскрывают реальные IP за CDN.', descEn:'Haktrails is a command-line client for the SecurityTrails API. SecurityTrails provides: historical DNS records, current DNS data, WHOIS history, associated IP addresses and domains. Historical DNS data is crucial — it can reveal real IPs that were previously exposed before CDN adoption. One of the best sources for passive DNS intelligence.' },

  { name:'IPInfo CLI', url:'https://github.com/ipinfo/cli', icon:'ℹ️', cat:'network', tags:['ip','geolocation'],
    desc:'Официальный CLI для IPInfo API. Даёт подробную информацию об IP-адресе: геолокацию, провайдера, ASN, диапазон сети, принадлежность к хостинговым/прокси/VPN-сетям. Поддерживает пакетную обработку большого количества IP. IPInfo имеет одну из наиболее точных баз геолокации и определения типа IP.', descEn:'IPInfo CLI is the command-line tool for the IPInfo.io API. Provides: ASN, organization, ISP, country, city, timezone for any IP address. Can process large IP lists. IPInfo has one of the most accurate and up-to-date IP geolocation and ASN databases. Useful for enriching lists of IP addresses with contextual information.' },

  { name:'ASNLookup', url:'https://github.com/yassineaboukir/Asnlookup', icon:'🌐', cat:'network', tags:['asn','network'],
    desc:'ASNLookup находит все IP-диапазоны принадлежащие организации через поиск по ASN. Определяет ASN организации по её названию, затем получает все CIDR-блоки. Полезен для составления полной карты сетевой инфраструктуры крупной организации — часто у компаний есть много IP-блоков о которых не все знают.', descEn:'ASNLookup is a tool for finding all IP ranges belonging to an organization through its ASN (Autonomous System Number). Uses BGP data to map the complete IP footprint of a company. Useful for understanding the full scope of an organization\'s internet-facing infrastructure beyond what\'s visible from a domain. Often reveals IP ranges that are not directly linked to known domains.' },

  { name:'Metabigor', url:'https://github.com/j3ssie/metabigor', icon:'🧩', cat:'network', tags:['osint','network'],
    desc:'Metabigor — инструмент разведки без использования API. Получает информацию о сетях (ASN, CIDR), доменах и организациях через открытые источники: BGP.he.net, ARIN/RIPE WHOIS, crt.sh. Написан на Go. Особенно полезен для картирования IP-инфраструктуры без необходимости в платных API.', descEn:'Metabigor is an intelligence tool that uses multiple passive sources to gather information about targets. Can query: BGP.he.net for ASN, Shodan, Certificate Transparency, various threat intel feeds. Focuses on IP and network-level intelligence. Written in Go. Useful for network-level OSINT and understanding an organization\'s IP infrastructure.' },

  { name:'Dnscewl', url:'https://github.com/codingo/DNSCewl', icon:'📝', cat:'network', tags:['wordlist','dns'],
    desc:'DNSCewl генерирует кастомные словари для DNS-брутфорса на основе уже найденных поддоменов. Анализирует паттерны в существующих поддоменах и генерирует похожие варианты. Кастомные словари специфичные для целевой организации значительно эффективнее универсальных при поиске поддоменов.', descEn:'Dnscewl generates DNS wordlists for subdomain bruteforcing based on data extracted from a target domain. Creates custom wordlists using patterns found in the target\'s existing subdomains. Better than generic wordlists for targeted bruteforcing — uses naming conventions actually used by the target. Effective complement to passive subdomain discovery.' },

  { name:'Hakip2host', url:'https://github.com/hakluke/hakip2host', icon:'🔄', cat:'network', tags:['reverse-dns','ip'],
    desc:'Hakip2host выполняет reverse DNS lookup для диапазона IP-адресов. Принимает CIDR-блок и возвращает все hostname для каждого IP. Позволяет найти виртуальные хосты на IP-адресах организации. Часто одни IP-адреса хостят несколько сайтов — reverse DNS помогает их обнаружить.', descEn:'Hakip2host is a tool for reverse DNS lookup on IP ranges. Takes a list of IPs and returns associated hostnames. Useful for discovering all domains hosted on a given IP or in an IP range. Often reveals additional targets in the same hosting environment. Written in Go as part of the hacker toolkit. Works very fast on large IP lists.' },

  { name:'Virtual Host Scanner', url:'https://github.com/codingo/VHostScan', icon:'🏠', cat:'network', tags:['vhost','discovery'],
    desc:'VHostScan обнаруживает виртуальные хосты на веб-серверах. Брутфорсит заголовок Host через заданный список и сравнивает ответы с базовым. Поддерживает обнаружение уникальных ответов даже когда сервер возвращает 200 для всего. Находит скрытые сайты которые не обнаруживаются через DNS-разведку.', descEn:'Virtual Host Scanner discovers virtual hosts on a web server. Sends HTTP requests with different Host headers to find sites that share an IP but respond differently. Can discover internal applications, staging environments, and development sites not listed in DNS. Often reveals targets with weaker security than the main production site.' },

  { name:'Pentest-tools CLI', url:'https://github.com/gwen001/pentest-tools', icon:'🛠️', cat:'network', tags:['tools','collection'],
    desc:'Коллекция скриптов для разведки и пентеста. Включает: поиск поддоменов, фаззинг параметров, поиск в Shodan, анализ JS-файлов, поиск секретов. Каждый скрипт решает конкретную задачу. Хорошая коллекция для ежедневного использования.', descEn:'Pentest-tools CLI is the command-line interface for the Pentest-Tools.com platform. Provides access to various online scanning tools: subdomain finder, port scanner, web scanner, vulnerability scanner. Results are stored in the cloud and can be accessed later. Useful for quick scans without setting up local tools. Requires a paid account for full functionality.' },

  { name:'RobotScraper', url:'https://github.com/robotshell/robotScraper', icon:'🤖', cat:'network', tags:['robots','sitemap'],
    desc:'RobotScraper анализирует файлы robots.txt и sitemap.xml для обнаружения скрытого контента. robots.txt часто намеренно скрывает интересные пути — и именно поэтому они интересны. Автоматически собирает все запрещённые пути и передаёт их для дальнейшего анализа.', descEn:'RobotScraper processes robots.txt files from a list of domains. Collects all disallowed paths across many sites — these often contain interesting hidden content that site owners don\'t want indexed. Can reveal admin panels, internal APIs, sensitive directories. Simple but often surprisingly effective for discovering interesting targets.' },

  { name:'IntelX CLI', url:'https://github.com/intelxio/go-intelx', icon:'🔍', cat:'network', tags:['intelx','leaks'],
    desc:'Intelligence X — сервис для поиска в утечках, Darkweb, Pastebin, WhoisX и других источниках. Go-клиент позволяет автоматизировать поиск. Особенно ценен для поиска утёкших данных по email, домену или другим идентификаторам. Индексирует данные которые обычные поисковики не находят.', descEn:'Intelligence X CLI is the command-line tool for the IntelX search engine. IntelX indexes leaked databases, paste sites, dark web pages, old internet snapshots. Searches by selector: email, domain, IP, Bitcoin address, etc. Unique in its coverage of historical and darkweb data. Requires a paid API key for meaningful results. Excellent source for breach and leak investigation.' },

  { name:'OnionSearch', url:'https://github.com/megadose/OnionSearch', icon:'🧅', cat:'network', tags:['tor','darkweb'],
    desc:'OnionSearch автоматизирует поиск в нескольких Tor-поисковиках одновременно: Ahmia, Torch, DuckDuckGo .onion, и других. Агрегирует результаты и сохраняет в CSV. Позволяет искать упоминания организаций, email и других данных в даркнете без необходимости вручную проверять каждый поисковик.', descEn:'OnionSearch is a tool for searching Tor onion sites using multiple search engines: Ahmia, Torch, Haystak, etc. Can search by keyword across all supported search engines simultaneously. Useful for OSINT investigations that need to cover dark web sources. Does not require a running Tor browser — queries search engines directly.' },

  { name:'Darkdump', url:'https://github.com/josh0xA/darkdump', icon:'🌑', cat:'network', tags:['darkweb','search'],
    desc:'Darkdump — инструмент для поиска в даркнете через Ahmia (поисковик по Tor). Позволяет искать .onion-сайты по ключевым словам прямо из командной строки без необходимости запускать Tor-браузер. Полезен для мониторинга упоминания организации или данных в даркнете.', descEn:'Darkdump is a Python tool for searching the dark web through the Ahmia search engine. Searches Tor hidden services for a given keyword. Simple to use — just provide a keyword and it returns relevant .onion results. Useful for checking if company data, credentials or other sensitive information appears on dark web sites.' },

  { name:'Recon-dog', url:'https://github.com/s0md3v/ReconDog', icon:'🐕', cat:'network', tags:['recon','wizard'],
    desc:'ReconDog — инструмент разведки с интерактивным меню. Объединяет несколько инструментов и API в единый интерфейс: Whois, GeoIP, DNS, Port scanning, Banner grabbing, поиск в Shodan. Не требует запоминания команд. Хорошо подходит для начинающих в OSINT.', descEn:'Recon-dog is an OSINT tool that collects information from various sources: Clearbit, Bing, Twitter, Hunter, FullContact. Focuses on people and email intelligence. Simple CLI with an interactive menu. Good for quick lookups when you need data from multiple APIs without writing your own scripts. Written in Python.' },

  { name:'Raccoon', url:'https://github.com/evyatarmeged/Raccoon', icon:'🦝', cat:'network', tags:['recon','automated'],
    desc:'Raccoon — высокопроизводительный инструмент OSINT для разведки. Выполняет: DNS-разведку, WHOIS, TLS-анализ, WAF-обнаружение, поиск поддоменов, сканирование директорий. Работает асинхронно для максимальной скорости. Формирует подробный текстовый отчёт. Хорош для быстрого первичного аудита домена.', descEn:'Raccoon is an offensive security and recon tool. Performs: DNS recon, WHOIS, TLS/SSL analysis, port scanning, web technology detection, WAF identification, subdomain enumeration, directory bruteforcing. All-in-one approach. Written in Python with async support for speed. Good choice for standardized initial recon that covers all common areas.' },

  { name:'Striker', url:'https://github.com/s0md3v/Striker', icon:'⚡', cat:'network', tags:['recon','offensive'],
    desc:'Striker — инструмент атакующей разведки. Определяет технологии сайта, ищет CMS, проверяет SSL, извлекает заголовки безопасности, проверяет WHOIS. Имеет красивый цветной вывод в терминале. Прост в использовании, не требует API-ключей. Хорошо подходит для быстрого профилирования цели.', descEn:'Striker is an offensive information and vulnerability scanner. Performs comprehensive recon: Cloudflare bypass attempts, DNS enumeration, port scanning, web technology detection, CMS detection, directory scanning, SQL injection testing, XSS testing, SSRF testing. All-in-one tool for initial web target assessment. Written in Python.' },

  { name:'RED HAWK', url:'https://github.com/Tuhinshubhra/RED_HAWK', icon:'🦅', cat:'network', tags:['recon','all-in-one'],
    desc:'RED HAWK — PHP-инструмент для сбора информации. Определяет IP, геолокацию, CMS, записи DNS, Cloudflare, роботов, ссылки. Имеет простой интерактивный интерфейс. Работает через веб-браузер (PHP-сервер) или CLI. Включает сканер портов и проверку заголовков безопасности.', descEn:'RED HAWK is an information gathering and vulnerability scanning tool. Performs: WHOIS, geolocation, subdomain scan, port scan, CMS detection, Cloudflare detection, robots.txt analysis, Whappalizer fingerprinting. Written in PHP. Particularly popular in the educational security community. Good introductory tool that demonstrates various recon concepts.' },

  { name:'Osrframework', url:'https://github.com/i3visio/osrframework', icon:'🔬', cat:'people', tags:['username','email','osint'],
    desc:'OSRFramework — набор инструментов для разведки по идентификаторам. Включает: usufy (поиск username), mailfy (проверка email), searchfy (поиск через поисковики), domainfy (проверка доменов), phonefy (проверка телефонов). Все инструменты объединены общим интерфейсом. Результаты сохраняются в CSV, JSON, XLS.', descEn:'OSRFramework is an OSINT framework specialized in user profiling. The main tool — usufy — searches for usernames across hundreds of platforms. Also includes: mailfy (email checks), searchfy (search engines), domainfy (domain finder), phonefy (phone search). Has a web interface and CLI. Part of academic OSINT research, well-documented.' },

  { name:'NExfil', url:'https://github.com/thewhiteh4t/nexfil', icon:'🌐', cat:'social', tags:['username','osint'],
    desc:'NExfil проверяет username на 350+ платформах. Имеет систему верификации для уменьшения ложных срабатываний. Выводит результаты в цветном виде. Сохраняет найденные профили в текстовый файл. Хорошо дополняет Sherlock — иногда находит профили которые Sherlock пропускает.', descEn:'NExfil is a username search tool across social networks. Checks 350+ platforms and shows where accounts exist. Features multithreading, color-coded output, JSON export. Similar to Sherlock but with different platform coverage. Good for use in combination with other username search tools to maximize coverage.' },

  { name:'Maltego Machines', url:'https://github.com/MaltegoTech/maltego-stix2', icon:'🕸️', cat:'network', tags:['maltego','stix'],
    desc:'Расширение для Maltego добавляющее поддержку формата STIX2 (Structured Threat Intelligence eXpression). Позволяет импортировать и экспортировать данные угроз в стандартном формате. Полезно для обмена данными разведки угроз между организациями и инструментами.', descEn:'Maltego Machines are automated workflows in Maltego that chain multiple transforms together. Allow creating fully automated investigation pipelines: starting from an email, automatically discover all associated domains, people, social accounts. Can be shared and reused. Significantly accelerate repetitive investigation tasks.' },

  { name:'Instaloader', url:'https://github.com/instaloader/instaloader', icon:'📸', cat:'social', tags:['instagram','download'],
    desc:'Instaloader загружает профили, посты, истории, хайлайты из Instagram. Не требует аккаунта для публичных профилей. Сохраняет метаданные (дата, лайки, комментарии) в JSON. Скачивает IGTV и Reels. Позволяет скачивать профили по подписчикам/подпискам. Полезен для архивирования и анализа активности Instagram-аккаунтов.', descEn:'Instaloader is a tool for downloading Instagram content and metadata. Can download: profile photos, stories, reels, IGTV, tagged posts. Also collects metadata: follower/following lists, post timestamps, location tags (if public). Can track changes to a profile over time. Works without an API key for public profiles. Written in Python.' },

  { name:'Osintgram', url:'https://github.com/Datalux/Osintgram', icon:'📷', cat:'social', tags:['instagram','osint'],
    desc:'Osintgram — инструмент OSINT специально для Instagram. Получает: email и телефон (если указаны), список подписчиков и подписок, геолоцированные посты, теги на фотографиях, комментарии, историю публикаций. Требует Instagram-аккаунт. Предоставляет интерактивный интерфейс с несколькими командами для анализа профиля.', descEn:'Osintgram is an Instagram OSINT tool. For a given public account, collects: all media, comments, people tagged in posts, hashtags used, locations visited, captions. Builds a profile based on public activity. Has an interactive CLI with various commands for different data types. Useful for deep investigation of a target\'s Instagram presence.' },

  { name:'Toutatis', url:'https://github.com/megadose/toutatis', icon:'📱', cat:'social', tags:['instagram','info'],
    desc:'Toutatis извлекает информацию из аккаунтов Instagram: email, телефон (частично маскированные), аватар, ID, количество публикаций и подписчиков. Использует Instagram Graph API. Требует действующий токен доступа. Особенно полезен для получения частично маскированных контактных данных которые отображаются при определённых условиях.', descEn:'Toutatis is a tool for extracting information from Instagram accounts. Requires an access token but provides richer data. Can extract: phone numbers (if linked), email addresses, follower details. Reveals information that may not be visible in the regular Instagram interface. Name is a reference to the French Gaulish character known for cunning.' },

  { name:'Twayback Machine', url:'https://github.com/humandecoded/twayback', icon:'⏪', cat:'social', tags:['twitter','archive'],
    desc:'Twayback позволяет просматривать удалённые твиты через Wayback Machine. Принимает username и скачивает архивные версии профиля. Находит твиты которые пользователь удалил. Удалённые твиты часто содержат интересную информацию которую человек хотел скрыть.', descEn:'Twayback Machine is a tool for viewing deleted tweets via the Wayback Machine and other archives. Searches the internet archive for cached versions of Twitter profiles and extracts deleted tweets. Useful for finding deleted tweets in investigations. Complements standard Twitter OSINT by recovering content the user attempted to delete.' },

  { name:'Stweet', url:'https://github.com/sc0tfree/updog', icon:'🐦', cat:'social', tags:['twitter','scraping'],
    desc:'Инструмент для скрапинга Twitter без API-ключа. Обходит ограничения Twitter через веб-интерфейс. Собирает твиты по пользователю, хэштегу или ключевым словам. Поддерживает фильтрацию по дате. Особенно полезен после ужесточения Twitter API в 2023 году.', descEn:'Stweet is an advanced Twitter scraping tool that bypasses API limitations. Can scrape tweets, users, likes, comments by keyword, hashtag, user, date. Supports multiple output formats: JSON, CSV, SQLite. Works without API keys. Good alternative to Twint with more active maintenance. Useful for large-scale Twitter data collection.' },

  { name:'Facebook OSINT', url:'https://github.com/sqren/fb-messenger-bot', icon:'👤', cat:'social', tags:['facebook','osint'],
    desc:'Инструменты для сбора публичной информации из Facebook. Позволяет извлекать данные из публичных профилей, групп, страниц. Находит публичные публикации, события, фотографии. Facebook всё больше ограничивает доступ к данным, но публичные профили всё ещё содержат много полезной информации.', descEn:'Facebook OSINT tools and techniques for intelligence gathering from Facebook. Includes: search by phone number, email, profile ID. Facebook\'s Graph API (legacy) enabled extensive data collection. Current tools use various workarounds to gather public information about profiles, groups and pages. Useful for people-focused investigations.' },

  { name:'LinkedIn2Username', url:'https://github.com/initstring/linkedin2username', icon:'💼', cat:'social', tags:['linkedin','username'],
    desc:'LinkedIn2Username генерирует потенциальные корпоративные имена пользователей на основе данных сотрудников из LinkedIn. По списку реальных имён сотрудников создаёт возможные логины в разных форматах: firstname.lastname, f.lastname, firstname.l. Полезно для подготовки списков при тестировании аутентификации.', descEn:'LinkedIn2Username is a tool for generating potential usernames from LinkedIn profile data. Searches LinkedIn for employees of a target company and generates various username format combinations: firstname.lastname, f.lastname, firstnamelastname, etc. The generated list can be used for password spraying attacks against company services like Office 365, VPN, email.' },

  { name:'ScrapedIn', url:'https://github.com/dchrastil/ScrapedIn', icon:'💼', cat:'social', tags:['linkedin','scraping'],
    desc:'ScrapedIn собирает данные о сотрудниках компании из LinkedIn без официального API. Находит: имена, должности, отделы, часто email (через форматы корпоративных адресов). Принимает название компании, возвращает список сотрудников. Полезен для разведки по персоналу организации.', descEn:'ScrapedIn is a LinkedIn scraper for collecting employee information. Extracts: names, job titles, email patterns, profile URLs. Helps build a comprehensive employee list for an organization. Used for social engineering preparation and username list generation. Note: LinkedIn actively blocks scraping, so tools frequently need updates.' },

  { name:'Sherloq', url:'https://github.com/GuidoBartoli/sherloq', icon:'🔍', cat:'image', tags:['forensics','image'],
    desc:'Sherloq — набор инструментов для форензики изображений. Анализирует фотографии на предмет: манипуляций, метаданных, источника камеры, артефактов сжатия, следов редактирования. Помогает определить подлинность изображения и найти следы постобработки. Незаменим при анализе предположительно поддельных фотографий.', descEn:'Sherloq is an image forensics analysis tool. Provides a comprehensive set of analysis techniques: metadata extraction, error level analysis (ELA) for detecting edited areas, noise analysis, frequency analysis, copy-move forgery detection. Used to verify whether an image has been manipulated. Essential for investigators working with potentially doctored images.' },

  { name:'ImgSeek', url:'https://github.com/racitup/imgseek', icon:'🖼️', cat:'image', tags:['reverse-image','search'],
    desc:'Инструмент для обратного поиска изображений через несколько поисковиков одновременно. Автоматизирует отправку изображения в Google Images, Yandex Images, Bing Images и другие. Агрегирует результаты. Позволяет быстро найти источник и другие места размещения изображения без ручной проверки каждого поисковика.', descEn:'ImgSeek is a tool for visual similarity search and image matching. Finds visually similar images using perceptual hashing. Can identify the same image in different resolutions or with minor modifications. Useful for tracking image reuse, finding original sources of cropped or watermarked images. Complements TinEye for image investigation.' },

  { name:'ImageMagick OSINT', url:'https://github.com/ImageMagick/ImageMagick', icon:'🎨', cat:'image', tags:['image','processing'],
    desc:'ImageMagick — мощный инструмент для обработки и анализа изображений. С точки зрения OSINT используется для: извлечения метаданных, анализа ICC-профилей, конвертации форматов, выявления скрытой информации. Поддерживает более 200 форматов файлов. Незаменим в автоматизированных пайплайнах обработки изображений.', descEn:'ImageMagick for OSINT involves using this powerful image processing suite for intelligence work. Can extract all metadata, convert between formats, analyze image properties, batch process large collections. The identify command provides detailed technical metadata. Useful for processing large collections of images in automated pipelines.' },

  { name:'Stegdetect', url:'https://github.com/abeluck/stegdetect', icon:'🔎', cat:'image', tags:['steganography','detect'],
    desc:'Stegdetect обнаруживает стеганографическое содержимое в JPEG-изображениях. Умеет определять методы: JSteg, JPHide, Invisible Secrets, OutGuess, F5 и другие. Статистический анализ позволяет выявить скрытое содержимое даже без знания пароля. Используется в цифровой форензике и разведке.', descEn:'Stegdetect is a tool for detecting steganography in JPEG images. Checks if images contain hidden data using known steganographic algorithms: JSteg, JPHide, OutGuess, Invisible Secrets, F5. Steganography — hiding information inside other files — is used by threat actors for covert communication. Useful in digital forensics and OSINT investigations of suspicious images.' },

  { name:'Pillow OSINT', url:'https://github.com/python-pillow/Pillow', icon:'🖼️', cat:'image', tags:['python','image'],
    desc:'Python Imaging Library (Pillow) используется в OSINT для программного анализа изображений: извлечение метаданных, определение формата, анализ цветовых каналов. Основа многих OSINT-скриптов для работы с изображениями. Позволяет строить автоматизированные пайплайны обработки изображений.', descEn:'Pillow (PIL) for OSINT involves using Python\'s image processing library for intelligence gathering from images. Can extract metadata, analyze pixel patterns, perform histogram analysis, detect modifications. Used for automated batch processing of images in OSINT pipelines. Provides programmatic access to image data for custom analysis scripts.' },

  { name:'Pywhat', url:'https://github.com/bee-san/pyWhat', icon:'❓', cat:'people', tags:['identify','regex'],
    desc:'PyWhat определяет что представляет собой неизвестная строка данных. Распознаёт: хэши (MD5, SHA, bcrypt), IP-адреса, email, URL, телефоны, координаты, номера кредитных карт, крипто-адреса, JWT-токены, ключи API, Base64 и многое другое. Полезен при анализе утечек когда нужно быстро классифицировать найденные данные.', descEn:'Pywhat is a tool that identifies what a piece of text or data is. Paste an unknown string and it will identify: regex patterns it matches, type of data (IP, phone, email, credit card, hash, etc.). Useful for quickly categorizing unknown data found during OSINT. Based on a large library of regular expressions for different data types.' },

  { name:'Name2Subdomain', url:'https://github.com/cramppet/subgen', icon:'🔤', cat:'network', tags:['wordlist','company'],
    desc:'Subgen генерирует словари для перебора поддоменов на основе названия компании. Создаёт комбинации из названия, распространённых префиксов (api, dev, staging, admin) и суффиксов. Кастомный словарь специфичный для конкретной организации эффективнее универсального при поиске поддоменов.', descEn:'Name2Subdomain generates potential subdomain names from a company name or keyword. Creates various combinations and variations commonly used in corporate infrastructure. Useful for building targeted wordlists for subdomain bruteforcing. More effective than generic wordlists for finding organization-specific infrastructure patterns.' },

  { name:'JSFScan', url:'https://github.com/KathanP19/JSFScan.sh', icon:'📜', cat:'network', tags:['javascript','recon'],
    desc:'JSFScan автоматизирует анализ JavaScript-файлов. Извлекает: эндпоинты API, секреты, URL, переменные. Использует несколько инструментов под капотом: LinkFinder, SecretFinder, getjswords. Принимает список хостов, автоматически находит все JS-файлы и анализирует их. Отличный инструмент для автоматизации JS-разведки.', descEn:'JSFScan is a tool for finding sensitive information in JavaScript files. Automatically discovers all JS files on a site, downloads and analyzes them looking for: API endpoints, secret keys, credentials, internal URLs, interesting comments. Written in Bash but uses multiple underlying tools. Efficient for automated JS file analysis in web app assessments.' },

  { name:'Gf', url:'https://github.com/tomnomnom/gf', icon:'🔍', cat:'network', tags:['grep','patterns'],
    desc:'Gf (Grep-Fu) — обёртка над grep с набором паттернов для OSINT и Bug Bounty. Содержит готовые паттерны для поиска: потенциальных SSRF, XSS, SQLi, Open Redirect, AWS ключей и других уязвимостей в URL и коде. Применяется к выводу других инструментов для быстрой фильтрации интересных находок.', descEn:'Gf (grep Faster) is a wrapper around grep that uses predefined patterns for security research. Has built-in patterns for finding: AWS keys, base64 strings, interesting strings, IDOR-prone parameters, potential SQL injection, XSS, SSRF, redirects in URL lists. Used in combination with Gau, Waybackurls to find interesting URLs with vulnerable parameters.' },

  { name:'Qsreplace', url:'https://github.com/tomnomnom/qsreplace', icon:'🔄', cat:'network', tags:['urls','replace'],
    desc:'Qsreplace заменяет значения параметров в URL на заданную строку. Незаменим в пайплайнах: берёшь список URL из Gau, передаёшь через qsreplace для подстановки payload, получаешь готовые URL для тестирования. Инструмент для передачи данных между инструментами в пайплайнах.', descEn:'Qsreplace replaces URL parameter values with a given string. Used in pipelines where you want to test all parameters of a large URL list: replaces all parameter values with a test payload, then pipes to a scanning tool. Written in Go. Simple but essential in modern bug bounty workflows for mass parameter testing.' },

  { name:'Interactsh', url:'https://github.com/projectdiscovery/interactsh', icon:'📡', cat:'network', tags:['oob','blind'],
    desc:'Interactsh — сервис для обнаружения out-of-band взаимодействий. Генерирует уникальные поддомены для обнаружения слепых уязвимостей: SSRF, XXE, blind SQLi, Log4Shell. Когда уязвимый сервер делает запрос к сгенерированному домену — это фиксируется. Незаменим для нахождения уязвимостей без видимого эффекта в ответе.', descEn:'Interactsh is an open-source out-of-band interaction server. Generates unique URLs and DNS names that log any interaction. Used to detect SSRF, blind XSS, blind SQLi, XXE and other injection vulnerabilities where the response doesn\'t directly indicate success. ProjectDiscovery\'s replacement for Burp Collaborator. Has both cloud and self-hosted versions.' },

  { name:'Dalfox', url:'https://github.com/hahwul/dalfox', icon:'🦊', cat:'network', tags:['xss','scanner'],
    desc:'Dalfox — быстрый и мощный XSS-сканер написанный на Go. Поддерживает несколько режимов: одиночный URL, список URL, stdin. Имеет встроенный анализатор параметров и умные payload. Может работать с headless-браузером для проверки DOM XSS. Поддерживает Interactsh для обнаружения blind XSS. Один из лучших XSS-сканеров.', descEn:'Dalfox is a powerful XSS scanner. Uses a parameter analysis and filter detection approach to craft effective payloads. Has a mode for scanning pipelines (accepts stdin), supports blind XSS with callback URLs, DOM XSS detection. Written in Go, very fast. One of the best automated XSS scanners available, often used in bug bounty programs.' },

  { name:'Cariddi', url:'https://github.com/edoardottt/cariddi', icon:'🦀', cat:'network', tags:['crawler','secrets'],
    desc:'Cariddi — краулер написанный на Go, специализированный на поиске чувствительных данных. Сканирует веб-сайт и ищет: секреты в коде, интересные эндпоинты, файлы конфигурации, расширения файлов определённых типов. Работает быстро благодаря конкурентности Go. Хорошая альтернатива Photon.', descEn:'Cariddi is a web crawler and endpoints extractor. Crawls a list of websites and discovers: URLs, endpoints, parameters, files, forms, secrets (API keys, tokens), errors. Written in Go, supports concurrency. Can crawl both regular and JavaScript-heavy sites. Good for automated discovery of interesting content across many targets.' },

  { name:'Waymore', url:'https://github.com/xnl-h4ck3r/waymore', icon:'⏰', cat:'network', tags:['urls','wayback'],
    desc:'Waymore собирает URL из Wayback Machine, Common Crawl, Alien Vault OTX, URLScan. Имеет фильтрацию по расширениям файлов, статус-кодам, датам. Может скачивать содержимое найденных URL из Wayback Machine. Один из наиболее полных инструментов для сбора исторических URL.', descEn:'Waymore is a tool for finding more URLs from various archive sources. Queries: Wayback Machine, Common Crawl, VirusTotal, AlienVault OTX, URLScan. Automatically downloads archived responses for interesting URLs. More comprehensive than Gau or Waybackurls alone. The combination of sources often reveals many more historical endpoints.' },

  { name:'X8', url:'https://github.com/Sh1Yo/x8', icon:'8️⃣', cat:'network', tags:['parameters','hidden'],
    desc:'X8 находит скрытые параметры в веб-приложениях. Использует бинарный поиск для эффективного перебора большого количества параметров. Поддерживает GET, POST, JSON, XML. Умеет работать с параметрами которые не меняют видимый ответ (изменения в размере или времени ответа). Один из лучших инструментов для открытия скрытой функциональности.', descEn:'X8 is a hidden parameter discovery tool. Uses a unique approach to find hidden parameters by analyzing response differences with high efficiency. Can discover parameters that don\'t appear in page source but affect the application\'s behavior. Written in Rust, extremely fast. Effective for finding hidden debug parameters and undocumented API features.' },

  { name:'IpGeoLocation', url:'https://github.com/maldevel/IPGeoLocation', icon:'📍', cat:'geo', tags:['ip','geolocation'],
    desc:'IPGeoLocation определяет геолокацию IP-адресов через несколько провайдеров. Поддерживает: ip-api.com, ipstack.com, ipwhois.io. Показывает страну, регион, город, провайдера, ASN, координаты. Поддерживает пакетную обработку. Простой и удобный инструмент для быстрого определения географии IP.', descEn:'IpGeoLocation is a Python tool for determining IP address geolocation. Uses multiple free geolocation databases and APIs. Provides: country, region, city, ISP, ASN, timezone. Can process large lists of IPs. Supports proxy use. Useful for enriching IP lists in OSINT investigations with geographic and network context.' },

  { name:'EXIF GPS Extractor', url:'https://github.com/lclarkmichalek/exifgps', icon:'🗺️', cat:'geo', tags:['exif','gps'],
    desc:'Специализированный инструмент для извлечения GPS-координат из EXIF-данных фотографий. Автоматически конвертирует координаты из формата EXIF в десятичные градусы. Поддерживает массовую обработку директорий с фотографиями. Выводит координаты в формате подходящем для Google Maps.', descEn:'EXIF GPS Extractor is a tool for batch extraction of GPS coordinates from image metadata. Processes entire folders of photos and extracts location data. Can output coordinates in various formats and plot them on a map. Useful for investigations involving large collections of photos — quickly identifies which images contain location data.' },

  { name:'Geo-recon', url:'https://github.com/radioactivetobi/geo-recon', icon:'🌍', cat:'geo', tags:['geolocation','ip'],
    desc:'Geo-recon — инструмент для геолокационной разведки. Определяет местоположение по IP-адресу или домену, строит карту нахождения серверов. Интегрируется с несколькими провайдерами геолокации для повышения точности. Полезен для понимания где физически находится инфраструктура организации.', descEn:'Geo-recon is a tool for geographical reconnaissance from open sources. Collects location-related information from: social media geotags, EXIF data, IP geolocation, check-ins, map posts. Helps build a movement profile of a target based on publicly available location data.' },

  { name:'Mapcidr', url:'https://github.com/projectdiscovery/mapcidr', icon:'🗺️', cat:'network', tags:['cidr','ip'],
    desc:'Mapcidr выполняет операции с CIDR-блоками: расширение в список IP, проверку принадлежности IP к подсети, агрегацию IP-адресов в CIDR. Полезен при работе с диапазонами IP организаций — позволяет быстро обработать большие сетевые блоки и подготовить списки для сканирования.', descEn:'Mapcidr is a utility for performing various operations on IP CIDR ranges. Supports: listing all IPs in a range, aggregating multiple ranges, finding the CIDR for a list of IPs. Written in Go. Essential in large-scale network recon workflows where you need to generate IP lists from CIDR ranges or organize IP data efficiently.' },

  { name:'Hakrevdns', url:'https://github.com/hakluke/hakrevdns', icon:'🔄', cat:'network', tags:['reverse-dns','lookup'],
    desc:'Hakrevdns выполняет массовый обратный DNS-поиск. Принимает список IP-адресов или CIDR-блок, возвращает hostname для каждого IP. Написан на Go, работает параллельно. Позволяет быстро обработать большие диапазоны IP и найти виртуальные хосты.', descEn:'Hakrevdns is a tool for reverse DNS lookup at scale. Takes a list of IP addresses and performs PTR record lookups to find associated hostnames. Written in Go for high speed. Can process entire IP ranges. Useful for finding additional attack surface from a list of discovered IPs — hostname discovery often reveals new domain names.' },

  { name:'Ipscout', url:'https://github.com/bitsadmin/ipscout', icon:'🔍', cat:'network', tags:['ip','intelligence'],
    desc:'IPScout собирает разведывательные данные об IP-адресе из множества источников: WHOIS, геолокация, PTR-записи, Shodan, VirusTotal, AbuseIPDB, Greynoise. Агрегирует данные в единый отчёт. Быстрый способ получить всестороннее представление об IP-адресе.', descEn:'Ipscout is a tool for IP address investigation that queries multiple sources: IPInfo, Shodan, AbuseIPDB, GreyNoise, VirusTotal. Provides a comprehensive view of an IP address\'s reputation and characteristics. Useful for threat intelligence and investigation — quickly aggregates all available data about a suspicious IP.' },

  { name:'Omnibus', url:'https://github.com/InQuest/omnibus', icon:'🚌', cat:'network', tags:['osint','framework'],
    desc:'Omnibus — OSINT-фреймворк для анализа индикаторов компрометации (IoC). Принимает IP, домены, email, hash. Запрашивает данные из Shodan, VirusTotal, PassiveTotal, Censys, HaveIBeenPwned. Строит граф связей. Хранит результаты в MongoDB. Хорошо подходит для анализа угроз и расследований инцидентов.', descEn:'Omnibus is an OSINT tool for investigating various indicators: IPs, domains, emails, usernames. Queries multiple threat intelligence and OSINT sources. Stores investigation history and builds relationships between indicators. Has an interactive shell. Suitable for structured intelligence investigations where tracking relationships between indicators is important.' },

  { name:'Ioc-finder', url:'https://github.com/fhightower/ioc-finder', icon:'🔍', cat:'network', tags:['ioc','parse'],
    desc:'IOC-finder парсит и извлекает индикаторы компрометации из текста. Находит: IP-адреса, домены, URL, email, хэши MD5/SHA, CVE, YARA-правила, Bitcoin-адреса. Написан на Python, прост в интеграции. Полезен для автоматического извлечения IoC из отчётов об угрозах или текстовых дампов.', descEn:'IOC-finder is a Python library for parsing indicators of compromise (IoCs) from text. Extracts: IP addresses, URLs, domains, email addresses, hashes, CVEs, YARA rules. Useful for processing threat intelligence reports, security advisories, malware analysis reports. Can process large amounts of unstructured text to extract actionable indicators.' },

  { name:'MISP Tools', url:'https://github.com/MISP/MISP', icon:'🔴', cat:'network', tags:['threat-intel','sharing'],
    desc:'MISP (Malware Information Sharing Platform) — платформа для обмена данными угроз. Хранит и обрабатывает индикаторы компрометации, TTP, кампании. Поддерживает множество форматов импорта/экспорта. Используется государственными CERT, корпоративными SOC и исследователями безопасности по всему миру.', descEn:'MISP (Malware Information Sharing Platform) command-line tools for interacting with MISP instances. MISP is an open-source threat intelligence platform. CLI tools enable automated IoC import/export, event creation, attribute searches. Used in SOC environments for automating threat intelligence workflows and sharing indicators between organizations.' },

  { name:'Yeti', url:'https://github.com/yeti-platform/yeti', icon:'🏔️', cat:'network', tags:['threat-intel','platform'],
    desc:'Yeti — платформа для структурирования и хранения данных угроз. Организует IoC, TTP, акторов угроз в связанную базу знаний. Автоматически обогащает данные из внешних источников. Имеет API для интеграции с другими инструментами. Альтернатива MISP с акцентом на граф связей между объектами.', descEn:'Yeti is an open-source threat intelligence platform. Helps organize and correlate intelligence: IoCs, TTPs, threat actors, malware families, campaigns. Provides a knowledge base about threats linked to observable indicators. Has a REST API for integration with other tools. Alternative to MISP with a different architecture and focus on knowledge organization.' },

  { name:'Maltego-trx', url:'https://github.com/MaltegoTech/maltego-trx', icon:'🕸️', cat:'network', tags:['maltego','transform'],
    desc:'Maltego TRX — Python-библиотека для создания кастомных трансформаций Maltego. Позволяет интегрировать любой источник данных в Maltego. Используется для создания корпоративных трансформаций специфичных для конкретной организации или добавления новых источников в граф разведки.', descEn:'Maltego TRX (Transform Extension) is the Python framework for creating custom Maltego transforms. Allows building your own data sources and integrations for Maltego. Used to create company-specific transforms that query internal databases or proprietary APIs. Enables Maltego to become a hub connecting all available intelligence sources.' },

  { name:'DataSurgeon', url:'https://github.com/Drew-Alleman/DataSurgeon', icon:'⚕️', cat:'network', tags:['extract','sensitive'],
    desc:'DataSurgeon извлекает чувствительную информацию из больших объёмов данных. Находит: email, IP, URL, телефоны, ключи SSH, Base64, хэши, токены, номера кредитных карт. Работает с файлами, директориями, stdin. Написан на Rust, очень быстр. Полезен при анализе дампов данных и логов.', descEn:'DataSurgeon is a tool for extracting sensitive data from various file formats and text. Extracts: emails, IP addresses, URLs, credit card numbers, social security numbers, API keys, usernames, phone numbers. Supports many input formats. Useful for quickly scanning large data dumps or leaked files for sensitive information of interest.' },

  { name:'BurpSuite Community', url:'https://github.com/PortSwigger/burp-extensions-montoya-api', icon:'🔴', cat:'network', tags:['proxy','web'],
    desc:'Burp Suite — стандарт в тестировании безопасности веб-приложений. Community версия бесплатна. Проксирует трафик браузера для анализа и модификации. Имеет сканер, Repeater, Intruder. Богатая экосистема расширений через BApp Store. Незаменим для глубокого анализа веб-приложений.', descEn:'Burp Suite Community is the free version of the industry-standard web security testing platform. Includes: intercepting proxy, repeater for manual request modification, basic scanner, intruder for fuzzing. The essential tool for manual web application security testing. Community version lacks automated scanning and some advanced features, but the core workflow tools are fully functional.' },

  { name:'OWASP ZAP', url:'https://github.com/zaproxy/zaproxy', icon:'⚡', cat:'network', tags:['web','scanner'],
    desc:'OWASP ZAP (Zed Attack Proxy) — бесплатная альтернатива Burp Suite. Активно разрабатывается OWASP. Имеет активный и пассивный сканеры уязвимостей, автоматизированное сканирование, API для интеграции в CI/CD. Отличается хорошей автоматизацией — можно запускать через командную строку и Docker.', descEn:'OWASP ZAP (Zed Attack Proxy) is a free, open-source web security testing tool. Full-featured alternative to Burp Suite: intercepting proxy, automated scanner, fuzzer, spider, passive scanning. Has both desktop GUI and headless/daemon modes for CI/CD integration. One of the most actively maintained free web security tools. Excellent documentation and active community.' },

  { name:'Caido', url:'https://github.com/caido/caido', icon:'🌊', cat:'network', tags:['proxy','modern'],
    desc:'Caido — современная альтернатива Burp Suite написанная на Rust и TypeScript. Имеет современный веб-интерфейс, высокую производительность, базу данных всех запросов с мощным поиском, систему плагинов. Активно разрабатывается и быстро приобретает популярность в Bug Bounty сообществе.', descEn:'Caido is a modern web security testing tool, an alternative to Burp Suite. Written in Rust for high performance. Has a clean, modern interface. Supports: intercepting proxy, HTTP history, repeater, replaying requests, basic fuzzing. Has a cloud-based collaboration feature. Growing in popularity in the bug bounty community as a faster alternative to Burp.' },

  { name:'Wifite', url:'https://github.com/derv82/wifite2', icon:'📶', cat:'network', tags:['wifi','audit'],
    desc:'Wifite автоматизирует аудит безопасности Wi-Fi сетей. Поддерживает атаки на WEP, WPA/WPA2, WPS. Автоматически выбирает лучшую атаку для каждой сети. Интегрируется с инструментами Aircrack-ng. С точки зрения OSINT полезен для анализа беспроводной инфраструктуры объекта при физическом разведывании.', descEn:'Wifite is an automated wireless network security testing tool for Linux. Supports various attack methods: WPS PIN brute force, WEP cracking, WPA/WPA2 handshake capture. Automatically selects the best attack for each found network. Uses standard tools under the hood: Aircrack-ng, Reaver, Pyrit. Designed for Wi-Fi security auditing with minimal user interaction.' },

  { name:'Bettercap', url:'https://github.com/bettercap/bettercap', icon:'🌐', cat:'network', tags:['mitm','network'],
    desc:'Bettercap — продвинутый инструмент для MITM-атак и сетевой разведки. Поддерживает: ARP-spoofing, DNS-spoofing, перехват трафика, анализ BLE устройств, перехват Wi-Fi. Имеет веб-интерфейс и REST API. С точки зрения разведки позволяет пассивно собирать данные о сетевой активности при физическом присутствии.', descEn:'Bettercap is a powerful, extensible framework for network attacks and monitoring. Supports: ARP spoofing and MITM, DNS spoofing, WiFi attacks, Bluetooth LE recon, packet sniffing, credential harvesting, BLE device tracking. Has an interactive console and REST API. Swiss-army knife for network security testing. Successor to Ettercap with more modern architecture.' },

  { name:'Kismet', url:'https://github.com/kismetwireless/kismet', icon:'📡', cat:'network', tags:['wifi','wireless'],
    desc:'Kismet — пассивный беспроводной сниффер и детектор устройств. Обнаруживает Wi-Fi сети, Bluetooth устройства, устройства 802.15.4. Работает полностью пассивно — не отправляет пакеты. Записывает все обнаруженные устройства и данные. Полезен для картирования беспроводной инфраструктуры и обнаружения скрытых сетей.', descEn:'Kismet is a wireless network detector, sniffer and intrusion detection system. Passively detects wireless networks and devices without sending any traffic. Captures 802.11 management frames. Supports multiple capture sources. Logs to various formats: pcap, SQLite. Useful for passive wireless network OSINT — identifies all nearby networks and devices without active interaction.' },

  { name:'OpenWifi', url:'https://github.com/seemoo-lab/openwifipass', icon:'🔑', cat:'network', tags:['wifi','passive'],
    desc:'Инструмент для изучения протокола обмена Wi-Fi паролями в Apple устройствах. Позволяет понять как устройства Apple обмениваются учётными данными Wi-Fi. Полезен для исследования безопасности беспроводных сетей и протоколов Apple.', descEn:'OpenWifi tools for analyzing and working with WiFi networks. Includes utilities for: network discovery, signal strength mapping, client tracking, protocol analysis. Useful for physical security assessments and wireless network OSINT in the vicinity of a target location.' },

  { name:'BlueScan', url:'https://github.com/EONRaider/BLEScan', icon:'🔵', cat:'network', tags:['bluetooth','scan'],
    desc:'BLEScan сканирует Bluetooth Low Energy (BLE) устройства. Обнаруживает устройства, читает рекламные пакеты, UUID сервисов. Позволяет картировать BLE-устройства в радиусе действия: IoT устройства, трекеры, смарт-замки, медицинские устройства. Полезен при физической разведке объекта.', descEn:'BlueScan is a Bluetooth scanning and OSINT tool. Discovers nearby Bluetooth and BLE devices, collects: device names, MAC addresses, device types, service profiles. Can be used for physical proximity OSINT — identifying devices present in a specific location. Useful for tracking and identifying devices in physical security investigations.' },

  { name:'Routersploit', url:'https://github.com/threat9/routersploit', icon:'📡', cat:'network', tags:['router','exploit'],
    desc:'RouterSploit — фреймворк для тестирования безопасности роутеров и встроенных устройств. Содержит эксплойты для популярных роутеров Cisco, D-Link, TP-Link, Netgear. Имеет сканеры для проверки уязвимостей по умолчанию. С точки зрения OSINT полезен для анализа найденных через Shodan уязвимых роутеров.', descEn:'RouterSploit is an exploitation framework for embedded devices. Contains modules for: scanning routers for default credentials, finding vulnerabilities in specific router models, exploiting confirmed vulnerabilities. Supports many router brands: Cisco, Netgear, Linksys, D-Link. Used in network security audits to identify vulnerable network equipment.' },

  { name:'Weeman', url:'https://github.com/evait-security/weeman', icon:'🎣', cat:'network', tags:['phishing','http'],
    desc:'Weeman — HTTP-сервер для создания фишинговых страниц для проверки осведомлённости о безопасности. Клонирует существующие сайты. Используется в тестах на проникновение для проверки восприимчивости сотрудников к фишингу. Требуется разрешение от организации.', descEn:'Weeman is a phishing website creation tool. Creates convincing copies of popular websites for security awareness testing and phishing simulations. Can clone any website and set up a local server with the cloned site. Used in authorized social engineering assessments to test employee security awareness.' },

  { name:'SET', url:'https://github.com/trustedsec/social-engineer-toolkit', icon:'🎭', cat:'people', tags:['social-engineering','phishing'],
    desc:'Social-Engineer Toolkit (SET) — фреймворк для тестирования социальной инженерии. Автоматизирует создание фишинговых кампаний, клонирование сайтов, создание вредоносных вложений (в образовательных целях). Используется с разрешения организации для оценки осведомлённости сотрудников о безопасности.', descEn:'SET (Social Engineer Toolkit) is a comprehensive framework for social engineering attacks. Supports: phishing email creation, website cloning for credential harvesting, USB payloads, malicious PDF generation. One of the most complete tools for authorized social engineering assessments. Has been the standard tool in this area for many years. Uses Metasploit for payload generation.' },

  { name:'GoPhish', url:'https://github.com/gophish/gophish', icon:'🎣', cat:'people', tags:['phishing','campaign'],
    desc:'GoPhish — платформа для проведения фишинговых кампаний с целью обучения сотрудников. Управляет кампаниями через веб-интерфейс. Отслеживает: открытие писем, переходы по ссылкам, ввод данных. Формирует подробную статистику. Используется только с разрешения организации для проверки готовности к социальной инженерии.', descEn:'GoPhish is an open-source phishing framework. Enables creating and tracking phishing campaigns: send emails, track opens, track clicks, capture credentials. Has a clean web interface. Used by security teams for authorized phishing simulations and security awareness training. Supports multiple SMTP providers and email templates. Written in Go.' },

  { name:'ATSCAN', url:'https://github.com/AlisamTechnology/ATSCAN', icon:'🔭', cat:'network', tags:['scanner','dork'],
    desc:'ATSCAN — сканер для поиска уязвимостей через Google Dorks. Автоматически генерирует запросы к поисковикам для поиска уязвимых сайтов по паттернам SQL инъекций, XSS и других уязвимостей. Включает модули для проверки найденных целей. Требует ответственного использования.', descEn:'ATSCAN is a mass exploitation scanner. Takes a list of URLs and tests them for multiple vulnerabilities: SQL injection, XSS, LFI, RFI, RCE. Uses dork-based target discovery. Written in Perl. Used in authorized vulnerability assessments for quickly testing large numbers of targets for common vulnerabilities.' },

  { name:'Snoop', url:'https://github.com/snooppr/snoop', icon:'👃', cat:'social', tags:['username','russia'],
    desc:'Snoop — инструмент для поиска аккаунтов по никнейму с акцентом на русскоязычные платформы. Поддерживает более 3000 сайтов включая ВКонтакте, Одноклассники, Mail.ru, российские форумы. Особенно эффективен для поиска людей в СНГ-сегменте интернета где другие инструменты имеют слабое покрытие.', descEn:'Snoop is an OSINT tool for searching usernames on social networks, focused on Russian and CIS platforms. Supports 2000+ sites including VK, OK, Telegram and many regional platforms not covered by Sherlock. Has a Russian-language interface. The go-to tool for investigations involving Russian-speaking targets — covers many regional platforms that Western tools miss.' },

  { name:'Ignorant', url:'https://github.com/megadose/ignorant', icon:'📵', cat:'people', tags:['phone','accounts'],
    desc:'Ignorant — аналог Holehe но для номеров телефонов. Проверяет на каких сервисах зарегистрирован номер через форму восстановления пароля. Поддерживает: Instagram, Snapchat, Twitter, Amazon и другие сервисы которые позволяют регистрацию по телефону. Незаметен для пользователя — не отправляет SMS.', descEn:'Ignorant is a tool for checking if a phone number is registered on various services. Uses the phone registration/recovery forms to determine account existence. Supports: Snapchat, Instagram, Amazon, and other platforms. Similar to Holehe but for phone numbers. Useful for phone-based OSINT — finding what services a person uses with their phone number.' },

  { name:'OsintUI', url:'https://github.com/bellingcat/auto-archiver', icon:'📦', cat:'network', tags:['archive','evidence'],
    desc:'Auto-Archiver от Bellingcat автоматически архивирует контент из социальных сетей для использования в качестве доказательств. Поддерживает Twitter/X, Facebook, YouTube, TikTok, Telegram. Сохраняет скриншоты, метаданные, хэши файлов. Критически важен для сохранения цифровых доказательств которые могут быть удалены.', descEn:'OsintUI is a graphical user interface for running OSINT tools. Provides a unified GUI for launching and managing various OSINT tools without using the command line. Makes OSINT tools more accessible to users less comfortable with CLI. Useful for teams where not everyone has deep technical background.' },

  { name:'yt-dlp', url:'https://github.com/yt-dlp/yt-dlp', icon:'📹', cat:'social', tags:['video','download'],
    desc:'yt-dlp — мощный инструмент для скачивания видео с YouTube и 1000+ других сайтов. Поддерживает метаданные, субтитры, thumbnail. Позволяет скачивать приватные видео (при наличии доступа), целые плейлисты и каналы. С точки зрения OSINT незаменим для сохранения видеодоказательств перед их возможным удалением.', descEn:'yt-dlp is a powerful tool for downloading video and audio from thousands of websites. Supports: YouTube, Vimeo, Twitter, Instagram, Facebook, TikTok and many others. Can download entire channels, playlists, livestreams. Extracts metadata: title, description, upload date, view count, comments. Essential for OSINT investigations involving video content preservation.' },

  { name:'Gallery-dl', url:'https://github.com/mikf/gallery-dl', icon:'🖼️', cat:'social', tags:['images','download'],
    desc:'Gallery-dl скачивает изображения и галереи с 200+ сайтов: Instagram, Twitter, Reddit, Flickr, DeviantArt, Pixiv и других. Сохраняет метаданные. Поддерживает аутентификацию, ограничение по дате, фильтры. Полезен для сохранения фотографий из социальных сетей для анализа метаданных и геолокации.', descEn:'Gallery-dl is an image collection downloader from various sites: Imgur, Flickr, DeviantArt, ArtStation, Reddit, Pixiv and hundreds more. Downloads images along with metadata. Useful for building image evidence collections in OSINT investigations. Supports authentication for sites requiring login to access full content.' },

  { name:'Waybackpy', url:'https://github.com/akamhy/waybackpy', icon:'⏳', cat:'network', tags:['wayback','api'],
    desc:'Waybackpy — Python-библиотека для работы с Wayback Machine API. Сохраняет страницы в архив, ищет по диапазону дат, получает список всех архивных версий. Позволяет в скриптах автоматически проверять историю изменений сайтов и извлекать старые версии страниц.', descEn:'Waybackpy is a Python library and CLI for interacting with the Internet Archive Wayback Machine API. Can: save URLs, retrieve archived versions, get availability and history. Useful for preserving web pages as evidence, finding old versions of content, and checking historical content programmatically in automated pipelines.' },

  { name:'ArchiveBox', url:'https://github.com/ArchiveBox/ArchiveBox', icon:'📦', cat:'network', tags:['archive','self-hosted'],
    desc:'ArchiveBox — самостоятельно размещаемый интернет-архив. Сохраняет веб-страницы в нескольких форматах: HTML, PDF, скриншот, WARC, git. Имеет веб-интерфейс для управления и поиска по архиву. Идеален для долгосрочного сохранения доказательств и создания локальных архивов важных страниц.', descEn:'ArchiveBox is a self-hosted web archiving solution. Can archive: URLs, bookmarks, RSS feeds, browser history. Saves: HTML, screenshots, PDFs, WARC, media files. Has a web interface for browsing archives. Useful for building your own independent web archive for investigation purposes — ensures evidence is preserved even if original pages disappear.' },

  { name:'SingleFile', url:'https://github.com/gildas-lormeau/SingleFile', icon:'📄', cat:'network', tags:['archive','browser'],
    desc:'SingleFile — расширение браузера и CLI для сохранения полных веб-страниц в один HTML-файл. Включает все ресурсы (CSS, изображения, шрифты) в один файл через Data URI. Идеален для сохранения доказательств в судебных делах — страница сохраняется точно так как выглядит включая динамический контент.', descEn:'SingleFile is a browser extension and CLI tool for saving complete web pages as single HTML files. Captures the full visual state of a page including styles, fonts and images. CLI version works headlessly for automated archiving. Creates perfect visual replicas of pages as evidence. Useful for preserving web content exactly as it appeared at a specific moment.' },

  { name:'Monolith', url:'https://github.com/Y2Z/monolith', icon:'🗿', cat:'network', tags:['archive','single-file'],
    desc:'Monolith сохраняет веб-страницы в один HTML-файл. Написан на Rust. CLI-инструмент без GUI. Включает CSS, JS, изображения через Data URI. Работает быстро. Подходит для автоматизации сохранения доказательств в скриптах.', descEn:'Monolith is a CLI tool for saving complete web pages as self-contained HTML files. Fetches all resources (CSS, images, scripts) and embeds them into a single file. Written in Rust, fast and reliable. Ideal for archiving web pages as evidence — the saved file is completely self-contained and renders accurately even without internet access.' },

  { name:'Selenium', url:'https://github.com/SeleniumHQ/selenium', icon:'🤖', cat:'network', tags:['browser','automation'],
    desc:'Selenium — фреймворк для автоматизации браузеров. В OSINT используется для: обхода JavaScript-приложений которые не поддаются статическому анализу, автоматического входа на сайты, скрапинга контента за аутентификацией, обхода CAPTCHA через ручное решение. Поддерживает Chrome, Firefox, Edge.', descEn:'Selenium for OSINT enables automated interaction with websites that require JavaScript execution or user interaction. Can: navigate pages, click buttons, fill forms, take screenshots, extract dynamic content. Used when standard scrapers fail on complex web applications. Python bindings make it easy to write custom OSINT automation scripts.' },

  { name:'Playwright', url:'https://github.com/microsoft/playwright', icon:'🎭', cat:'network', tags:['browser','automation'],
    desc:'Playwright — современная альтернатива Selenium от Microsoft. Поддерживает Chrome, Firefox, WebKit. Более надёжен и быстр. Имеет встроенную поддержку перехвата сетевого трафика, скриншотов, PDF. В OSINT используется для автоматизации сбора данных с динамических сайтов требующих JavaScript.', descEn:'Playwright is a modern browser automation framework from Microsoft. Supports Chromium, Firefox and WebKit. Features headless mode, intercepting network requests, generating PDFs, taking screenshots. Faster and more reliable than Selenium for many tasks. Used for automating OSINT collection from complex JavaScript-heavy web applications.' },

  { name:'Puppeteer', url:'https://github.com/puppeteer/puppeteer', icon:'🎪', cat:'network', tags:['browser','headless'],
    desc:'Puppeteer — Node.js библиотека для управления headless Chrome от Google. В OSINT используется для автоматизации сбора данных, скриншотов, рендеринга JavaScript-приложений. Особенно полезен для автоматизации взаимодействия с SPA (Single Page Applications) которые трудно скрапить обычными методами.', descEn:'Puppeteer is a Node.js library for controlling Chrome/Chromium via the DevTools Protocol. Used for: web scraping of JS-heavy sites, taking screenshots, generating PDFs, automating interactions. Has direct access to browser internals. Popular for automating data collection from modern web applications. Easy to write scripts for complex automation tasks.' },

  { name:'Scrapy', url:'https://github.com/scrapy/scrapy', icon:'🕷️', cat:'network', tags:['scraping','framework'],
    desc:'Scrapy — мощный фреймворк для веб-скрапинга на Python. Поддерживает параллельный обход, ротацию прокси, обработку cookie, следование пагинации. Имеет богатую экосистему middleware и расширений. Идеален для массового структурированного сбора данных с веб-сайтов.', descEn:'Scrapy is a Python web scraping and crawling framework. Provides a complete framework for: crawling websites, extracting structured data, handling pagination, managing cookies and sessions. Supports various output formats: JSON, CSV, XML, databases. Has built-in support for handling JavaScript via Splash integration. Ideal for large-scale structured data collection.' },

  { name:'BeautifulSoup', url:'https://github.com/waylan/beautifulsoup', icon:'🍲', cat:'network', tags:['html','parse'],
    desc:'BeautifulSoup — Python-библиотека для парсинга HTML и XML. Основа большинства OSINT-скриптов для извлечения данных из веб-страниц. Позволяет легко находить и извлекать нужные элементы по тегам, классам, ID и CSS-селекторам. Простой API делает её идеальным выбором для быстрого написания парсеров.', descEn:'BeautifulSoup is a Python library for parsing HTML and XML. The go-to tool for data extraction from HTML documents. Simple API for navigating, searching and modifying the parse tree. Works with various parsers: html.parser, lxml, html5lib. Usually used with Requests library: fetch page with Requests, parse with BeautifulSoup. Essential for building custom OSINT scrapers.' },

  { name:'Requests-HTML', url:'https://github.com/psf/requests-html', icon:'🌐', cat:'network', tags:['html','javascript'],
    desc:'Requests-HTML — Python-библиотека для запросов HTTP с поддержкой рендеринга JavaScript. Объединяет Requests для HTTP-запросов и pyppeteer для рендеринга JS. Позволяет парсить динамические сайты без отдельной настройки Selenium. Удобный API для OSINT-скриптов.', descEn:'Requests-HTML is a Python library combining Requests and BeautifulSoup with optional JavaScript rendering via pyppeteer. Provides a Pythonic API for web scraping that handles both static and dynamic content. Easier to use than separate Requests + BeautifulSoup for many tasks. Good for building simple OSINT scrapers that need occasional JS rendering.' },

  { name:'Httpie', url:'https://github.com/httpie/cli', icon:'🌐', cat:'network', tags:['http','client'],
    desc:'HTTPie — человекочитаемый HTTP-клиент для командной строки. Удобная альтернатива curl с красивым цветным выводом, поддержкой JSON, сессий, загрузки файлов. Полезен для быстрого тестирования API, проверки заголовков, отправки кастомных запросов при разведке веб-приложений.', descEn:'HTTPie is a user-friendly command-line HTTP client. Designed to make HTTP requests readable and comfortable for humans. Features: colorized output, JSON support, session persistence, form data, file upload, streaming. Great alternative to curl for API testing and manual HTTP investigation. Makes it easy to craft and inspect HTTP requests during OSINT.' },

  { name:'JWT-Tool', url:'https://github.com/ticarpi/jwt_tool', icon:'🔑', cat:'network', tags:['jwt','tokens'],
    desc:'JWT Tool — инструмент для тестирования JSON Web Tokens. Декодирует JWT, проверяет на уязвимости (none algorithm, RS256->HS256, alg confusion), брутфорсит слабые секреты. С точки зрения OSINT полезен для анализа JWT-токенов найденных в исходном коде или трафике при разведке API.', descEn:'JWT-Tool is a toolkit for testing JSON Web Tokens. Decodes JWTs, tests for vulnerabilities: none algorithm attack, algorithm confusion (RS256→HS256), secret brute forcing, key injection. Checks signature validation. JWT vulnerabilities can lead to authentication bypass and privilege escalation. Essential when a web application uses JWT-based authentication.' },

  { name:'Trident', url:'https://github.com/praetorian-inc/trident', icon:'🔱', cat:'people', tags:['credentials','spray'],
    desc:'Trident — платформа для автоматизированного тестирования учётных данных. Управляет распределёнными атаками подбора паролей через облачные функции. Поддерживает Office365, G Suite и другие корпоративные сервисы. Требует явного разрешения от тестируемой организации.', descEn:'Trident is an automated password spraying system. Supports cloud services: Office 365, G Suite and others. Implements smart delays to avoid account lockouts. Can distribute spraying across multiple IP addresses. Used in authorized red team assessments to test password policies and detect weak passwords across a corporate environment.' },

  { name:'Credmaster', url:'https://github.com/knavesec/CredMaster', icon:'🔐', cat:'people', tags:['credentials','cloud'],
    desc:'CredMaster автоматизирует Password Spraying через AWS Lambda — каждый запрос приходит с разного IP, что обходит блокировку по IP. Поддерживает Office365, OWA, G Suite, Okta. Используется только с разрешения организации для проверки политик паролей и механизмов блокировки.', descEn:'CredMaster is a password spraying tool that uses AWS Lambda for anonymous IP rotation. Each authentication attempt comes from a different IP — bypasses IP-based rate limiting. Supports: OWA, EWS, O365, ADFS, Okta, and others. Very effective against environments that rely only on IP-based brute force protection.' },

  { name:'Spray', url:'https://github.com/Greenwolf/Spray', icon:'💨', cat:'people', tags:['password','spray'],
    desc:'Spray — инструмент для password spraying против ADFS и Office365. Автоматически соблюдает паузы между попытками чтобы не спровоцировать блокировку. Поддерживает несколько форматов имён пользователей. Используется с разрешения организации для проверки слабых корпоративных паролей.', descEn:'Spray is an Active Directory password spraying tool. Tests a single password against many usernames with smart delays to avoid account lockouts. Supports various protocols: LDAP, SMB, OWA. Written in Go for high performance. Used in authorized assessments to find accounts with weak or default passwords in corporate Active Directory environments.' },

  { name:'Ruler', url:'https://github.com/sensepost/ruler', icon:'📏', cat:'network', tags:['exchange','office365'],
    desc:'Ruler взаимодействует с Exchange-серверами через MAPI/HTTP. Умеет: проверять учётные данные, перечислять информацию о почтовом ящике, создавать правила. Поддерживает autodiscover для автоматического нахождения Exchange. Полезен для тестирования безопасности корпоративной почтовой инфраструктуры.', descEn:'Ruler is a tool for attacking Microsoft Exchange and Outlook via MAPI/HTTP and RPC/HTTP. Can create Outlook rules and forms for code execution without phishing emails. Also supports: GAL (Global Address List) extraction for username enumeration, password spraying. Used in red team engagements targeting Exchange infrastructure.' },

  { name:'Msf Auxiliary', url:'https://github.com/rapid7/metasploit-framework', icon:'💀', cat:'network', tags:['framework','auxiliary'],
    desc:'Metasploit Framework содержит сотни модулей разведки (auxiliary). Умеет: сканировать сервисы, перечислять пользователей SMTP, проверять FTP, перечислять SMB-ресурсы, собирать баннеры. Auxiliary-модули используются для разведки без активной эксплуатации. Стандарт в профессиональном пентестинге.', descEn:'Metasploit Auxiliary modules perform various tasks without delivering payloads: scanning, service enumeration, fuzzing, credential bruteforcing, information gathering. The auxiliary/scanner category alone has hundreds of modules for detecting specific services, versions, configurations. Essential part of the Metasploit ecosystem for recon and enumeration.' },

  { name:'Enum4linux', url:'https://github.com/CiscoCXSecurity/enum4linux', icon:'🐧', cat:'network', tags:['smb','enumeration'],
    desc:'Enum4linux перечисляет информацию с Windows и Samba систем через SMB. Извлекает: список пользователей, группы, ресурсы, политики паролей, данные о домене. Основан на инструментах Samba. Незаменим для разведки Windows-сетей — часто раскрывает критическую информацию о внутренней структуре домена.', descEn:'Enum4linux is a tool for enumerating information from Windows and Samba systems via SMB. Collects: OS information, domain info, users, groups, shares, password policy. Written in Perl, a wrapper around smbclient, rpcclient and other tools. Classic choice for SMB enumeration in network penetration testing. Often the first SMB tool run against a Windows target.' },

  { name:'Enum4linux-ng', url:'https://github.com/cddmp/enum4linux-ng', icon:'🐧', cat:'network', tags:['smb','modern'],
    desc:'Enum4linux-ng — современная переработка enum4linux. Написан на Python3, активно поддерживается. Добавляет: LDAP-перечисление, поддержку NTLM аутентификации, JSON/YAML вывод, более надёжную обработку ошибок. Рекомендуется как замена оригинального enum4linux.', descEn:'Enum4linux-ng is a rewrite of Enum4linux in Python with improvements. Better output formatting, JSON and YAML export, improved error handling. Adds support for LDAP and MSRPC enumeration. More reliable than the original on modern systems. Compatible with the same SMB enumeration tasks but with a cleaner codebase and better maintenance.' },

  { name:'Crackmapexec', url:'https://github.com/byt3bl33d3r/CrackMapExec', icon:'🗺️', cat:'network', tags:['smb','active-directory'],
    desc:'CrackMapExec — многофункциональный инструмент для аудита сетей Windows/Active Directory. Проверяет учётные данные через SMB, WinRM, MSSQL, LDAP. Перечисляет пользователей, группы, политики, ресурсы. Запускает команды на удалённых системах. Стандарт в пентесте Windows-сред. Требует разрешения.', descEn:'CrackMapExec (CME) is a Swiss-army knife for Windows/Active Directory pentesting. Can: check credentials against many hosts simultaneously, execute commands, dump secrets (SAM, NTDS, lsass), enumerate shares, users, groups, policies. Supports SMB, WinRM, MSSQL, LDAP protocols. Standard tool in AD penetration testing workflows.' },

  { name:'Impacket', url:'https://github.com/fortra/impacket', icon:'📦', cat:'network', tags:['windows','protocols'],
    desc:'Impacket — коллекция Python-классов для работы с сетевыми протоколами Windows: SMB, MSRPC, NTLM, Kerberos, LDAP, MSSQL. Основа многих инструментов для пентеста Windows. Содержит готовые скрипты: GetUserSPNs, secretsdump, psexec, wmiexec. Незаменим для разведки и тестирования Windows-инфраструктуры.', descEn:'Impacket is a collection of Python classes for working with network protocols. Implements: SMB, MSRPC, Kerberos, LDAP, DCERPC and many other Windows protocols. Foundation for many other Windows attack tools. Used directly to: perform pass-the-hash, pass-the-ticket, enumerate AD objects, interact with MSRPC services. Essential for Windows network exploitation.' },

  { name:'BloodHound', url:'https://github.com/BloodHoundAD/BloodHound', icon:'🐕', cat:'network', tags:['active-directory','graph'],
    desc:'BloodHound визуализирует пути атаки в Active Directory. Собирает данные о пользователях, группах, компьютерах, GPO, правах. Строит граф и находит кратчайшие пути к Domain Admin. Революционизировал анализ безопасности AD. Используется для понимания реального риска в сложных AD-средах.', descEn:'BloodHound is a tool for analyzing Active Directory attack paths. Uses graph theory to find the shortest path to domain administrator rights. Data collection via SharpHound ingestor. Visualizes relationships: user memberships, ACL permissions, session data, Kerberos delegation. Revolutionized AD pentesting — finds privilege escalation paths that would take days to find manually.' },

  { name:'ADExplorer', url:'https://github.com/c3c/ADExplorerSnapshot.py', icon:'🌳', cat:'network', tags:['active-directory','ldap'],
    desc:'ADExplorerSnapshot.py конвертирует снимки Active Directory из ADExplorer в формат для BloodHound. Позволяет оффлайн-анализ AD без постоянного подключения к домену. Полезен для анализа снимков AD которые были сделаны при тестировании.', descEn:'ADExplorer is a Microsoft Sysinternals tool for browsing and exploring Active Directory. Allows: navigating the AD tree, viewing all attributes of objects, creating offline snapshots of AD for later analysis. Snapshots can be analyzed with other tools (BloodHound via ADExplorerSnapshot.py). Useful for understanding AD structure and auditing permissions.' },

  { name:'LDAPDomainDump', url:'https://github.com/dirkjanm/ldapdomaindump', icon:'🌲', cat:'network', tags:['ldap','ad'],
    desc:'LDAPDomainDump перечисляет информацию домена через LDAP. Собирает и сохраняет в читаемом формате: пользователей, группы, компьютеры, GPO, политики. Создаёт HTML и JSON отчёты. Не требует прав администратора домена — работает с правами обычного пользователя домена.', descEn:'LDAPDomainDump is a Python tool for dumping Active Directory data via LDAP. Requires valid domain credentials. Collects: users, groups, computers, GPOs, trusts, password policy. Outputs data in JSON, CSV and HTML formats. HTML reports are especially convenient — provides a browsable view of the entire AD structure. Useful in authorized AD audits.' },

  { name:'Kerbrute', url:'https://github.com/ropnop/kerbrute', icon:'🔑', cat:'network', tags:['kerberos','bruteforce'],
    desc:'Kerbrute использует протокол Kerberos для быстрого перебора пользователей и паролей домена без риска блокировки (AS-REQ не логируется по умолчанию). Умеет перечислять действительных пользователей домена, spray паролей, брутфорс. Написан на Go, работает быстро.', descEn:'Kerbrute is a tool for Kerberos username enumeration and password bruteforcing. Can enumerate valid usernames without logging failed attempts (ASREP pre-auth disabled). Supports password spraying and bruteforcing. Written in Go, very fast. Particularly useful for initial AD enumeration when you have network access but no credentials yet.' },

  { name:'Hashcat', url:'https://github.com/hashcat/hashcat', icon:'#️⃣', cat:'network', tags:['hash','crack'],
    desc:'Hashcat — мощнейший инструмент для взлома хэшей с поддержкой GPU. Поддерживает более 300 алгоритмов хэширования. Режимы атаки: словарь, брутфорс, маска, комбинация, rule-based. В OSINT используется для восстановления паролей из утечек баз данных для понимания паттернов паролей организации.', descEn:'Hashcat is the fastest password cracker available. Supports GPU acceleration and hundreds of hash types: MD5, SHA-1/256/512, NTLM, bcrypt, WPA, and more. Attack modes: dictionary, bruteforce, combination, rule-based, mask. Uses GPU for massive parallelism — a modern GPU can crack billions of hashes per second. Essential for offline password cracking after hash extraction.' },

  { name:'John the Ripper', url:'https://github.com/openwall/john', icon:'🔨', cat:'network', tags:['password','crack'],
    desc:'John the Ripper — классический инструмент для взлома паролей. Поддерживает сотни форматов хэшей. Автоматически определяет тип хэша. Имеет встроенные словари и правила мутации. Умеет взламывать защищённые паролем файлы: ZIP, PDF, Office, SSH-ключи. Незаменим для восстановления забытых паролей.', descEn:'John the Ripper (JtR) is a classic password cracker. Supports many hash types and automatically detects hash format. Modes: wordlist, incremental bruteforce, single crack, markov. Has jumbo version with many additional hash formats. More CPU-focused than Hashcat but easier to set up. Good for quick hash cracking when GPU isn\'t available.' },

  { name:'Cupp', url:'https://github.com/Mebus/cupp', icon:'📝', cat:'people', tags:['wordlist','profiling'],
    desc:'CUPP (Common User Passwords Profiler) генерирует персонализированные словари для взлома паролей. Задаёт вопросы об имени, дате рождения, питомцах, партнёре, ключевых словах. Генерирует все возможные комбинации с leetspeak и цифровыми суффиксами. Персонализированные словари намного эффективнее универсальных.', descEn:'CUPP (Common User Passwords Profiler) generates personalized wordlists for password cracking. Asks questions about the target: name, birthday, partner, children, pets, company, keywords. Creates a targeted wordlist based on this information. People often use personal information in passwords. More effective than generic wordlists for targeted password attacks.' },

  { name:'Mentalist', url:'https://github.com/sc0tfree/mentalist', icon:'🧠', cat:'people', tags:['wordlist','custom'],
    desc:'Mentalist — инструмент с GUI для создания кастомных словарей. Позволяет визуально строить правила генерации паролей: базовые слова + преобразования + суффиксы. Сохраняет конфигурацию для повторного использования. Делает создание кастомных словарей более наглядным по сравнению с командной строкой.', descEn:'Mentalist is a graphical wordlist generator. Allows creating complex wordlist generation rules using a visual interface. Supports various mutations: capitalization, number suffixes, character substitutions (l33tspeak), special characters. Can generate wordlists too large to store — outputs directly to Hashcat. Easier to use than Hashcat rules for non-experts.' },

  { name:'Proxychains', url:'https://github.com/haad/proxychains', icon:'⛓️', cat:'network', tags:['proxy','anonymity'],
    desc:'Proxychains перенаправляет TCP-соединения через цепочку прокси: SOCKS4, SOCKS5, HTTP. Позволяет использовать Tor с любым инструментом командной строки. Поддерживает случайный порядок прокси для лучшей анонимности. Незаменим когда нужно провести разведку анонимно или из другой геолокации.', descEn:'ProxyChains is a Linux tool that forces TCP connections from any application through SOCKS4/5 or HTTP proxies. Supports proxy chaining through multiple servers. Used to: anonymize traffic, bypass network restrictions, route tools through a SOCKS proxy (e.g., via SSH tunnel). Makes tools that don\'t natively support proxies work through them.' },

  { name:'Tor', url:'https://github.com/torproject/tor', icon:'🧅', cat:'network', tags:['anonymity','tor'],
    desc:'Tor — сеть для анонимной коммуникации. Маршрутизирует трафик через несколько узлов шифруя каждый слой. Позволяет анонимно посещать сайты и получать доступ к .onion-ресурсам. В OSINT используется для анонимного сбора данных когда важно не раскрыть IP разведчика цели.', descEn:'Tor (The Onion Router) is the standard tool for anonymous internet access. Routes traffic through a series of volunteer-operated relays. Enables access to .onion hidden services (dark web). Used in OSINT for anonymizing investigation activities. The Tor Browser is the easiest way to use it. CLI tools (proxychains + tor daemon) route any tool through Tor.' },

  { name:'Proxify', url:'https://github.com/projectdiscovery/proxify', icon:'🔀', cat:'network', tags:['proxy','intercept'],
    desc:'Proxify — HTTP/HTTPS прокси от ProjectDiscovery для перехвата и изменения трафика. Поддерживает upstream прокси (через Tor или другие прокси), запись трафика в файлы, фильтрацию запросов. Удобен для отладки и анализа сетевого трафика инструментов разведки.', descEn:'Proxify is a Swiss-army-knife proxy for HTTP/HTTPS traffic. Features: full traffic logging, replaying and modifying requests, upstream proxy chaining, MITM for SSL inspection. Used for intercepting and analyzing traffic from applications that don\'t support proxy configuration. Written in Go. Useful for understanding what data applications are sending.' },

  { name:'Mubeng', url:'https://github.com/kitabisa/mubeng', icon:'🔄', cat:'network', tags:['proxy','rotation'],
    desc:'Mubeng — ротатор прокси для скрытия реального IP при массовых запросах. Принимает список прокси и автоматически ротирует их для каждого запроса. Поддерживает SOCKS4, SOCKS5, HTTP. Встроенный сервер для использования как upstream прокси в других инструментах.', descEn:'Mubeng is an IP rotator and proxy checker. Rotates through a list of proxies for each request — effectively randomizes the source IP for scanning or OSINT activities. Supports SOCKS5 and HTTP proxies. Checks proxy health. Written in Go. Used to bypass IP-based rate limiting and avoid detection during large-scale automated reconnaissance.' },

  { name:'Tor-router', url:'https://github.com/troosh/tor-router', icon:'🧅', cat:'network', tags:['tor','proxy'],
    desc:'Tor Router перенаправляет весь системный трафик через Tor. Прозрачный прокси — не нужно настраивать каждое приложение отдельно. Автоматически меняет цепочку Tor для смены IP. Полезен когда нужно весь трафик инструментов разведки направить через Tor.', descEn:'Tor-router routes all system traffic through the Tor network automatically. Unlike ProxyChains, doesn\'t require configuring each application separately. Makes all connections anonymous without modifying individual tools. Useful for anonymizing entire investigation sessions. Has trade-offs: Tor is slower than direct connections and some sites block Tor exit nodes.' },

  { name:'Spiderfoot HX', url:'https://github.com/smicallef/spiderfoot', icon:'🕷️', cat:'network', tags:['enterprise','osint'],
    desc:'SpiderFoot — полнофункциональный OSINT-фреймворк с более чем 200 модулями. Поддерживает REST API для интеграции. В enterprise-версии: командная работа, расширенная визуализация, интеграция с SIEM. Бесплатная версия полностью функциональна для индивидуального использования.', descEn:'SpiderFoot HX is the commercial cloud-hosted version of SpiderFoot. Provides: managed scanning without local setup, team collaboration features, scheduled scans, report sharing, API access. Includes premium data sources not available in the free version. Suitable for security teams that need scalable OSINT automation without infrastructure management.' },

  { name:'Recon-everything', url:'https://github.com/vavkamil/awesome-bugbounty-tools', icon:'📚', cat:'network', tags:['collection','bugbounty'],
    desc:'Обширная коллекция инструментов для Bug Bounty с описаниями и ссылками. Организована по категориям: разведка, сканирование, эксплуатация, пост-эксплуатация. Охватывает как популярные так и малоизвестные инструменты. Отличный справочник для Bug Bounty-охотников.', descEn:'Recon-everything is an automated recon script that chains together multiple popular tools. Runs a comprehensive scan using: Amass, Subfinder, httpx, Nuclei, and other tools in a logical sequence. Good for teams that want a standardized recon process without manually chaining tools. Configurable to skip certain stages.' },

  { name:'ReconX', url:'https://github.com/sakshamtaneja21/ReconX', icon:'🔭', cat:'network', tags:['recon','automated'],
    desc:'ReconX автоматизирует несколько шагов разведки в одном скрипте. Выполняет: поиск поддоменов, проверку живых хостов, скрининг портов, захват скриншотов. Прост в использовании. Хороший стартовый набор для автоматизации первичной разведки.', descEn:'ReconX is an automated reconnaissance framework. Combines passive and active recon techniques in a single workflow. Performs: subdomain enumeration, port scanning, service detection, web analysis, vulnerability detection. Has configurable scanning profiles for different levels of intrusiveness. Written in Python.' },

  { name:'Arsenal', url:'https://github.com/Orange-Cyberdefense/arsenal', icon:'⚔️', cat:'network', tags:['cheatsheet','commands'],
    desc:'Arsenal — удобная система поиска по шпаргалкам для инструментов безопасности. Содержит готовые команды для множества инструментов разведки и пентеста. Поиск по ключевым словам. Позволяет быстро найти нужную команду не запоминая синтаксис каждого инструмента.', descEn:'Arsenal is an cheatsheet tool for pentesters and CTF players. Provides quick access to common commands and techniques. Supports searching by keyword, tag, or category. Enables custom cheatsheet additions. Reduces the cognitive load of remembering exact syntax for hundreds of tools. Particularly useful during time-limited assessments.' },

  { name:'Pentest-wiki', url:'https://github.com/nixawk/pentest-wiki', icon:'📖', cat:'network', tags:['reference','wiki'],
    desc:'Pentest Wiki — библиотека ресурсов для пентеста и OSINT. Организована по методологии: разведка, сканирование, эксплуатация. Содержит ссылки на инструменты, руководства, технические детали. Хорошая отправная точка для изучения методологии разведки.', descEn:'PentestWiki is a knowledge base for penetration testers. Contains: methodology guides, tool documentation, exploit techniques, checklists. Maintained as a wiki for easy contribution and updates. Useful as a reference during engagements. Good supplement to formal training materials with practical, hands-on information.' },

  { name:'HackerOne Reports', url:'https://github.com/reddelexc/hackerone-reports', icon:'💰', cat:'network', tags:['bugbounty','reports'],
    desc:'Коллекция публичных отчётов об уязвимостях с HackerOne. Включает отчёты о реальных уязвимостях с описанием методологии обнаружения. Ценный ресурс для обучения — показывает как профессионалы проводят разведку и находят уязвимости в реальных программах Bug Bounty.', descEn:'HackerOne public reports provide valuable learning material for security researchers. Public bug bounty reports detail: vulnerability types, affected endpoints, proof of concept, remediation. Learning from disclosed reports improves understanding of what vulnerabilities look like in real applications. Also useful for understanding program scope and common vulnerability patterns.' },

  { name:'Sploitus', url:'https://github.com/nicowillis/sploitus-api', icon:'💥', cat:'network', tags:['exploits','search'],
    desc:'Sploitus — агрегатор эксплойтов и инструментов взлома. Собирает данные из Exploit-DB, Packetstorm, GitHub и других источников. API позволяет автоматизировать поиск эксплойтов для конкретного ПО. Полезен для быстрого нахождения публичных эксплойтов для уязвимых версий обнаруженных при разведке.', descEn:'Sploitus is an exploit search engine that aggregates exploits from multiple sources: Exploit-DB, Packet Storm, GitHub. Allows searching for exploits by CVE, software name or version. Updated regularly. Useful for finding available exploits for specific vulnerabilities discovered during OSINT/recon. More comprehensive than searching individual databases.' },

  { name:'SearchSploit', url:'https://github.com/offensive-security/exploitdb', icon:'🗃️', cat:'network', tags:['exploits','database'],
    desc:'SearchSploit — CLI для поиска по Exploit-DB (крупнейшей базе публичных эксплойтов). Позволяет искать оффлайн по локальной копии базы. Содержит: PoC-код, описания уязвимостей, shellcode. После разведки помогает быстро найти публичные эксплойты для обнаруженных версий ПО.', descEn:'SearchSploit is the command-line tool for Exploit-DB — the world\'s largest archive of exploits. Offline searching of the local exploit database. Finds exploits for specific software and versions. Can copy exploits for use. Included in Kali Linux. Essential for finding known exploits for vulnerabilities identified during reconnaissance.' },

  { name:'Vuln Scan', url:'https://github.com/v3n0m-Scanner/V3n0M-Scanner', icon:'🔍', cat:'network', tags:['scanner','vulnerability'],
    desc:'V3n0M Scanner — многофункциональный сканер уязвимостей. Проверяет SQL-инъекции, XSS, LFI, RFI через Google Dorks. Имеет модули для Cloudflare bypass, геолокации, получения заголовков. Поддерживает несколько поисковых движков для сбора целей. Инструмент для автоматизированной массовой разведки.', descEn:'Vulnerability scanning tools identify known vulnerabilities in discovered services and software. Combine: Nuclei templates, Nmap NSE scripts, vendor advisories, CVE databases. Automated vulnerability matching against discovered service versions. Used after recon to identify potentially exploitable weaknesses in discovered infrastructure.' },

  { name:'Carbon14', url:'https://github.com/Lazza/Carbon14', icon:'⚛️', cat:'network', tags:['timing','dating'],
    desc:'Carbon14 помогает определить дату создания контента в интернете методами форензики. Анализирует: дату создания файлов, DNS-историю, временные метки в HTML. Полезен при расследовании когда важно установить временную шкалу событий — когда был создан сайт, когда появился контент.', descEn:'Carbon14 is an OSINT tool for estimating when a website was created or last modified. Uses clues like: static asset filenames, JavaScript library versions, page structure, CSS properties. Useful for investigating websites when the creation date is relevant — e.g., determining if a site was created before or after a specific event.' },

  { name:'URLextractor', url:'https://github.com/eschultze/URLextractor', icon:'🔗', cat:'network', tags:['url','extract'],
    desc:'URLextractor извлекает URL и информацию о сайте через несколько онлайн-сервисов. Получает данные из VirusTotal, Urlscan.io, Web Archive. Собирает: ссылки, скриншоты, историю DNS, SSL-сертификаты. Хороший инструмент для быстрого сбора информации о URL.', descEn:'URLextractor is a tool for extracting all URLs from a target webpage or a list of pages. Collects links, scripts, images and other URL references. Helps build a comprehensive map of a site\'s linked resources. Used in web app recon to discover all linked URLs before further analysis.' },

  { name:'Urlscan CLI', url:'https://github.com/heywoodlh/urlscan-go', icon:'🔍', cat:'network', tags:['urlscan','analyze'],
    desc:'CLI для urlscan.io — сервиса который сканирует URL и предоставляет подробную информацию: скриншот, DOM, cookies, запросы, ресурсы, технологии, DNS, сертификаты. Позволяет безопасно "посетить" подозрительный URL не открывая его в своём браузере.', descEn:'Urlscan CLI is the command-line interface for urlscan.io — a service that scans and analyzes websites. Submits URLs for scanning and retrieves results: screenshot, DOM, network requests, technologies, certificates, links. Historical scan data reveals past states of websites. Useful for safely analyzing suspicious URLs without visiting them directly.' },

  { name:'Pwndb', url:'https://github.com/davidtavarez/pwndb', icon:'🔓', cat:'email', tags:['breach','pwndb'],
    desc:'PwnDB CLI позволяет искать скомпрометированные учётные данные в базе pwndb через Tor. База содержит сотни миллионов пар логин-пароль из реальных утечек. Важно использовать только для проверки собственных аккаунтов или с разрешения владельца. Требует Tor для доступа.', descEn:'Pwndb is a Python tool for searching leaked credentials in the Pwndb Tor hidden service database. Queries by email or domain to find leaked username/password combinations. Useful for checking if accounts have been compromised in data breaches. Note: Pwndb has had availability issues — alternative services may be more reliable.' },

  { name:'Have I Been Pwned API', url:'https://github.com/andrewbarber/hibp', icon:'🔒', cat:'email', tags:['breach','hibp'],
    desc:'HIBP API-клиент для проверки email-адресов и паролей в базе haveibeenpwned.com. База содержит данные из сотен утечек. Проверка паролей использует k-анонимность — пароль никогда не передаётся полностью. Незаменим для проверки корпоративных email на факт компрометации.', descEn:'Have I Been Pwned (HIBP) API is the official API for Troy Hunt\'s breach notification service. Programmatically check emails against the breach database. The Pwned Passwords API checks individual passwords against 600+ million compromised passwords. Used in security tools to automate credential exposure checking. Widely trusted and regularly updated.' },

  { name:'LeakLooker', url:'https://github.com/woj-ciech/LeakLooker', icon:'💧', cat:'network', tags:['shodan','databases'],
    desc:'LeakLooker использует Shodan для поиска открытых баз данных: MongoDB, Elasticsearch, CouchDB, Kibana, Jenkins, Cassandra. Автоматически проверяет найденные базы на доступность без аутентификации. Находит случайно открытые базы с реальными данными.', descEn:'LeakLooker is a tool for finding publicly accessible databases and sensitive files. Searches Shodan for exposed MongoDB, Elasticsearch, CouchDB, Redis instances. Also checks for accessible S3 buckets, .git directories, and other common misconfigurations. Useful for quickly identifying exposed data sources associated with a target organization.' },

  { name:'Datasploit-ng', url:'https://github.com/DataSploit/datasploit', icon:'🧬', cat:'people', tags:['osint','automated'],
    desc:'Datasploit автоматизирует OSINT по нескольким типам идентификаторов. Собирает данные из десятков источников, дедуплицирует и формирует отчёт. Поддерживает поиск по email, домену, имени, телефону. Хорошо подходит для быстрого первичного сбора данных об объекте.', descEn:'Datasploit-ng is an updated version of Datasploit OSINT framework. Collects information about targets from multiple sources and correlates the data. Supports: email, domain, phone, username as inputs. Generates comprehensive HTML reports. Updated to work with current APIs and services where the original version has become outdated.' },

  { name:'Dojo', url:'https://github.com/DefectDojo/django-DefectDojo', icon:'🥋', cat:'network', tags:['vulnerability','management'],
    desc:'DefectDojo — платформа для управления уязвимостями и результатами тестирования. Агрегирует результаты сканеров (Nmap, ZAP, Burp, Nuclei), дедуплицирует, отслеживает статус устранения. Формирует метрики и отчёты. Незаменим при организации систематического процесса безопасности.', descEn:'DefectDojo is an open-source vulnerability management platform. Aggregates results from security scanners, manages vulnerabilities, tracks remediation. Supports importing results from 100+ tools: Burp Suite, Nessus, ZAP, Semgrep, and others. Provides: metrics, reporting, deduplication. Used by security teams to manage findings from multiple assessments.' },

  { name:'Faraday', url:'https://github.com/infobyte/faraday', icon:'⚗️', cat:'network', tags:['pentest','management'],
    desc:'Faraday — IDE для пентестинга. Агрегирует данные из более чем 70 инструментов, хранит в базе, визуализирует. Поддерживает командную работу. Имеет веб-интерфейс для управления и отчётности. Превращает хаотичный процесс разведки в структурированный управляемый рабочий процесс.', descEn:'Faraday is a collaborative penetration testing and vulnerability management platform. Aggregates results from multiple security tools into a single dashboard. Supports 70+ tool plugins. Enables team collaboration on assessments. Has workspace management for organizing multiple engagements. Community edition is free with limitations.' },

  { name:'Piracy Shield', url:'https://github.com/arantius/picard', icon:'🛡️', cat:'network', tags:['monitoring','osint'],
    desc:'Инструмент для мониторинга собственной цифровой экспозиции. Отслеживает упоминания в интернете, проверяет данные в утечках, мониторит DNS-изменения. Полезен для организаций которые хотят знать что о них известно из открытых источников и быстро реагировать на утечки.', descEn:'Tools for investigating piracy and content theft. Includes techniques for: identifying piracy sites, WHOIS-based attribution, finding hosting infrastructure of illegal distribution networks. Used by content rights holders and investigators to trace and document unauthorized content distribution.' },

  { name:'Censys Subdomain Finder', url:'https://github.com/christophetd/censys-subdomain-finder', icon:'🔍', cat:'network', tags:['censys','subdomains'],
    desc:'Censys Subdomain Finder ищет поддомены через базу SSL-сертификатов Censys. Certificate Transparency логи содержат информацию обо всех выданных сертификатах включая wildcard и multi-SAN сертификаты. Часто находит поддомены которые не отображаются в DNS и других источниках.', descEn:'Censys Subdomain Finder is a tool specifically designed to extract subdomains from Censys certificate data. Censys maintains one of the most comprehensive TLS certificate databases. This tool queries it efficiently to find all subdomains with valid certificates. Fast and reliable for certificate-based subdomain discovery.' },

  { name:'Crtsh', url:'https://github.com/PaulSec/crt.sh', icon:'🔐', cat:'network', tags:['certificates','ct'],
    desc:'crt.sh — публичный лог Certificate Transparency. Python-обёртка для поиска через crt.sh API. Находит все SSL-сертификаты выданные для домена и поддоменов. Certificate Transparency — один из лучших пассивных источников для обнаружения поддоменов, часто включая внутренние и staging-серверы.', descEn:'crt.sh is a website and API for Certificate Transparency log search. Every TLS certificate issued by trusted CAs is logged in CT logs. crt.sh makes this data searchable. Can find subdomains (via wildcard certs), historical certificates, expired certs that may still be in use. CLI tools query the crt.sh API for automated use in recon pipelines.' },

  { name:'CT-exposer', url:'https://github.com/chris408/ct-exposer', icon:'📜', cat:'network', tags:['certificates','discovery'],
    desc:'CT-Exposer использует логи Certificate Transparency для нахождения доменов и поддоменов. Ищет в публичных CT-логах по организации или ключевым словам. Может находить домены которые никогда не появлялись в DNS-запросах и недоступны через другие методы.', descEn:'CT-exposer is a tool for discovering subdomains using Certificate Transparency logs. Queries CT log aggregators to find all certificates issued for a domain and its subdomains. Particularly useful for finding old subdomains that may no longer be in active DNS but whose certificates were once issued. Complements other passive subdomain discovery methods.' },

  { name:'Dnsx Bruteforce', url:'https://github.com/projectdiscovery/dnsx', icon:'💥', cat:'network', tags:['dns','wordlist'],
    desc:'DNSx с режимом брутфорса поддоменов. Принимает список слов, добавляет к базовому домену, резолвит. Один из самых быстрых инструментов для DNS-брутфорса благодаря асинхронной архитектуре. Отлично работает с большими словарями. Правильно обрабатывает wildcard-домены.', descEn:'DNSx in bruteforce mode takes a wordlist and resolves potential subdomain names. Combined with a good wordlist and DNS wildcard filtering, can discover many subdomains missed by passive methods. The active complement to passive subdomain discovery — finds subdomains that have never been in CT logs or passive sources.' },

  { name:'Shuffledns', url:'https://github.com/projectdiscovery/shuffledns', icon:'🔀', cat:'network', tags:['dns','massdns'],
    desc:'shuffleDNS — обёртка над MassDNS от ProjectDiscovery. Добавляет: обнаружение wildcard, дедупликацию, интеграцию с другими инструментами. Умеет как брутфорсить поддомены так и резолвить переданный список. Решает проблему ложных срабатываний при wildcard DNS.', descEn:'ShuffleDNS is a DNS resolver wrapper that uses MassDNS under the hood. Resolves a list of potential subdomains at massive scale while handling wildcard DNS properly. Can take input from other subdomain discovery tools. Handles millions of DNS lookups efficiently. Key component in large-scale subdomain discovery workflows.' },

  { name:'Gotator', url:'https://github.com/Josue87/gotator', icon:'🔄', cat:'network', tags:['permutations','subdomains'],
    desc:'Gotator генерирует перестановки поддоменов. Принимает список найденных поддоменов и создаёт новые варианты путём добавления префиксов и суффиксов. Умнее Altdns — учитывает структуру найденных поддоменов. Результат резолвируется через MassDNS или DNSx для нахождения реальных хостов.', descEn:'Gotator generates subdomain permutations from a list of known subdomains. Uses a wordlist of mutation keywords to generate: dev-api, api-v2, old-api, etc. Written in Go. More configurable than Altdns with additional permutation patterns. Used to discover subdomains that follow naming patterns similar to known ones.' },

  { name:'Regexp-tools', url:'https://github.com/tomnomnom/meg', icon:'📡', cat:'network', tags:['fetch','parallel'],
    desc:'Meg от tomnomnom — параллельно загружает много URL. Принимает список путей и список хостов, запрашивает каждый путь для каждого хоста. Сохраняет ответы в файлы. Идеален для проверки наличия определённых файлов (robots.txt, .git/config, .env) на большом количестве хостов.', descEn:'Regexp-tools is a collection of regular expression utilities for OSINT and security research. Contains pre-built patterns for: extracting IoCs from text, matching email formats, finding URLs, identifying hash types. Used in automated text processing pipelines to extract structured data from unstructured sources.' },

  { name:'Freq', url:'https://github.com/MarkBaggett/freq', icon:'📊', cat:'network', tags:['domain','scoring'],
    desc:'Freq анализирует частоту символов в доменных именах для обнаружения DGA (Domain Generation Algorithm) доменов используемых малварью. Помогает отличить легитимные домены от автоматически сгенерированных. Полезен при анализе DNS-логов на предмет C2-коммуникаций.', descEn:'Freq is a tool for analyzing DNS frequency patterns to detect domain generation algorithms (DGA). DGA is used by malware to generate many domain names for C2 communication. By analyzing character frequency patterns, Freq identifies algorithmically generated domains among normal ones. Useful for malware domain infrastructure OSINT.' },

  { name:'Dnstake', url:'https://github.com/pwnesia/dnstake', icon:'🚩', cat:'network', tags:['dns','takeover'],
    desc:'DNStake проверяет поддомены на возможность перехвата через DNS (subdomain takeover). Обнаруживает ситуации когда CNAME-запись указывает на несуществующий ресурс в облаке (AWS, GitHub Pages, Azure). Subdomain takeover позволяет злоумышленнику разместить контент на поддомене организации.', descEn:'DNSTake is a tool for checking subdomain takeover vulnerabilities at scale. Detects dangling DNS records that point to expired or unclaimed services: GitHub Pages, Heroku, Fastly, etc. A subdomain pointing to an unclaimed service can be taken over by anyone. Processes large lists of subdomains quickly. Written in Go.' },

  { name:'Subzy', url:'https://github.com/LukaSikic/subzy', icon:'🚩', cat:'network', tags:['takeover','subdomain'],
    desc:'Subzy — быстрый инструмент для обнаружения уязвимостей subdomain takeover. Поддерживает 50+ сервисов (GitHub Pages, Heroku, Shopify, Tumblr и другие). Принимает список поддоменов и проверяет каждый. Написан на Go, работает конкурентно. Один из лучших инструментов для поиска takeover-уязвимостей.', descEn:'Subzy is a subdomain takeover vulnerability checker. Takes a list of subdomains and checks each for potential takeover by matching CNAME responses against a database of fingerprints for vulnerable services. Supports 50+ services. Written in Go, very fast. Essential for large-scale takeover detection in bug bounty programs.' },

  { name:'Can-I-take-over-xyz', url:'https://github.com/EdOverflow/can-i-take-over-xyz', icon:'❓', cat:'network', tags:['takeover','reference'],
    desc:'Справочник по уязвимостям subdomain takeover для разных облачных провайдеров и сервисов. Содержит: статус уязвимости (vulnerable/not vulnerable), как проверить, как эксплуатировать, как исправить. Незаменимый ресурс при проверке на subdomain takeover.', descEn:'Can I take over XYZ is a GitHub repository that documents which services are vulnerable to subdomain takeover. For each service, it specifies: vulnerable CNAME patterns, proof of concept steps, difficulty level. The reference guide for subdomain takeover research. Used to identify takeover candidates from CNAME records found during subdomain enumeration.' },

  { name:'Httprobe', url:'https://github.com/tomnomnom/httprobe', icon:'🌐', cat:'network', tags:['probe','http'],
    desc:'Httprobe проверяет список доменов на наличие работающих HTTP/HTTPS-серверов. Быстро фильтрует живые хосты из тысяч найденных поддоменов. Поддерживает кастомные порты. Написан на Go. Один из самых часто используемых инструментов в Bug Bounty пайплайнах.', descEn:'Httprobe takes a list of domains and probes for working HTTP and HTTPS servers. Very fast — uses concurrency to probe thousands of hosts quickly. Outputs only those that respond. Written in Go by tomnomnom. Essential filtering step between subdomain discovery and screenshot taking — eliminates dead hosts before more expensive operations.' },

  { name:'Webanalyze', url:'https://github.com/rverton/webanalyze', icon:'🔬', cat:'network', tags:['wappalyzer','fingerprint'],
    desc:'Webanalyze — Go-реализация Wappalyzer для fingerprinting технологий. Принимает список URL и определяет используемые технологии для каждого. Работает быстро, поддерживает конкурентность. Использует базу данных Wappalyzer. Идеален для массового fingerprinting большого количества хостов.', descEn:'Webanalyze is the CLI version of Wappalyzer for bulk technology detection. Takes a list of URLs and identifies technologies used on each. Processes large lists efficiently. Outputs JSON for programmatic processing. Used in recon pipelines to identify CMSs, frameworks, and technologies across many targets at scale.' },

  { name:'HTTPScreenshot', url:'https://github.com/breenmachine/httpscreenshot', icon:'📷', cat:'network', tags:['screenshot','recon'],
    desc:'HTTPScreenshot делает скриншоты веб-сайтов в масштабе используя PhantomJS или Selenium. Принимает список хостов из Nmap или других источников. Сохраняет скриншоты для визуального осмотра. Один из первых инструментов этого класса — заложил основу для GoWitness и EyeWitness.', descEn:'HTTPScreenshot is a tool for mass screenshot taking of web servers. Takes a list of IPs or URLs and captures screenshots using a headless browser. One of the original mass screenshot tools. Useful for quick visual triage of large numbers of discovered hosts. Older tool — GoWitness and EyeWitness are more modern alternatives.' },

  { name:'Goclone', url:'https://github.com/imthaghost/goclone', icon:'🔗', cat:'network', tags:['clone','website'],
    desc:'GoClone клонирует веб-сайты для локального просмотра. Скачивает HTML, CSS, JS, изображения. Сохраняет структуру директорий. Полезен для архивирования доказательств, анализа исходного кода сайта, создания локальной копии для изучения.', descEn:'GoClone is a website cloning tool written in Go. Creates a local copy of a website for: offline analysis, evidence preservation, security testing. Handles relative links and resources. Faster than HTTrack for simple sites. Used in OSINT for preserving website content and in social engineering setups for authorized phishing simulations.' },

  { name:'HTTrack', url:'https://github.com/xroche/httrack', icon:'💾', cat:'network', tags:['mirror','website'],
    desc:'HTTrack — классический инструмент для зеркалирования сайтов. Скачивает весь сайт для локального просмотра. Поддерживает продолжение прерванной загрузки, фильтры по типу файлов, ограничение глубины. Идеален для создания полных локальных копий сайтов для последующего анализа.', descEn:'HTTrack is a website copier that allows downloading a website to a local directory. Mirrors the entire site including HTML, images, CSS, JS. Handles relative links correctly for offline browsing. One of the oldest and most reliable web copying tools. Useful for creating offline archives of websites for evidence or analysis.' },

  { name:'Maltego-Shodan', url:'https://github.com/penafieljlm/maltego-shodan', icon:'🕸️', cat:'network', tags:['maltego','shodan'],
    desc:'Maltego-трансформации для Shodan. Позволяет интегрировать данные Shodan в граф Maltego. Можно из IP получить открытые порты, сервисы, баннеры прямо в интерфейсе Maltego. Объединяет визуализацию Maltego с данными Shodan для наглядного представления сетевой инфраструктуры.', descEn:'Maltego Shodan integration connects Shodan\'s internet scan data with Maltego\'s visual analysis. Transform inputs (IP, domain, organization) into Shodan discoveries: open ports, banners, services, vulnerabilities. Building a visual map of an organization\'s internet-facing infrastructure. Enables discovering related assets from initial indicators.' },

  { name:'Recon-go', url:'https://github.com/j3ssie/goverview', icon:'📊', cat:'network', tags:['overview','recon'],
    desc:'Goverview даёт быстрый обзор большого количества хостов. Проверяет HTTP-ответы, определяет технологии, делает скриншоты. Параллельная обработка. Формирует сводный отчёт. Полезен когда нужно быстро оценить большое количество найденных хостов.', descEn:'Recon-go is a reconnaissance framework written in Go. Focuses on speed by leveraging Go\'s concurrency. Performs various recon tasks: subdomain discovery, port scanning, web analysis. Configurable via config files. Good choice for performance-critical recon workflows where Python-based tools are too slow.' },

  { name:'Osint-cli', url:'https://github.com/jivoi/awesome-osint', icon:'📚', cat:'network', tags:['collection','reference'],
    desc:'Awesome OSINT — один из самых популярных кураторских списков OSINT-инструментов и ресурсов. Охватывает: поиск по людям, социальным сетям, доменам, IP, геолокации, изображениям, даркнету. Включает инструменты, онлайн-сервисы, книги, курсы. Эссенциальный ресурс для каждого OSINT-исследователя.', descEn:'OSINT CLI tools provide command-line access to various OSINT services and APIs. Enable scripting and automation of common OSINT lookups. Useful for building custom workflows that combine multiple OSINT data sources without manual browser interaction.' },

  { name:'Osint-search', url:'https://github.com/ivan-sincek/chad', icon:'🔍', cat:'network', tags:['google','dorks'],
    desc:'Chad (formerly GoogleFu) — инструмент для автоматизированного Google-поиска с поддержкой дорков. Обходит ограничения Google через паузы и ротацию. Поддерживает экспорт результатов. Автоматизирует ручной процесс поиска через Google что экономит время при разведке.', descEn:'OSINT Search aggregates results from multiple OSINT search engines and databases. Queries multiple sources simultaneously and combines results. Reduces the manual effort of checking each source individually. Useful for comprehensive coverage of available OSINT data for a given indicator.' },

  { name:'Gitgraber', url:'https://github.com/hisxo/gitGraber', icon:'🐙', cat:'network', tags:['github','monitoring'],
    desc:'gitGraber мониторит GitHub в реальном времени для нахождения конфиденциальных данных. Отслеживает новые коммиты и ищет в них паттерны: API-ключи, пароли, токены, конфигурационные файлы. Отправляет уведомления в Slack или Telegram. Незаменим для мониторинга утечек в реальном времени.', descEn:'Gitgraber is a real-time GitHub monitoring tool that continuously searches for sensitive keywords. Monitors new commits and repos for: passwords, API keys, tokens, usernames, company-specific terms. Sends notifications when matches are found. Useful for continuous monitoring of GitHub for data leaks related to your organization.' },

  { name:'Github-dork', url:'https://github.com/techgaun/github-dorks', icon:'🔍', cat:'network', tags:['github','secrets'],
    desc:'Коллекция дорков для поиска конфиденциальных данных в GitHub. Содержит готовые поисковые запросы для нахождения: паролей, API-ключей, SSH-ключей, конфигурационных файлов. Помогает быстро и систематически искать утечки в публичных репозиториях.', descEn:'Github-dork is a tool for running multiple GitHub search dorks against a target. Automates searching GitHub for sensitive data related to a domain or organization: API keys, passwords, internal hostnames, email addresses. Uses GitHub\'s code search API. Requires a GitHub token for meaningful results.' },

  { name:'Shhgit', url:'https://github.com/eth0izzle/shhgit', icon:'🤫', cat:'network', tags:['github','secrets'],
    desc:'Shhgit — мониторинг GitHub, GitLab и Bitbucket в реальном времени для нахождения случайно опубликованных секретов. Обрабатывает поток событий публичных репозиториев. Содержит 120+ встроенных паттернов для обнаружения секретов. Отображает результаты в веб-интерфейсе.', descEn:'Shhgit monitors GitHub, GitLab, and Bitbucket in real-time for sensitive data. Uses a library of detection signatures covering hundreds of secret types. Processes thousands of commits per minute. Can be configured with custom signatures. Alternative to TruffleHog/GitLeaks for real-time monitoring rather than historical scanning.' },

  { name:'Repo-supervisor', url:'https://github.com/auth0/repo-supervisor', icon:'👀', cat:'network', tags:['secrets','scan'],
    desc:'Repo-supervisor сканирует репозитории на предмет конфиденциальных данных. Анализирует файлы конфигурации, исходный код, переменные окружения. Использует словари и паттерны для обнаружения секретов. Разработан Auth0 для защиты собственных репозиториев.', descEn:'Repo-supervisor is a tool for detecting secrets and passwords in git repositories. Scans commit history looking for high-entropy strings that may be API keys or tokens. Also applies pattern matching for known secret formats. Good complement to TruffleHog and GitLeaks for comprehensive secrets detection in source code.' },

  { name:'Pip-audit', url:'https://github.com/pypa/pip-audit', icon:'🐍', cat:'network', tags:['python','vulnerabilities'],
    desc:'pip-audit проверяет Python-зависимости на известные уязвимости через базу PyPI Advisory Database и OSV. С точки зрения OSINT полезен для анализа найденных Python-приложений — если известны зависимости можно быстро определить какие CVE применимы.', descEn:'Pip-audit is a tool for auditing Python packages for known vulnerabilities. Checks installed Python packages against the OSV vulnerability database. Used in security assessments to identify vulnerable dependencies in Python applications. Essential part of supply chain security analysis.' },

  { name:'Trivy', url:'https://github.com/aquasecurity/trivy', icon:'🔍', cat:'network', tags:['container','vulnerability'],
    desc:'Trivy — сканер уязвимостей для контейнеров, файловых систем, репозиториев. Проверяет OS-пакеты, зависимости приложений, IaC-файлы на CVE. Используется в CI/CD для проверки Docker-образов. В OSINT полезен для анализа публично доступных Docker-образов организации.', descEn:'Trivy is a comprehensive security scanner for containers, filesystems and IaC. Detects: CVEs in OS packages and programming language dependencies, IaC misconfigurations, exposed secrets. Supports Docker images, OCI artifacts, Git repos, file systems. Very easy to use: trivy image <image_name>. Standard tool in container security pipelines.' },

  { name:'Scout Suite', url:'https://github.com/nccgroup/ScoutSuite', icon:'☁️', cat:'network', tags:['cloud','audit'],
    desc:'Scout Suite — инструмент аудита безопасности облачных инфраструктур. Поддерживает AWS, Azure, GCP, Alibaba Cloud. Собирает конфигурацию и проверяет на соответствие лучшим практикам безопасности. Формирует HTML-отчёт с находками. Используется для оценки состояния безопасности облачной инфраструктуры.', descEn:'Scout Suite is an open-source multi-cloud security auditing tool. Analyzes cloud provider configurations: AWS, GCP, Azure, Alibaba Cloud, Oracle Cloud. Generates an HTML report showing misconfigurations and security issues across all services. Useful for assessing cloud security posture in authorized audits. Requires cloud provider credentials.' },

  { name:'Pacu', url:'https://github.com/RhinoSecurityLabs/pacu', icon:'🦎', cat:'network', tags:['aws','pentest'],
    desc:'Pacu — фреймворк для пентестинга AWS-окружений. Содержит модули для: перечисления сервисов, эскалации привилегий, экфильтрации данных. Управляет сессиями и ключами. Ведёт журнал действий. Используется для проверки безопасности AWS-инфраструктуры с разрешения владельца.', descEn:'Pacu is an open-source AWS exploitation framework. Helps with: post-exploitation after gaining AWS credentials, privilege escalation, lateral movement in AWS environments, data exfiltration. Has 40+ modules covering different AWS services. Used in authorized red team assessments to evaluate AWS security. Inspired by Metasploit in design.' },

  { name:'Prowler', url:'https://github.com/prowler-cloud/prowler', icon:'☁️', cat:'network', tags:['aws','compliance'],
    desc:'Prowler — инструмент для проверки безопасности и соответствия требованиям в AWS. Содержит более 300 проверок, соответствующих стандартам CIS, HIPAA, GDPR, SOC2. Обнаруживает открытые S3-бакеты, незашифрованные ресурсы, избыточные права IAM. Используется организациями для аудита собственной AWS-инфраструктуры.', descEn:'Prowler is a security tool for AWS, GCP and Azure compliance assessment. Performs 300+ checks for CIS Benchmarks, GDPR, HIPAA, PCI-DSS, SOC2 compliance. Written in Python, fast and easy to use. Generates reports in JSON, HTML and CSV. Used for both initial security assessment and continuous compliance monitoring of cloud environments.' },

  { name:'Steghide', url:'https://github.com/StefanoDeVuono/steghide', icon:'🙈', cat:'image', tags:['steganography','hide'],
    desc:'Steghide — инструмент для встраивания и извлечения данных из изображений и аудиофайлов методом стеганографии. Поддерживает JPEG, BMP, WAV, AU. Использует шифрование для защиты скрытых данных. В OSINT используется для проверки изображений на наличие скрытых сообщений.', descEn:'Steghide is a steganography tool for hiding data in JPEG, BMP, WAV and AU files. Uses AES-128 encryption. Both hides data and extracts hidden data. Common in CTF challenges. From OSINT perspective: used to extract hidden messages from suspicious images shared online. Detecting steganography requires tools like Stegdetect.' },

  { name:'Zsteg', url:'https://github.com/zed-0xff/zsteg', icon:'🔎', cat:'image', tags:['steganography','png'],
    desc:'Zsteg обнаруживает стеганографические данные в PNG и BMP изображениях. Проверяет различные методы LSB стеганографии. Умеет автоматически определять тип скрытых данных. Используется в CTF и OSINT для анализа подозрительных изображений.', descEn:'Zsteg is a tool for detecting and extracting hidden data in PNG and BMP images. Checks: LSB steganography, zlib-compressed hidden data, extraLSB, bgr/rgb channel reordering. More focused on PNG than Steghide. Common in CTF and digital forensics. Used to analyze images suspected of containing hidden messages.' },

  { name:'Binwalk', url:'https://github.com/ReFirmLabs/binwalk', icon:'🔧', cat:'image', tags:['firmware','extract'],
    desc:'Binwalk анализирует и извлекает файлы из бинарных образов. Обнаруживает: встроенные файлы и файловые системы, сигнатуры форматов, сжатые данные. В OSINT полезен для анализа прошивок устройств найденных через Shodan и извлечения конфигурационных файлов и ключей.', descEn:'Binwalk is a tool for analyzing firmware and binary files. Identifies embedded files and executable code: file system signatures, compressed archives, encryption keys, certificates. Can extract found files. Used in: IoT firmware analysis, finding hidden files inside images or binaries, reverse engineering embedded devices. Essential for firmware security research.' },

  { name:'Foremost', url:'https://github.com/korczis/foremost', icon:'📂', cat:'image', tags:['forensics','recovery'],
    desc:'Foremost — инструмент для восстановления файлов по сигнатурам. Может извлечь файлы из дампов диска, образов памяти. Поддерживает: JPEG, PNG, GIF, PDF, ZIP, DOC и другие форматы. В OSINT используется для извлечения файлов из найденных образов прошивок или дампов.', descEn:'Foremost is a file carving tool for recovering files based on file headers and footers. Recovers files from disk images or arbitrary data streams. Supports: JPEG, GIF, PNG, BMP, AVI, EXE, MPG, WAV, PDF, ZIP. Used in digital forensics for data recovery and CTF challenges. Can find hidden files even without a filesystem structure.' },

  { name:'OSINTer', url:'https://github.com/osinter-tools/osinter', icon:'🤖', cat:'network', tags:['news','aggregator'],
    desc:'OSINTer — платформа для сбора и анализа OSINT-информации из новостных источников. Автоматически скрапит публикации из сотен источников кибербезопасности, классифицирует по темам и субъектам. Поддерживает поиск по IoC. Полезен для мониторинга угроз и актуальных уязвимостей.', descEn:'OSINTer is an open-source intelligence platform for automated collection and analysis. Manages: news collection from custom profiles, OSINT article aggregation, timeline building. Has both CLI and web interface. Focuses on structured intelligence collection and analysis rather than technical target investigation. Good for media monitoring and intelligence briefings.' },

  { name:'Shodan Dorks', url:'https://github.com/lothos612/shodan', icon:'🔍', cat:'network', tags:['shodan','dorks'],
    desc:'Коллекция дорков для Shodan — специальных запросов для нахождения конкретных типов уязвимых устройств и сервисов. Охватывает: промышленные системы управления, IP-камеры, принтеры, роутеры, базы данных, панели управления. Незаменимый справочник для работы с Shodan.', descEn:'Shodan Dorks are specialized search queries that find specific types of devices and services. Examples: \'default password\' finds devices with default credentials exposed, \'port:27017\' finds exposed MongoDB instances. A library of effective Shodan dorks significantly expands what you can find. Regularly updated community dork collections are available on GitHub.' },

  { name:'IoTscan', url:'https://github.com/therealsaumil/static-arm-bins', icon:'📡', cat:'network', tags:['iot','firmware'],
    desc:'Набор инструментов для анализа IoT-устройств. Включает статически скомпилированные бинарники для ARM-архитектур. Позволяет запускать утилиты разведки прямо на устройствах или в эмуляторах. Полезен для анализа безопасности IoT-прошивок.', descEn:'IoTscan is a tool for discovering and analyzing IoT devices on networks. Identifies: device types, manufacturers, firmware versions, known vulnerabilities. Uses passive fingerprinting and active probing. Useful for IoT security assessments and OSINT investigations of organizations with industrial/IoT infrastructure.' },

  { name:'Eaphammer', url:'https://github.com/s0lst1c3/eaphammer', icon:'📶', cat:'network', tags:['wifi','evil-twin'],
    desc:'EAPHammer — инструмент для тестирования безопасности корпоративных Wi-Fi сетей. Создаёт Evil Twin точки доступа для перехвата учётных данных. Используется с разрешения организации для проверки устойчивости к атакам на WPA-Enterprise. Помогает выявить уязвимости в конфигурации Wi-Fi.', descEn:'EAPHammer is a toolkit for attacking WPA2-Enterprise networks. Performs: evil twin attacks against enterprise WiFi, hostile portal attacks, authentication capture. Used for assessing the security of corporate WiFi implementations that use 802.1X authentication. Shows whether employees can be phished via rogue access points.' },

  { name:'Netdiscover', url:'https://github.com/netdiscover-scanner/netdiscover', icon:'🔍', cat:'network', tags:['arp','discovery'],
    desc:'Netdiscover — активный/пассивный ARP-сканер для обнаружения хостов в сети. Работает путём отправки ARP-запросов или пассивного прослушивания ARP-трафика. Быстро находит все активные устройства в локальной сети. Полезен при физическом присутствии в сети объекта разведки.', descEn:'Netdiscover is an active/passive ARP recon tool. Discovers hosts on a local network by sending ARP requests and monitoring ARP traffic. Shows: IP addresses, MAC addresses, manufacturer information. Useful for initial discovery of devices on a local network during physical access assessments or internal network penetration tests.' },

  { name:'Arp-scan', url:'https://github.com/royhills/arp-scan', icon:'📡', cat:'network', tags:['arp','local'],
    desc:'Arp-scan отправляет ARP-пакеты для обнаружения и fingerprinting хостов в локальной сети. Очень быстр — сканирует /24 сеть за секунды. Определяет производителя устройства по MAC-адресу. Невозможно заблокировать через брандмауэр (ARP работает на L2). Незаменим для быстрого картирования локальной сети.', descEn:'Arp-scan is a command-line tool for network discovery using ARP. Sends ARP packets to all possible IP addresses in a range and collects responses. Provides: IP, MAC and manufacturer information. Very fast for local network discovery. More reliable than Nmap ping scan on local networks since ARP doesn\'t rely on ICMP being allowed.' },

  { name:'Nessus CLI', url:'https://github.com/tenable/pyTenable', icon:'🔴', cat:'network', tags:['nessus','vulnerability'],
    desc:'pyTenable — Python SDK для Tenable.io и Nessus API. Позволяет автоматизировать запуск сканирований, получение результатов, управление активами. Nessus — один из ведущих коммерческих сканеров уязвимостей. SDK позволяет интегрировать его в автоматизированные рабочие процессы.', descEn:'Nessus is the industry-leading vulnerability scanner. The CLI allows automating scan creation, execution and result retrieval. Nessus performs deep service analysis and vulnerability detection across thousands of CVEs. Standard in enterprise security assessments. Requires a subscription for the full version (Essentials is free with limitations).' },

  { name:'OpenVAS', url:'https://github.com/greenbone/openvas-scanner', icon:'🟢', cat:'network', tags:['vulnerability','scanner'],
    desc:'OpenVAS — мощный бесплатный сканер уязвимостей. Содержит более 100 000 тестов уязвимостей (NVT). Регулярно обновляется. Поддерживает аутентифицированное сканирование. Часть Greenbone Vulnerability Management. Стандарт среди бесплатных сканеров уязвимостей для корпоративного использования.', descEn:'OpenVAS (Open Vulnerability Assessment System) is the free alternative to commercial vulnerability scanners. Part of the Greenbone Vulnerability Manager. Has 50,000+ Network Vulnerability Tests (NVTs). Performs comprehensive service and vulnerability scanning. Setup is more complex than Nessus but completely free. Standard in open-source security assessment toolchains.' },

  { name:'Lynis', url:'https://github.com/CISOfy/lynis', icon:'🐧', cat:'network', tags:['audit','linux'],
    desc:'Lynis — инструмент аудита безопасности для Unix-систем. Проверяет конфигурацию системы на соответствие лучшим практикам: пакеты, пользователи, авторизация, файрволл, логирование. Формирует отчёт с приоритизированными рекомендациями. Незаменим для hardening Linux/Unix серверов.', descEn:'Lynis is a security auditing tool for Unix-based systems. Performs a deep security scan: file permissions, authentication settings, installed software, kernel hardening, firewall configuration, logging. Generates a security score and prioritized recommendations. Used for: server hardening, compliance auditing, security baselines. Runs on the target system itself.' },

  { name:'OSquery', url:'https://github.com/osquery/osquery', icon:'🔍', cat:'network', tags:['endpoint','monitoring'],
    desc:'OSquery позволяет использовать SQL для получения информации о состоянии операционной системы. "Таблицы" — это процессы, пользователи, сетевые соединения, установленные пакеты, файловая система. Используется для мониторинга хостов и реагирования на инциденты. Поддерживает Windows, macOS, Linux.', descEn:'OSquery transforms the operating system into a relational database. Allows querying system state using SQL: running processes, open network connections, installed packages, user accounts, cron jobs. Used for: security monitoring, incident investigation, compliance checking. Can run queries across many systems simultaneously via the fleet management features.' },

  { name:'TheHive', url:'https://github.com/TheHive-Project/TheHive', icon:'🐝', cat:'network', tags:['incident','response'],
    desc:'TheHive — платформа для управления инцидентами безопасности. Интегрируется с Cortex для автоматического обогащения IoC и MISP для обмена данными угроз. Позволяет командам совместно работать над расследованием инцидентов. Широко используется в CERT и SOC по всему миру.', descEn:'TheHive is an open-source Security Incident Response Platform (SIRP). Enables: creating and tracking security cases, collaborative investigation, task management, evidence handling. Integrates with MISP for threat intelligence. Used by SOC teams to manage security incidents. Has an API for automation and integration with SIEM and other tools.' },

  { name:'Cortex', url:'https://github.com/TheHive-Project/Cortex', icon:'🧠', cat:'network', tags:['analysis','automation'],
    desc:'Cortex — движок для анализа IoC и автоматизации ответных действий. Поддерживает сотни анализаторов: VirusTotal, Shodan, MISP, MaxMind, URLScan. Каждый анализатор обогащает IoC дополнительными данными. Интегрируется с TheHive. Мощный инструмент для автоматизации анализа угроз.', descEn:'Cortex is a powerful observable analysis and active response engine that integrates with TheHive. Enables running automated analyzers on observables: IPs, domains, emails, files. Analyzers query external services: VirusTotal, Shodan, AbuseIPDB, DomainTools. Centralizes threat intelligence lookups. Responders can take automated defensive actions.' },

  { name:'Mihari', url:'https://github.com/ninoseki/mihari', icon:'🔍', cat:'network', tags:['threat-hunt','osint'],
    desc:'Mihari — Ruby-фреймворк для охоты на угрозы. Автоматизирует запросы к Shodan, Censys, VirusTotal, URLScan, MISP. Сохраняет результаты в базе данных. Поддерживает уведомления через Slack. Позволяет строить автоматические рабочие процессы для мониторинга угроз.', descEn:'Mihari is a threat hunting tool for finding C2 servers and malicious infrastructure. Queries multiple sources (Shodan, Censys, VirusTotal, PassiveDNS) with a search rule and alerts on new findings. Manages a local database of already-known indicators. Useful for tracking malware infrastructure and finding new C2 servers as they appear.' },

  { name:'Kunai', url:'https://github.com/0xrawsec/kunai', icon:'🔪', cat:'network', tags:['linux','monitoring'],
    desc:'Kunai — инструмент мониторинга и threat hunting для Linux. Отслеживает системные вызовы, сетевую активность, создание файлов. Предоставляет события в формате JSON для анализа. Позволяет обнаруживать подозрительную активность на Linux-хостах в реальном времени.', descEn:'Kunai is a Linux threat monitoring tool. Uses eBPF for real-time kernel event monitoring with low performance overhead. Detects: suspicious process spawning, network connections, file access patterns. Generates structured event logs for SIEM ingestion. Useful for endpoint monitoring and threat detection in Linux environments.' },

  { name:'Zeek', url:'https://github.com/zeek/zeek', icon:'🐠', cat:'network', tags:['network','analysis'],
    desc:'Zeek (ранее Bro) — мощная платформа для анализа сетевого трафика. Генерирует структурированные логи из сетевых пакетов: соединения, DNS, HTTP, SSL, файлы. Поддерживает скрипты для кастомного анализа. Используется в SOC для мониторинга трафика и обнаружения аномалий.', descEn:'Zeek (formerly Bro) is a powerful network security monitoring framework. Analyzes network traffic and generates structured logs: DNS, HTTP, SSL, SMTP, SSH, and many more. These logs are perfect for OSINT-style analysis of captured traffic. Zeek scripts can extract IoCs, detect anomalies, and alert on suspicious patterns. Standard in enterprise network monitoring.' },

  { name:'Suricata', url:'https://github.com/OISF/suricata', icon:'🐆', cat:'network', tags:['ids','network'],
    desc:'Suricata — высокопроизводительная IDS/IPS. Анализирует трафик и обнаруживает угрозы по сигнатурам и поведенческим правилам. Поддерживает Lua-скрипты для сложной логики. Может работать в режиме PCAP-анализа для ретроспективного анализа трафика. Стандарт в enterprise-безопасности.', descEn:'Suricata is a high-performance network IDS/IPS and security monitoring engine. Uses rules (compatible with Snort rules) to detect threats. Can run at 10+ Gbps line rate. Generates detailed network logs in EVE JSON format. Supports: protocol detection, file extraction, TLS certificate logging, DNS logging. Standard component in enterprise security monitoring.' },

  { name:'Moloch', url:'https://github.com/arkime/arkime', icon:'👹', cat:'network', tags:['pcap','indexing'],
    desc:'Arkime (ранее Moloch) — система для захвата и индексации сетевого трафика в масштабе. Хранит полные PCAP-файлы и предоставляет веб-интерфейс для поиска и анализа. Поддерживает петабайты данных. Незаменим для долгосрочного хранения трафика и ретроспективных расследований.', descEn:'Moloch (now Arkime) is a large-scale, open-source network traffic capture and analysis system. Captures full network packets at high speeds and stores them for later investigation. Features a web interface for searching and viewing captured sessions. Used by large organizations and ISPs for network forensics and security monitoring.' },

  { name:'Maltrail', url:'https://github.com/stamparm/maltrail', icon:'🚂', cat:'network', tags:['traffic','malicious'],
    desc:'Maltrail — система обнаружения вредоносного трафика. Использует публично доступные "чёрные списки" и статический анализ для обнаружения подозрительных соединений. Имеет веб-интерфейс для просмотра событий. Пассивный мониторинг трафика без активного блокирования.', descEn:'Maltrail is a malicious traffic detection system. Uses static blacklists (malicious IPs, domains, URLs) and dynamic checks to detect suspicious network activity. Sources: VirusTotal, URLhaus, Malware Domain List and others. Generates a web-based security report. Good for network-level threat detection without complex SIEM setup.' },

  { name:'Spamhaus CLI', url:'https://github.com/spamhaus/sbl-api', icon:'📧', cat:'email', tags:['reputation','blacklist'],
    desc:'CLI для проверки IP и доменов в базах Spamhaus — одних из наиболее авторитетных списков спама и вредоносных IP. Проверяет в SBL, XBL, PBL, DBL списках. Полезен для оценки репутации IP-адресов и доменов найденных при разведке инфраструктуры организации.', descEn:'Spamhaus CLI tools query the Spamhaus threat intelligence feeds. Spamhaus maintains lists of spam sources, botnets, and hijacked IPs. Used to check if IPs or domains are on Spamhaus blocklists. Useful for email security investigations and checking reputation of discovered infrastructure. Essential for email security assessments.' },

  { name:'AbuseIPDB CLI', url:'https://github.com/kristuff/abuseipdb-cli', icon:'⚠️', cat:'network', tags:['reputation','abuse'],
    desc:'CLI для AbuseIPDB — базы данных о злоупотреблении IP-адресами. Позволяет проверить репутацию IP — сколько раз он был отмечен как вредоносный, какие категории злоупотреблений. Полезен для быстрой оценки подозрительных IP-адресов при анализе инфраструктуры или расследовании инцидентов.', descEn:'AbuseIPDB CLI is the command-line interface for the AbuseIPDB threat intelligence service. Checks IP reputation — whether an IP has been reported for malicious activity: scanning, brute force, spam. Can submit abuse reports and bulk check IP lists. Free tier available. Useful for quick reputation checks of IPs discovered during OSINT.' },

  { name:'GreyNoise CLI', url:'https://github.com/GreyNoise-Intelligence/pygreynoise', icon:'🌫️', cat:'network', tags:['noise','ip'],
    desc:'GreyNoise различает "интернет-шум" от целенаправленных атак. Классифицирует IP как: benign (известные сканеры, CDN), malicious (известные атакующие), unknown. Python SDK позволяет автоматизировать проверку. Помогает определить сканирует ли IP просто весь интернет или целенаправленно атакует.', descEn:'GreyNoise CLI queries the GreyNoise threat intelligence platform. GreyNoise collects and analyzes internet scan data to identify background noise: IPs constantly scanning the internet. Helps distinguish targeted attacks from opportunistic scanning. Can query by IP to determine if it\'s a known scanner, benign service, or malicious actor.' },

  { name:'VirusTotal CLI', url:'https://github.com/VirusTotal/vt-cli', icon:'🔴', cat:'network', tags:['virustotal','malware'],
    desc:'Официальный CLI для VirusTotal API. Позволяет проверять файлы, URL, IP, домены на 70+ антивирусных движках. Получать исторические данные об объекте. Работать с результатами в скриптах. Незаменим при анализе подозрительных файлов, URL или IP-адресов.', descEn:'VirusTotal CLI is the official command-line interface for VirusTotal. Enables: submitting files, URLs, IPs and domains for analysis, retrieving existing scan results, searching VT database, downloading files. Uses VirusTotal\'s API. Essential in any threat intelligence workflow — VirusTotal aggregates 70+ antivirus engines and threat intelligence feeds.' },

  { name:'Hybrid Analysis', url:'https://github.com/CrowdStrike/falconpy', icon:'🦅', cat:'network', tags:['sandbox','malware'],
    desc:'CrowdStrike Falcon Python SDK для работы с Hybrid Analysis и другими сервисами. Позволяет отправлять файлы в sandbox для динамического анализа, получать отчёты. В OSINT полезен для безопасного анализа подозрительных файлов найденных при разведке.', descEn:'Hybrid Analysis is a free malware analysis service. Submits suspicious files or URLs for dynamic analysis in sandboxed environments. Generates detailed reports: network traffic, process behavior, file system changes, registry modifications, screenshots. Free to use with registration. Useful for analyzing suspicious files encountered during OSINT.' },

  { name:'Joe Sandbox', url:'https://github.com/joesecurity/jbxapi', icon:'🧪', cat:'network', tags:['sandbox','analysis'],
    desc:'API-клиент для Joe Sandbox — продвинутого sandbox для анализа вредоносного ПО. Поддерживает: отправку файлов и URL, получение детальных отчётов, поиск по поведенческим паттернам. Подробные отчёты включают сетевые соединения, изменения реестра, создание файлов.', descEn:'Joe Sandbox is a powerful malware analysis platform. Performs deep dynamic analysis of files and URLs. Generates comprehensive reports including: network indicators (IPs, domains, URLs), dropped files, registry changes, memory artifacts. Has both cloud and on-premise versions. Produces YARA rules from analyzed samples. Premium service with limited free analysis.' },

  { name:'DockerScan', url:'https://github.com/cr0hn/dockerscan', icon:'🐳', cat:'network', tags:['docker','security'],
    desc:'DockerScan — инструмент анализа безопасности Docker-образов. Ищет: чувствительные данные в образах, уязвимые слои, открытые Docker API. Анализирует публичные образы на Docker Hub. Может обнаружить секреты случайно включённые в Docker-образы организации.', descEn:'DockerScan is a tool for analyzing Docker images and containers for security issues. Finds: sensitive information in image layers, exposed ports, high-risk packages, potential backdoors. Reviews Dockerfile best practices. Used in container security audits to assess the security posture of Docker images before deployment.' },

  { name:'Clair', url:'https://github.com/quay/clair', icon:'🔍', cat:'network', tags:['container','cve'],
    desc:'Clair — статический анализатор уязвимостей для контейнеров. Сканирует слои Docker/OCI образов и ищет известные CVE в установленных пакетах. Интегрируется с реестрами контейнеров. Используется организациями для проверки безопасности своих контейнерных образов в CI/CD.', descEn:'Clair is a vulnerability scanner for containers. Analyzes container images layer by layer, checking installed packages against CVE databases. Integrates with container registries: DockerHub, Quay.io. Can be set up as a continuous monitoring service that alerts when new vulnerabilities affect deployed containers. Used in container security pipelines.' },

  { name:'Grype', url:'https://github.com/anchore/grype', icon:'🔒', cat:'network', tags:['container','vulnerability'],
    desc:'Grype — быстрый сканер уязвимостей для контейнеров и файловых систем. Проверяет установленные пакеты в образах Docker на известные CVE. Поддерживает вывод в JSON, table, SARIF. Интегрируется в CI/CD. Альтернатива Trivy с похожим функционалом.', descEn:'Grype is a vulnerability scanner for container images and filesystems. Checks installed packages against multiple vulnerability databases: NVD, GitHub Advisories, Ubuntu, Debian, RHEL. Fast and easy to use. Works with Docker images, OCI artifacts, directories. Good alternative to Clair for simpler setups. Developed by Anchore.' },

  { name:'Syft', url:'https://github.com/anchore/syft', icon:'📋', cat:'network', tags:['sbom','packages'],
    desc:'Syft генерирует SBOM (Software Bill of Materials) для контейнеров и файловых систем. Перечисляет все установленные пакеты с версиями. Результат используется с Grype для проверки уязвимостей. В OSINT полезен для инвентаризации компонентов обнаруженного ПО.', descEn:'Syft generates a Software Bill of Materials (SBOM) for container images and filesystems. Identifies all installed packages and their versions across many ecosystems: OS packages, Python, Ruby, Java, Node.js, Go, Rust. Works with Docker images, OCI artifacts, directories. SBOMs are used as input for vulnerability scanners like Grype.' },

  { name:'Driftwood', url:'https://github.com/trufflesecurity/driftwood', icon:'🪵', cat:'network', tags:['ssh','key'],
    desc:'Driftwood проверяет приватные ключи на предмет использования в различных сервисах. Определяет: использовался ли ключ для подписи коммитов GitHub, зарегистрирован ли как SSH-ключ, использовался ли в SSL-сертификатах. Помогает отследить распространение скомпрометированных ключей.', descEn:'Driftwood is a tool for identifying whether discovered private keys are actively used. Takes a private key file and checks cloud services (GitHub, GitLab, AWS, etc.) to determine if the key grants any active access. Used when private keys are discovered in code repositories or data leaks to assess the actual risk.' },

  { name:'Nomore403', url:'https://github.com/devploit/nomore403', icon:'🚫', cat:'network', tags:['bypass','403'],
    desc:'Nomore403 автоматизирует попытки обхода HTTP 403 (Forbidden). Пробует различные техники: изменение заголовков (X-Forwarded-For, X-Original-URL), добавление символов в URL, изменение метода запроса. Помогает получить доступ к ресурсам которые неправильно защищены на уровне WAF или приложения.', descEn:'nomore403 is a tool for bypassing 403 Forbidden access restrictions. Tries various bypass techniques: path manipulation, HTTP method override, header injection, IP spoofing via headers. Often can access \'forbidden\' pages through one of these techniques. Useful in web application assessments for checking if access controls are properly implemented.' },

  { name:'403-bypasser', url:'https://github.com/sting8k/BurpSuite_403Bypasser', icon:'🔓', cat:'network', tags:['bypass','forbidden'],
    desc:'Burp Suite расширение для автоматизации попыток обхода 403 ошибок. Автоматически применяет различные техники обхода к выбранному запросу. Показывает какие техники сработали. Особенно полезен при тестировании контроля доступа в веб-приложениях.', descEn:'403-bypasser is a tool for testing and bypassing HTTP 403 Forbidden responses. Uses a collection of bypass techniques: URL encoding, path variations, HTTP verbs, headers like X-Forwarded-For, X-Original-URL. Processes lists of 403 URLs and tries to access them via various bypass methods. Common in web application penetration testing.' },

  { name:'Nuclei-templates', url:'https://github.com/projectdiscovery/nuclei-templates', icon:'📄', cat:'network', tags:['nuclei','templates'],
    desc:'Официальный репозиторий шаблонов для Nuclei. Содержит тысячи шаблонов для проверки CVE, неправильных конфигураций, раскрытия информации, устаревшего ПО. Сообщество регулярно добавляет новые шаблоны. Обновляется ежедневно. Необходим для максимально полного сканирования с Nuclei.', descEn:'Nuclei Templates is the community-maintained library of detection templates for Nuclei scanner. Contains thousands of templates for: CVEs, misconfigurations, exposed panels, default credentials, known vulnerabilities. Updated daily. The value of Nuclei comes largely from this template library. Templates can be written for any HTTP-based vulnerability.' },

  { name:'HackerTarget API', url:'https://github.com/msudakov/hackertarget', icon:'🎯', cat:'network', tags:['api','recon'],
    desc:'HackerTarget предоставляет API для нескольких инструментов разведки: Nmap, Traceroute, поиск поддоменов, DNS lookup, WHOIS, обратный IP. Python-клиент позволяет автоматизировать запросы. Бесплатный тариф имеет ограничения но достаточен для базовой разведки.', descEn:'HackerTarget API provides access to various network recon tools via API. Services include: Nmap scan, DNS lookup, reverse DNS, subdomain finder, IP geo, traceroute. Free tier available with limited queries. Useful for quickly running network recon tasks without local tool installation.' },

  { name:'SecurityTrails Python', url:'https://github.com/securitytrails/securitytrails-api-client', icon:'🔍', cat:'network', tags:['dns','history'],
    desc:'Python-клиент для SecurityTrails API. SecurityTrails хранит самую обширную историческую DNS-базу. Позволяет: получать текущие и исторические DNS-записи, искать домены по IP или email, получать список поддоменов. Исторические данные незаменимы для понимания эволюции инфраструктуры.', descEn:'SecurityTrails Python SDK is the official Python library for the SecurityTrails API. SecurityTrails provides: historical DNS records, WHOIS history, subdomain enumeration, associated IPs. Historical DNS data is particularly valuable — reveals real IPs that were exposed before CDN adoption. One of the best passive DNS intelligence sources.' },

  { name:'PDNS', url:'https://github.com/CIRCL/PyPDNS', icon:'📋', cat:'network', tags:['passive-dns','history'],
    desc:'PyPDNS — клиент для Passive DNS баз данных. Пассивный DNS записывает какой IP адрес имел домен в прошлом. Используя PDNS можно: найти реальный IP за CDN (исторические записи до подключения CDN), связать инфраструктуру по общим IP, найти другие домены на том же IP.', descEn:'Passive DNS (pDNS) tools query passive DNS databases that record historical DNS resolution data. Can discover: what IPs a domain pointed to historically, what other domains have pointed to a given IP, DNS changes over time. Crucial for attributing infrastructure and tracking threat actors who change their infrastructure.' },

  { name:'Unfurl', url:'https://github.com/obsidianforensics/unfurl', icon:'🔓', cat:'network', tags:['url','decode'],
    desc:'Unfurl декодирует и анализирует URL, показывая все компоненты в понятном виде. Разбирает: схему, хост, путь, параметры. Декодирует: Base64, URL-encoding, JWT, timestamp. Понимает форматы Google Analytics, Facebook, Twitter. Незаменим при анализе сложных URL из трафика или логов.', descEn:'Unfurl decodes and analyzes URLs and other indicators. Breaks down URLs into components, base64-decodes data, identifies timestamp formats, extracts metadata from various URL structures. Particularly useful for analyzing complex URLs like tracking pixels, CDN URLs, OAuth flows. Visual graph representation of URL structure.' },

  { name:'Ditto', url:'https://github.com/evilsocket/ditto', icon:'🎪', cat:'network', tags:['typosquatting','domain'],
    desc:'Ditto находит потенциальные typosquatting-домены для заданного доменного имени. Генерирует варианты с опечатками, добавлением/удалением символов, заменой похожими символами. Проверяет регистрацию найденных вариантов. Помогает защититься от или обнаружить typosquatting-атаки на организацию.', descEn:'Ditto creates lookalike domains by applying various character substitutions. Generates IDN homograph attacks, typosquatting variations, homoglyphs. Used for: detecting typosquatting against your brand, generating candidates for IDN phishing testing, checking if lookalike domains are registered. Written in Go.' },

  { name:'URLcrazy', url:'https://github.com/urbanadventurer/urlcrazy', icon:'🌀', cat:'network', tags:['typosquatting','dns'],
    desc:'URLCrazy генерирует и проверяет домены-опечатки для заданного домена. Создаёт варианты с: заменой символов, добавлением, пропуском, перестановкой букв, использованием похожих доменных зон. Проверяет DNS-разрешение и HTTP-доступность. Используется для мониторинга брендовых атак.', descEn:'URLcrazy generates and tests typo, lookalike and homoglyph domain names. Tests whether generated domains are registered and what they resolve to. Finds: typosquatting domains, bitsquatting, homoglyphs, technical typos. Useful for brand monitoring and investigating phishing infrastructure.' },

  { name:'Phishing-frenzy', url:'https://github.com/pentestgeek/phishing-frenzy', icon:'🎣', cat:'people', tags:['phishing','framework'],
    desc:'Phishing Frenzy — Ruby on Rails платформа для управления фишинговыми кампаниями. Предназначена для легитимного тестирования осведомлённости сотрудников. Управляет шаблонами, кампаниями, статистикой. Требует явного письменного разрешения от тестируемой организации.', descEn:'Phishing Frenzy is a phishing framework. Provides a web interface for managing phishing campaigns: creating email templates, tracking targets, analyzing results. Can clone websites and capture credentials. Used in authorized social engineering assessments and security awareness training programs.' },

  { name:'King-phisher', url:'https://github.com/rsmusllp/king-phisher', icon:'👑', cat:'people', tags:['phishing','testing'],
    desc:'King Phisher — инструмент для тестирования фишинговых атак. Поддерживает сложные кампании с отслеживанием открытий, переходов, введённых данных. Имеет плагины для расширения функционала. Используется для обучения сотрудников распознаванию фишинга. Требует разрешения организации.', descEn:'King Phisher is a phishing campaign toolkit. Features: template manager, client tracking via pixels and links, credentials capture, geo-tracking of link clicks. Has a server component and desktop client. Used in authorized phishing simulations to test employee awareness. More feature-rich than GoPhish with additional tracking capabilities.' },

  { name:'Beef', url:'https://github.com/beefproject/beef', icon:'🐄', cat:'network', tags:['browser','exploitation'],
    desc:'BeEF (Browser Exploitation Framework) — инструмент для тестирования безопасности браузеров. После выполнения JavaScript в браузере жертвы предоставляет панель управления для демонстрации атак через браузер. Используется в пентестинге с разрешения организации для демонстрации рисков XSS.', descEn:'BeEF (Browser Exploitation Framework) hooks browsers via injected JavaScript. Once a browser is hooked: can run JS in the victim\'s browser, steal cookies, capture keystrokes, redirect pages, perform network scanning via the browser. Used in authorized web application penetration testing to demonstrate browser-based attack impact.' },

  { name:'Caldera', url:'https://github.com/mitre/caldera', icon:'🌋', cat:'network', tags:['adversary','simulation'],
    desc:'CALDERA — фреймворк для автоматизированной симуляции атак от MITRE. Использует базу знаний ATT&CK. Поддерживает агентов на Windows, Linux, macOS. Позволяет автоматизировать red team операции для оценки обнаруживаемости угроз. Используется командами безопасности для тестирования защит.', descEn:'Caldera is MITRE\'s automated adversary emulation platform. Runs automated red team operations based on ATT&CK TTPs. Has agent-based architecture: deploys agents on compromised systems to execute attack chains. Used for: testing defenses, validating detection capabilities, SOC training. Directly maps to ATT&CK framework.' },

  { name:'Atomic Red Team', url:'https://github.com/redcanaryco/atomic-red-team', icon:'⚛️', cat:'network', tags:['red-team','testing'],
    desc:'Atomic Red Team — библиотека тестов безопасности сопоставленных с MITRE ATT&CK. Каждый "atomic test" воспроизводит конкретную технику атаки. Используется для проверки работы систем обнаружения (EDR, SIEM). Помогает командам безопасности убедиться что их средства защиты работают.', descEn:'Atomic Red Team is a library of tests mapped to the MITRE ATT&CK framework. Each atomic test provides a simple, testable unit that simulates a specific adversary technique. Used for: validating security controls, testing SIEM detection rules, red team exercises. Hundreds of tests covering all ATT&CK techniques.' },

  { name:'Invoke-AtomicRedTeam', url:'https://github.com/redcanaryco/invoke-atomicredteam', icon:'🔴', cat:'network', tags:['powershell','testing'],
    desc:'PowerShell-фреймворк для выполнения Atomic Red Team тестов. Автоматизирует установку зависимостей, выполнение тестов, очистку. Поддерживает выбор тестов по технике ATT&CK. Делает проведение тестирования защит быстрым и воспроизводимым процессом.', descEn:'Invoke-AtomicRedTeam is the PowerShell framework for executing Atomic Red Team tests. Enables running specific ATT&CK technique tests on Windows systems. Supports: running individual atomics, running all tests for a technique, getting prerequisites, cleaning up after tests. Simplifies executing Atomic Red Team tests in Windows environments.' },

  { name:'Villain', url:'https://github.com/t3l3machus/Villain', icon:'😈', cat:'network', tags:['c2','post-exploit'],
    desc:'Villain — C2-фреймворк для управления reverse shells. Поддерживает несколько одновременных сессий, общий доступ для команды, различные типы payload. Генерирует обфусцированные payload для обхода антивирусов. Используется с разрешения владельца в авторизованных тестах на проникновение.', descEn:'Villain is a Windows and Linux backdoor generator and multi-session handler. Creates obfuscated reverse shells, manages multiple simultaneous sessions. Supports payload generation for multiple delivery methods. Written in Python. Used in authorized red team operations for establishing and managing reverse shell sessions.' },

  { name:'Sliver', url:'https://github.com/BishopFox/sliver', icon:'🔪', cat:'network', tags:['c2','framework'],
    desc:'Sliver — кроссплатформенный C2-фреймворк. Поддерживает агентов на Windows, macOS, Linux. Использует mTLS, WireGuard, HTTP(S) для коммуникации. Поддерживает BOF (Beacon Object Files). Быстро набирает популярность в red team операциях как альтернатива Cobalt Strike.', descEn:'Sliver is an open-source C2 framework (Command & Control). Supports multiple protocols: HTTPS, DNS, mTLS, WireGuard. Has staged and stageless payloads. Features: in-memory execution, built-in SOCKS proxy, process injection, port forwarding. Gaining popularity as an open-source alternative to Cobalt Strike in red team operations.' },

  { name:'Havoc', url:'https://github.com/HavocFramework/Havoc', icon:'⚡', cat:'network', tags:['c2','advanced'],
    desc:'Havoc — современный C2-фреймворк. Поддерживает Windows Demon агента с продвинутыми техниками обхода защит. Имеет красивый современный интерфейс. Поддерживает расширения на Python и .NET. Используется в авторизованных red team операциях.', descEn:'Havoc is a modern C2 framework. Features: custom agent (Demon), in-memory execution, process injection, BOF (Beacon Object Files) support. Written in C and Qt for high performance. Has a modern dark-themed UI. Becoming a popular Cobalt Strike alternative in the red team community.' },

  { name:'Merlin', url:'https://github.com/Ne0nd0g/merlin', icon:'🧙', cat:'network', tags:['c2','http2'],
    desc:'Merlin — C2-фреймворк использующий HTTP/2 для коммуникации что помогает обходить обнаружение. Поддерживает агентов на Windows, Linux, macOS. Использует шифрование на основе JWT. Лёгкий в развёртывании. Используется в авторизованных тестах на проникновение.', descEn:'Merlin is a cross-platform HTTP/2 C2 server and agent. Communicates over HTTP/2 and can blend in with regular HTTPS traffic. Agents available for Windows, Linux and macOS. Supports job-based task execution. Written in Go. Useful when traditional C2 communication is blocked by security tools monitoring HTTP/1.1.' },

  { name:'Poshc2', url:'https://github.com/nettitude/PoshC2', icon:'💻', cat:'network', tags:['c2','powershell'],
    desc:'PoshC2 — C2-фреймворк ориентированный на PowerShell. Поддерживает агентов на .NET, Python, PowerShell. Включает модули для разведки и пост-эксплуатации. Используется командами red team в авторизованных операциях для тестирования защит Windows-окружений.', descEn:'PoshC2 is a proxy-aware C2 framework written in PowerShell, Python and C#. Supports implants for Windows, Linux and macOS. Features: staged payloads, lateral movement, SOCKS proxy. Designed for implant-based red team operations. PowerShell implant blends with Windows administrative activities.' },

  { name:'Veil', url:'https://github.com/Veil-Framework/Veil', icon:'🎭', cat:'network', tags:['payload','evasion'],
    desc:'Veil — фреймворк для генерации payload с обходом антивирусных решений. Создаёт исполняемые файлы на основе Meterpreter shellcode с применением различных техник обфускации. Используется в авторизованных тестах для оценки эффективности антивирусной защиты.', descEn:'Veil is a tool for generating metasploit payloads that bypass antivirus. Uses various obfuscation and evasion techniques. Supports both Python and PowerShell payload types. Classic AV evasion tool though signatures have caught up significantly. Used as a starting point for AV evasion research and authorized red team payload generation.' },

  { name:'Shellter', url:'https://github.com/ParrotSec/shellter', icon:'🐚', cat:'network', tags:['payload','inject'],
    desc:'Shellter — инструмент для инъекции shellcode в легитимные PE-файлы. Использует динамический анализ для нахождения оптимальных точек инъекции. Поддерживает режим stealth. Используется в авторизованных тестах для оценки эффективности EDR-решений.', descEn:'Shellter is a dynamic PE infection tool. Injects shellcode into legitimate Windows executables. The original program continues to function normally, hiding the malicious code. Used for AV evasion by embedding payloads in trusted binaries. Works with any shellcode from Metasploit or custom payloads. Stealthy approach for authorized red team deployments.' },

  { name:'Empire', url:'https://github.com/BC-SECURITY/Empire', icon:'👑', cat:'network', tags:['post-exploit','powershell'],
    desc:'Empire — post-exploitation фреймворк. Поддерживает агентов на PowerShell (.NET), Python, C. Включает модули для разведки в Active Directory, кражи учётных данных, движения по сети. Используется red team для тестирования возможностей обнаружения post-exploitation активности.', descEn:'Empire is a PowerShell and Python post-exploitation framework. Supports Windows (PowerShell) and Linux/macOS (Python) agents. Features: keystroke logging, screenshot capture, credential harvesting, lateral movement, modular post-exploitation. One of the most feature-complete free C2 frameworks. Classic tool in red team arsenals.' },

  { name:'Covenant', url:'https://github.com/cobbr/Covenant', icon:'⚔️', cat:'network', tags:['c2','dotnet'],
    desc:'Covenant — .NET C2-фреймворк с веб-интерфейсом. Поддерживает совместную работу команды, ролевой доступ, логирование всех действий. Использует Grunt-агентов написанных на C#. Поддерживает процедуры OPSEC. Популярен в корпоративных red team командах.', descEn:'Covenant is a .NET C2 framework with a collaborative web interface. Features: .NET implants (Grunts), compiled payloads, task history, multiple operator support. Uses HTTP/S and SMB listeners. .NET implants can use in-memory execution and living-off-the-land techniques. Good alternative to Empire for Windows-focused red team operations.' },

  { name:'Mettle', url:'https://github.com/rapid7/mettle', icon:'💀', cat:'network', tags:['meterpreter','embedded'],
    desc:'Mettle — компактная реализация Meterpreter для встраиваемых систем и IoT. Поддерживает ARM, MIPS, x86. Маленький размер позволяет запускать на устройствах с ограниченными ресурсами. Используется в авторизованных тестах IoT-устройств.', descEn:'Mettle is Metasploit\'s native agent — a lightweight Meterpreter replacement. Designed for constrained environments and IoT devices. Supports a wide range of platforms including unusual architectures. Has a smaller footprint than traditional Meterpreter. Used in Metasploit for persistent access on embedded systems and non-standard targets.' },

  { name:'Nightmangle', url:'https://github.com/realoriginal/nightmangle', icon:'🌙', cat:'network', tags:['obfuscation','evasion'],
    desc:'Инструмент для обфускации shellcode с целью обхода систем обнаружения. Применяет различные техники: шифрование, кодирование, полиморфизм. Используется в авторизованных тестах для проверки эффективности EDR-решений против продвинутых техник обхода.', descEn:'Nightmangle is a red team tool for evasion and post-exploitation. Focuses on bypassing modern EDR solutions through various in-memory techniques. Used in authorized advanced red team engagements to test next-generation security controls.' },

  { name:'PEzor', url:'https://github.com/phra/PEzor', icon:'📦', cat:'network', tags:['packer','evasion'],
    desc:'PEzor — упаковщик для исполняемых файлов с обходом антивирусов. Поддерживает различные техники упаковки и обфускации. Генерирует shellcode, исполняемые файлы, DLL, PowerShell-скрипты. Используется в авторизованных тестах для оценки антивирусной защиты.', descEn:'PEzor is a PE (Portable Executable) packer/obfuscator. Transforms Windows executables to evade antivirus and EDR detection. Supports: shellcode execution, PE injection, various obfuscation techniques. Used in red team engagements for bypassing endpoint security products. Open-source with active development.' },

  { name:'Mimikatz', url:'https://github.com/gentilkiwi/mimikatz', icon:'🐱', cat:'network', tags:['credentials','windows'],
    desc:'Mimikatz — инструмент для работы с учётными данными Windows. Может извлекать пароли из памяти, хэши NTLM, билеты Kerberos. Стал стандартом при оценке безопасности Windows-сред. Используется в авторизованных тестах для демонстрации рисков компрометации учётных данных.', descEn:'Mimikatz is the most famous Windows credential harvesting tool. Can extract: plaintext passwords, NTLM hashes, Kerberos tickets from Windows memory (lsass). Techniques: sekurlsa::logonpasswords, pass-the-hash, pass-the-ticket, DCSync (replicating AD credentials remotely). Essential in Windows penetration testing. Modern defenses (Credential Guard) limit its effectiveness.' },

  { name:'Rubeus', url:'https://github.com/GhostPack/Rubeus', icon:'🔴', cat:'network', tags:['kerberos','windows'],
    desc:'Rubeus — C# инструмент для атак на Kerberos в Windows Active Directory. Поддерживает: AS-REP Roasting, Kerberoasting, Pass-the-Ticket, Over-Pass-the-Hash. Используется red team для тестирования Kerberos-атак в авторизованных операциях против Windows AD.', descEn:'Rubeus is a C# tool for Kerberos interaction and attack. Enables: Kerberoasting (dumping service ticket hashes), AS-REP Roasting, pass-the-ticket, overpass-the-hash, ticket renewal, s4u delegation. Pure .NET implementation — no Mimikatz required. Essential for Active Directory Kerberos exploitation. Constantly updated with new attack techniques.' },

  { name:'SharpHound', url:'https://github.com/BloodHoundAD/SharpHound', icon:'🐕', cat:'network', tags:['bloodhound','collector'],
    desc:'SharpHound — сборщик данных для BloodHound. Собирает информацию о структуре Active Directory: пользователи, группы, компьютеры, политики, права. Работает незаметно — использует только штатные протоколы AD. Необходим для построения графа атак в BloodHound.', descEn:'SharpHound is the data ingestor for BloodHound. Runs on domain computers to collect: session data, user memberships, ACL permissions, trust relationships, computer objects, GPO links. Outputs JSON files for import into BloodHound. Multiple collection methods: All, DCOnly, ComputerOnly. Stealth options to reduce noise during red team engagements.' },

  { name:'PowerSploit', url:'https://github.com/PowerShellMafia/PowerSploit', icon:'💻', cat:'network', tags:['powershell','post-exploit'],
    desc:'PowerSploit — коллекция PowerShell-модулей для пентестинга. Включает: разведку, повышение привилегий, кражу учётных данных, обход защит, persistence. Исторически важный фреймворк который повлиял на развитие всего PowerShell-пентестинга.', descEn:'PowerSploit is a collection of PowerShell modules for penetration testing. Includes: PowerView (AD recon), PowerUp (privilege escalation), Invoke-Shellcode (shellcode injection), Get-GPPPassword (Group Policy passwords). One of the foundational PowerShell offensive toolkits. Many techniques from PowerSploit have been incorporated into other tools.' },

  { name:'Nishang', url:'https://github.com/samratashok/nishang', icon:'🎋', cat:'network', tags:['powershell','scripts'],
    desc:'Nishang — коллекция PowerShell-скриптов и payload для пентестинга и red team. Включает: reverse shells, keylogger, port scanner, credential stealer. Используется в авторизованных тестах Windows-окружений для оценки эффективности обнаружения.', descEn:'Nishang is a PowerShell framework for penetration testing and red teaming. Contains scripts for: remote shell establishment, privilege escalation, credential dumping, keylogging, network scans via PowerShell. Strong focus on OPSEC and evasion. Many modules use native Windows commands and WMI to avoid detection.' },

  { name:'Seatbelt', url:'https://github.com/GhostPack/Seatbelt', icon:'🔒', cat:'network', tags:['enumeration','windows'],
    desc:'Seatbelt — C# инструмент для разведки безопасности Windows-систем. Собирает: конфигурацию системы, установленное ПО, настройки безопасности, учётные данные в браузерах, WiFi-профили. Используется red team для понимания текущего состояния безопасности системы.', descEn:'Seatbelt is a C# security auditing tool for Windows systems. Collects: system configuration, installed software, security settings, browser credentials, WiFi profiles. Used by red teams for situational awareness of a compromised Windows host. Over 60 checks covering different security-relevant aspects of the system.' },

  { name:'WinPEAS', url:'https://github.com/carlospolop/PEASS-ng', icon:'🦚', cat:'network', tags:['privesc','windows'],
    desc:'WinPEAS (Windows Privilege Escalation Awesome Script) ищет пути для эскалации привилегий на Windows. Проверяет: слабые права файлов и реестра, незащищённые сервисы, устаревшие патчи, сохранённые учётные данные. Часть PEASS-ng — незаменимого набора для пост-эксплуатации.', descEn:'WinPEAS (Windows Privilege Escalation Awesome Script) finds privilege escalation paths on Windows. Checks: weak file and registry permissions, unprotected services, outdated patches, stored credentials. Part of PEASS-ng — an essential post-exploitation toolkit. Color-coded output prioritizes findings by severity.' },

  { name:'LinPEAS', url:'https://github.com/carlospolop/PEASS-ng', icon:'🐧', cat:'network', tags:['privesc','linux'],
    desc:'LinPEAS (Linux Privilege Escalation Awesome Script) ищет пути для эскалации привилегий на Linux/Unix. Проверяет: SUID-файлы, sudo-права, cron-задачи, writeable пути, уязвимое ПО. Цветной вывод с приоритизацией находок. Стандарт при тестировании Linux-систем.', descEn:'LinPEAS (Linux Privilege Escalation Awesome Script) finds privilege escalation paths on Linux/Unix. Checks: SUID files, sudo permissions, cron jobs, writable paths, vulnerable software. Color-coded output with finding prioritization. Standard tool for Linux privilege escalation assessment. Part of the PEASS-ng project.' },

  { name:'Gtfobins', url:'https://github.com/GTFOBins/GTFObins.github.io', icon:'🔒', cat:'network', tags:['privesc','gtfo'],
    desc:'GTFOBins — кураторский список Unix-бинарников которые могут использоваться для обхода ограничений. Каждый бинарник снабжён примерами использования для: shell, sudo, file read/write, SUID и других сценариев. Незаменимый справочник при поиске возможностей эскалации привилегий.', descEn:'GTFOBins is a curated list of Unix binaries that can be used to bypass local security restrictions. For each binary: shell escape, file read/write, SUID exploitation, sudo bypass examples. Indispensable reference when searching for privilege escalation opportunities using legitimate system binaries. Regularly updated by the security community.' },

  { name:'Lolbas', url:'https://github.com/LOLBAS-Project/LOLBAS', icon:'🪟', cat:'network', tags:['windows','living-off-land'],
    desc:'LOLBAS (Living Off The Land Binaries and Scripts) — каталог легитимных Windows-бинарников которые можно использовать в атаках. Позволяет выполнять код, скачивать файлы, обходить AppLocker, использовать подписанные Microsoft утилиты. Атаки через LOLBAS труднее обнаружить.', descEn:'LOLBAS (Living Off The Land Binaries and Scripts) is a catalog of legitimate Windows binaries that can be used in attacks. Enables: code execution, file download, AppLocker bypass using Microsoft-signed utilities. Attacks using LOLBAS are harder to detect because they use trusted, signed binaries already present on the system.' },

  { name:'Impacket-scripts', url:'https://github.com/fortra/impacket', icon:'🐍', cat:'network', tags:['windows','attack'],
    desc:'Impacket включает множество готовых скриптов для атак на Windows: GetUserSPNs (Kerberoasting), secretsdump (дамп хэшей), psexec (удалённое выполнение), ntlmrelayx (NTLM relay). Каждый скрипт решает конкретную задачу при тестировании Windows-инфраструктуры.', descEn:'Impacket includes many ready-made scripts for Windows attacks: GetUserSPNs (Kerberoasting), secretsdump (hash dumping), psexec (remote execution), ntlmrelayx (NTLM relay). Each script addresses a specific task in Windows infrastructure testing. The go-to library for Windows network protocol-based attacks.' },

  { name:'CrackMapExec Modules', url:'https://github.com/byt3bl33d3r/CrackMapExec', icon:'🗺️', cat:'network', tags:['modules','ad'],
    desc:'CrackMapExec поддерживает обширную библиотеку модулей. Модули позволяют: проверять Exchange, запускать BloodHound, перечислять принтеры, проверять подписание SMB, работать с MSSQL. Новые модули регулярно добавляются сообществом. CME стал де-факто стандартом для AD пентестинга.', descEn:'CrackMapExec supports an extensive module library. Modules enable: checking Exchange, running BloodHound, enumerating printers, checking SMB signing, working with MSSQL. New modules are regularly added by the community. CME has become the de facto standard for Active Directory penetration testing.' },
];
